@Composable
fun MainAppEntrance(viewModel: MainViewModel) {
    val isSplashActive by viewModel.isSplashActive.collectAsStateWithLifecycle()
    val isAppLocked by viewModel.isAppLocked.collectAsStateWithLifecycle()

    AnimatedContent(
        targetState = when {
            isSplashActive -> AppState.SPLASH
            isAppLocked -> AppState.LOCKED
            else -> AppState.CONTENT
        },
        transitionSpec = {
            fadeIn(animationSpec = tween(400)) togetherWith fadeOut(animationSpec = tween(400))
        },
        label = "app_state_transition"
    ) { state ->
        when (state) {
            AppState.SPLASH -> SplashScreen()
            AppState.LOCKED -> ApplicationLockerScreen(viewModel)
            AppState.CONTENT -> MainDrawerLayout(viewModel)
        }
    }
}

enum class AppState {
    SPLASH, LOCKED, CONTENT
}

// ==========================================
// 🌌 1. SPLASH SCREEN (ELEGANT INITIALIZATION)
// ==========================================
@Composable
fun SplashScreen() {
    val infiniteTransition = rememberInfiniteTransition(label = "splash")
    val angle by infiniteTransition.animateFloat(
        initialValue = 0f,
        targetValue = 360f,
        animationSpec = infiniteRepeatable(
            animation = tween(2000, easing = LinearEasing),
            repeatMode = RepeatMode.Restart
        ),
        label = "rotation"
    )

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(DarkBackground),
        contentAlignment = Alignment.Center
    ) {
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            Box(contentAlignment = Alignment.Center) {
                // Outer glowing sphere rotation
                Box(
                    modifier = Modifier
                        .size(110.dp)
                        .rotate(angle)
                        .background(
                            Brush.sweepGradient(listOf(CyberCyan, CyberPink, CyberCyan)),
                            shape = CircleShape
                        )
                )
                Box(
                    modifier = Modifier
                        .size(104.dp)
                        .background(DarkBackground, CircleShape)
                )
                // Inner emblem
                Icon(
                    imageVector = Icons.Default.Star,
                    contentDescription = null,
                    tint = CyberCyan,
                    modifier = Modifier.size(54.dp)
                )
            }
            Spacer(modifier = Modifier.height(24.dp))
            Text(
                text = "RABIYA",
                letterSpacing = 6.sp,
                fontSize = 28.sp,
                fontWeight = FontWeight.ExtraBold,
                color = Color.White
            )
            Spacer(modifier = Modifier.height(4.dp))
            Text(
                text = "NEURAL AI COMPANION",
                fontSize = 11.sp,
                fontWeight = FontWeight.Medium,
                letterSpacing = 2.sp,
                color = CyberCyan
            )
            Spacer(modifier = Modifier.height(40.dp))
            CircularProgressIndicator(
                color = CyberPink,
                modifier = Modifier.size(24.dp),
                strokeWidth = 2.5.dp
            )
        }
    }
}

