// 🌌 2. PRIVATE APPS SECURITY KEYS KEYPAD
// ==========================================
@Composable
fun ApplicationLockerScreen(viewModel: MainViewModel) {
    val context = LocalContext.current
    val settings by viewModel.lockSettings.collectAsStateWithLifecycle()
    var pinText by remember { mutableStateOf("") }
    var pinMessage by remember { mutableStateOf("ENTER HIGH-SECURITY ACCESS PIN") }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(DarkBackground),
        contentAlignment = Alignment.Center
    ) {
        Column(
            modifier = Modifier
                .widthIn(max = 400.dp)
                .padding(24.dp),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Icon(
                imageVector = Icons.Default.Lock,
                contentDescription = null,
                tint = CyberPink,
                modifier = Modifier.size(48.dp)
            )
            Spacer(modifier = Modifier.height(16.dp))
            Text(
                text = "SECURE CABINET LOCKED",
                fontWeight = FontWeight.Bold,
                fontSize = 18.sp,
                color = Color.White,
                letterSpacing = 1.sp
            )
            Spacer(modifier = Modifier.height(6.dp))
            Text(
                text = pinMessage,
                fontSize = 12.sp,
                color = TextMuted,
                fontWeight = FontWeight.Bold
            )
            
            // Password indicators
            Spacer(modifier = Modifier.height(24.dp))
            Row(horizontalArrangement = Arrangement.spacedBy(16.dp)) {
                for (i in 1..4) {
                    val isChecked = pinText.length >= i
                    Box(
                        modifier = Modifier
                            .size(16.dp)
                            .background(
                                if (isChecked) CyberCyan else GridSpace,
                                CircleShape
                            )
                            .border(1.2.dp, if (isChecked) CyberCyan else TextMuted.copy(alpha = 0.5f), CircleShape)
                    )
                }
            }

            Spacer(modifier = Modifier.height(40.dp))

            // Grid Keypad 3x4
            Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                val buttonRows = listOf(
                    listOf("1", "2", "3"),
                    listOf("4", "5", "6"),
                    listOf("7", "8", "9"),
                    listOf("C", "0", "🔓")
                )

                for (row in buttonRows) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(16.dp)
                    ) {
                        for (key in row) {
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .aspectRatio(1.5f)
                                    .background(GridSpace, RoundedCornerShape(16.dp))
                                    .clickable {
                                        when (key) {
                                            "C" -> if (pinText.isNotEmpty()) pinText = pinText.dropLast(1)
                                            "🔓" -> {
                                                // Quick bypass for testability
                                                viewModel.bypassUnlockQuickly()
                                                android.widget.Toast
                                                    .makeText(
                                                        context,
                                                        "Access code bypassed successfully!",
                                                        android.widget.Toast.LENGTH_SHORT
                                                    )
                                                    .show()
                                            }
                                            else -> {
                                                if (pinText.length < 4) {
                                                    pinText += key
                                                    if (pinText.length == 4) {
                                                        val isCorrect = viewModel.verifyUnlockPasscode(pinText)
                                                        if (!isCorrect) {
                                                            pinText = ""
                                                            pinMessage = "❌ PIN INCORRECT! TRY AGAIN"
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    },
                                contentAlignment = Alignment.Center
                            ) {
                                Text(
                                    text = key,
                                    fontSize = 18.sp,
                                    fontWeight = FontWeight.Bold,
                                    color = if (key == "C" || key == "🔓") CyberPink else Color.White
                                )
                            }
                        }
                    }
                }

                // Collapsible Shared Rabiya Smart Vocal AI Assistant Panel (Active across all tools!)
                val coroutineScope = rememberCoroutineScope()
                var isAssistantOpen by remember { mutableStateOf(false) }
                var userCommandText by remember { mutableStateOf("") }
                var assistantReplyText by remember { mutableStateOf("") }
                var isProcessingCmd by remember { mutableStateOf(false) }

                Surface(
                    shape = RoundedCornerShape(16.dp),
                    color = Color(0xFF070B18),
                    modifier = Modifier
                        .fillMaxWidth()
                        .animateContentSize()
                        .border(1.dp, CyberCyan.copy(alpha = 0.5f), RoundedCornerShape(16.dp))
                ) {
                    Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clickable { isAssistantOpen = !isAssistantOpen },
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                Text("🎙️", fontSize = 12.sp)
                                Text("RABIYA WORKSPACE VOICE ASSISTANT", fontWeight = FontWeight.Bold, color = CyberCyan, fontSize = 9.sp)
                            }
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                Box(
                                    modifier = Modifier
                                        .size(6.dp)
                                        .background(if (isProcessingCmd) CyberPink else SuccessGreen, CircleShape)
                                )
                                Text(if (isAssistantOpen) "Collapse ▲" else "Expand Companion ▼", color = TextMuted, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        if (isAssistantOpen) {
                            if (assistantReplyText.isNotEmpty()) {
                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .background(Color(0xFF03070E), RoundedCornerShape(8.dp))
                                        .border(0.5.dp, GridSpace, RoundedCornerShape(8.dp))
                                        .padding(8.dp)
                                ) {
                                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                        Text("Rabiya Companion:", color = CyberPink, fontWeight = FontWeight.Bold, fontSize = 9.sp)
                                        Text(assistantReplyText, color = Color.White, fontSize = 10.sp, lineHeight = 14.sp)
                                        
                                        IconButton(
                                            onClick = {
                                                viewModel.generateRealHumanVoiceAndSpeak(assistantReplyText, viewModel.selectedVoiceProfile.value, "Hindi")
                                            },
                                            modifier = Modifier.align(Alignment.End).size(20.dp)
                                        ) {
                                            Icon(Icons.Default.VolumeUp, contentDescription = "Play Reply", tint = CyberCyan, modifier = Modifier.size(12.dp))
                                        }
                                    }
                                }
                            }

                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(6.dp)
                            ) {
                                TextField(
                                    value = userCommandText,
                                    onValueChange = { userCommandText = it },
                                    placeholder = { Text("Command me in Urdu, Hindi, English...", color = Color.Gray, fontSize = 10.sp) },
                                    modifier = Modifier
                                        .weight(1f)
                                        .height(38.dp)
                                        .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(8.dp)),
                                    colors = TextFieldDefaults.colors(
                                        focusedContainerColor = Color(0xFF0C101F),
                                        unfocusedContainerColor = Color(0xFF0C101F),
                                        focusedIndicatorColor = Color.Transparent,
                                        unfocusedIndicatorColor = Color.Transparent,
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White
                                    ),
                                    singleLine = true,
                                    shape = RoundedCornerShape(8.dp)
                                )

                                Box(
                                    modifier = Modifier
                                        .size(38.dp)
                                        .background(CyberCyan, RoundedCornerShape(8.dp))
                                        .clickable {
                                            if (userCommandText.isNotBlank()) {
                                                isProcessingCmd = true
                                                coroutineScope.launch {
                                                    val finalPrompt = "You are Rabiya, a helpful Roman Urdu/Hindi AI voice assistant. The user is currently in the high-security locker screen. User says/demands:\n$userCommandText\n\nProvide an extremely helper answer of maximum 2 short sentences in Roman Urdu/Hindi, then immediately read it aloud."
                                                    val reply = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, finalPrompt)
                                                    assistantReplyText = reply
                                                    viewModel.generateRealHumanVoiceAndSpeak(reply, viewModel.selectedVoiceProfile.value, "Hindi")
                                                    userCommandText = ""
                                                    isProcessingCmd = false
                                                }
                                            }
                                        },
                                    contentAlignment = Alignment.Center
                                ) {
                                    if (isProcessingCmd) {
                                        CircularProgressIndicator(color = Color.Black, modifier = Modifier.size(14.dp), strokeWidth = 1.5.dp)
                                    } else {
                                        Icon(imageVector = Icons.Default.Send, contentDescription = "Send Command", tint = Color.Black, modifier = Modifier.size(14.dp))
                                    }
                                }

                                Box(
                                    modifier = Modifier
                                        .size(38.dp)
                                        .background(CyberPink, RoundedCornerShape(8.dp))
                                        .clickable {
                                            isProcessingCmd = true
                                            coroutineScope.launch {
                                                val autoPrompt = "Explain what actions the active security locker screen satisfies and give 1 pro-tip in sweet Roman Urdu/Hindi about privacy."
                                                val reply = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, autoPrompt)
                                                assistantReplyText = reply
                                                viewModel.generateRealHumanVoiceAndSpeak(reply, viewModel.selectedVoiceProfile.value, "Hindi")
                                                isProcessingCmd = false
                                            }
                                        },
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(imageVector = Icons.Default.Mic, contentDescription = "Voice Tip", tint = Color.Black, modifier = Modifier.size(16.dp))
                                }
                            }
                        }
                    }
                }
            }
            
            Spacer(modifier = Modifier.height(24.dp))
            TextButton(onClick = { viewModel.bypassUnlockQuickly() }) {
                Text("DEVELOPER QUICK ACCESS BYPASS", color = CyberCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
            }
        }
    }
}

// ==========================================
// 🌌 3. CONTAINER LAYOUT AND TOP BAR
// ==========================================
@Composable
fun MainDrawerLayout(viewModel: MainViewModel) {
    val currentTab by viewModel.currentTab.collectAsStateWithLifecycle()

    Scaffold(
        modifier = Modifier
            .fillMaxSize()
            .navigationBarsPadding(),
        topBar = {
            Column {
                if (currentTab != 0 && currentTab != 3) {
                    RabiyaUnifiedTopBar(viewModel)
                    AdMobBanner()
                }
            }
        },
        bottomBar = { RabiyaBottomNavigationBar(viewModel, currentTab) }
    ) { innerPadding ->
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .background(DarkBackground)
        ) {
            // Fluid Adaptive constraints for tablets and large screens
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .widthIn(max = 600.dp)
                    .align(Alignment.Center)
            ) {
                when (currentTab) {
                    0 -> HomeScreen(viewModel)
                    1 -> ChatScreen(viewModel)
                    2 -> {
                        var historySubTab by remember { mutableStateOf(0) } // 0 = Vocalizer, 1 = File Manager
                        Column(modifier = Modifier.fillMaxSize()) {
                            // High-quality segmented tab selector at the top
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(horizontal = 14.dp, vertical = 6.dp)
                                    .background(CardSpace, RoundedCornerShape(12.dp))
                                    .padding(4.dp),
                                horizontalArrangement = Arrangement.spacedBy(6.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .clip(RoundedCornerShape(8.dp))
                                        .background(if (historySubTab == 0) CyberCyan.copy(alpha = 0.15f) else Color.Transparent)
                                        .border(
                                            if (historySubTab == 0) BorderStroke(1.dp, CyberCyan.copy(alpha = 0.6f)) else BorderStroke(0.dp, Color.Transparent),
                                            RoundedCornerShape(8.dp)
                                        )
                                        .clickable { historySubTab = 0 }
                                        .padding(vertical = 8.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text("🎙️ VOCALIZER PRO", color = if (historySubTab == 0) CyberCyan else TextMuted, fontSize = 10.5.sp, fontWeight = FontWeight.Bold)
                                }
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .clip(RoundedCornerShape(8.dp))
                                        .background(if (historySubTab == 1) CyberCyan.copy(alpha = 0.15f) else Color.Transparent)
                                        .border(
                                            if (historySubTab == 1) BorderStroke(1.dp, CyberCyan.copy(alpha = 0.6f)) else BorderStroke(0.dp, Color.Transparent),
                                            RoundedCornerShape(8.dp)
                                        )
                                        .clickable { historySubTab = 1 }
                                        .padding(vertical = 8.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text("📁 FILE MANAGER", color = if (historySubTab == 1) CyberCyan else TextMuted, fontSize = 10.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                            
                            Box(modifier = Modifier.weight(1f)) {
                                if (historySubTab == 0) {
                                    VoiceScreen(viewModel)
                                } else {
                                    FileManagerScreen(viewModel)
                                }
                            }
                        }
                    }
                    3 -> ToolsScreen(viewModel)
                    4 -> ProfileScreen(viewModel)
                }
                SimulatedInterstitialAdOverlay(viewModel)
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun RabiyaUnifiedTopBar(viewModel: MainViewModel) {
    val currentTab by viewModel.currentTab.collectAsStateWithLifecycle()
    val tabNames = listOf("AI Home Desk", "Saheli Chat", "Library & Vocalizer", "Neural Tools", "AI Directory Hub")
    val configuration = androidx.compose.ui.platform.LocalConfiguration.current
    val isWideScreen = configuration.screenWidthDp >= 600

    TopAppBar(
        colors = TopAppBarDefaults.topAppBarColors(
            containerColor = DarkBackground,
            titleContentColor = Color.White
        ),
        navigationIcon = {
            if (currentTab == 1 && !isWideScreen) {
                IconButton(onClick = { viewModel.toggleMobileSidebar() }) {
                    Icon(
                        imageVector = Icons.Default.Menu,
                        contentDescription = "Menu History Sidebar",
                        tint = Color.White,
                        modifier = Modifier.size(22.dp)
                    )
                }
            }
        },
        title = {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Box(
                    modifier = Modifier
                        .size(8.dp)
                        .background(CyberCyan, CircleShape)
                )
                Text(
                    text = tabNames[currentTab].uppercase(),
                    fontSize = 14.sp,
                    fontWeight = FontWeight.ExtraBold,
                    letterSpacing = 1.2.sp,
                    color = Color.White
                )
            }
        },
        actions = {
            if (currentTab == 1) {
                var isTopModelSelectorOpen by remember { mutableStateOf(false) }
                val selectedModel by viewModel.selectedModel.collectAsStateWithLifecycle()

                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp),
                    modifier = Modifier
                        .background(CardSpace, RoundedCornerShape(8.dp))
                        .clickable { isTopModelSelectorOpen = true }
                        .padding(horizontal = 8.dp, vertical = 5.dp)
                ) {
                    Box(modifier = Modifier.size(5.dp).background(SuccessGreen, CircleShape))
                    val shortModelName = when {
                        selectedModel.contains("Gemini 3.5") -> "Gemini 3.5"
                        selectedModel.contains("Gemini 3.1") -> "Gemini 3.1"
                        selectedModel.contains("GPT") -> "GPT-4o"
                        selectedModel.contains("Claude") -> "Claude"
                        selectedModel.contains("DeepSeek") -> "DeepSeek"
                        selectedModel.contains("Llama") -> "Llama"
                        else -> selectedModel.take(8)
                    }
                    Text(
                        text = shortModelName,
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Icon(
                        imageVector = Icons.Default.ArrowDropDown,
                        contentDescription = "Select Model",
                        tint = TextMuted,
                        modifier = Modifier.size(14.dp)
                    )
                }

                Spacer(modifier = Modifier.width(6.dp))

                if (isTopModelSelectorOpen) {
                    androidx.compose.ui.window.Dialog(onDismissRequest = { isTopModelSelectorOpen = false }) {
                        Surface(
                            shape = RoundedCornerShape(20.dp),
                            color = CardSpace,
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(16.dp)
                        ) {
                            Column(modifier = Modifier.padding(16.dp)) {
                                Text("CHOOSE NEURAL ENGINE", fontWeight = FontWeight.ExtraBold, color = Color.White, fontSize = 13.sp)
                                Spacer(modifier = Modifier.height(12.dp))
                                listOf(
                                    "Rabiya Core-v3 (Gemini 3.5 Flash)" to "Official Google AI Studio Endpoint Sweet Companion",
                                    "Rabiya Ultra-Pro-v3 (Gemini 3.1 Pro)" to "Advanced Reasoning & Cognitive Pro Intelligence (Advance Brain)",
                                    "GPT-4o Deep Intelligence" to "Direct OpenAI high-reasoning flow",
                                    "Claude 3.5 Sonnet (Direct Cloud)" to "Directly powered by sk-ant Anthropic Cloud Engine"
                                ).forEach { (name, label) ->
                                    Row(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .clickable {
                                                viewModel.updateSelectedModel(name)
                                                isTopModelSelectorOpen = false
                                            }
                                            .padding(vertical = 12.dp),
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(12.dp)
                                    ) {
                                        Box(
                                            modifier = Modifier
                                                .size(16.dp)
                                                .border(1.2.dp, if (selectedModel == name) CyberCyan else TextMuted, CircleShape)
                                                .padding(3.dp)
                                        ) {
                                            if (selectedModel == name) {
                                                Box(modifier = Modifier.fillMaxSize().background(CyberCyan, CircleShape))
                                            }
                                        }
                                        Column {
                                            Text(name, color = Color.White, fontWeight = FontWeight.Bold, fontSize = 12.sp)
                                            Text(label, color = TextMuted, fontSize = 10.sp)
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            } else {
                IconButton(onClick = { viewModel.setTab(4) }) {
                    Icon(
                        imageVector = Icons.Default.Settings,
                        contentDescription = "Status",
                        tint = CyberCyan,
                        modifier = Modifier.size(20.dp)
                    )
                }
            }
        }
    )
}

@Composable
fun RabiyaBottomNavigationBar(viewModel: MainViewModel, currentTab: Int) {
    Surface(
        color = Color(0xFF070B15),
        tonalElevation = 8.dp,
        modifier = Modifier.fillMaxWidth()
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 4.dp, horizontal = 12.dp)
                .windowInsetsPadding(WindowInsets.navigationBars),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Tab 1: Home
            BottomTabItem(
                icon = Icons.Default.Home,
                label = "Home",
                isSelected = (currentTab == 0),
                onClick = { viewModel.setTab(0) },
                modifier = Modifier.testTag("nav_home_tab")
            )

            // Tab 2: Tools
            BottomTabItem(
                icon = Icons.Default.Apps,
                label = "Tools",
                isSelected = (currentTab == 3),
                onClick = { viewModel.setTab(3) },
                modifier = Modifier.testTag("nav_tools_tab")
            )

            // Center: Glowing Robot Head FAB (goes to active chatbot)
            Box(
                modifier = Modifier
                    .size(54.dp)
                    .background(
                        Brush.radialGradient(
                            colors = listOf(CyberCyan.copy(alpha = 0.35f), Color.Transparent)
                        ),
                        CircleShape
                    )
                    .border(
                        BorderStroke(1.8.dp, Brush.linearGradient(listOf(CyberCyan, CyberPink))),
                        CircleShape
                    )
                    .background(Color(0xFF0F1424), CircleShape)
                    .clickable { viewModel.setTab(1) }
                    .padding(8.dp),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = Icons.Default.Face,
                    contentDescription = "Rabiya Chat Central",
                    tint = CyberCyan,
                    modifier = Modifier.size(26.dp)
                )
            }

            // Tab 3: History
            BottomTabItem(
                icon = Icons.Default.History,
                label = "History",
                isSelected = (currentTab == 2),
                onClick = { viewModel.setTab(2) },
                modifier = Modifier.testTag("nav_voice_tab")
            )

            // Tab 4: AI Directory Hub
            BottomTabItem(
                icon = Icons.Default.Widgets,
                label = "AI Hub",
                isSelected = (currentTab == 4),
                onClick = { viewModel.setTab(4) },
                modifier = Modifier.testTag("nav_profile_tab")
            )
        }
    }
}

@Composable
fun BottomTabItem(
    icon: ImageVector,
    label: String,
    isSelected: Boolean,
    onClick: () -> Unit,
    modifier: Modifier = Modifier
) {
    Column(
        horizontalAlignment = Alignment.CenterHorizontally,
        modifier = modifier
            .clickable(onClick = onClick)
            .padding(vertical = 4.dp, horizontal = 12.dp)
            .minimumInteractiveComponentSize()
    ) {
        Icon(
            imageVector = icon,
            contentDescription = label,
            tint = if (isSelected) CyberCyan else TextMuted,
            modifier = Modifier.size(23.dp)
        )
        Spacer(modifier = Modifier.height(2.dp))
        Text(
            text = label,
            color = if (isSelected) CyberCyan else TextMuted,
            fontSize = 11.sp,
            fontWeight = if (isSelected) FontWeight.ExtraBold else FontWeight.Medium
        )
    }
}

