                                            viewModel.addFileToFileManager(context, validName, "Documents", notepadContent)
                                            android.widget.Toast.makeText(context, "Saved successfully inside FileManager Workspace Documents as $validName!", android.widget.Toast.LENGTH_SHORT).show()
