                        "paint_sketch" -> {
                            val currentStroke = remember { mutableStateListOf<androidx.compose.ui.geometry.Offset>() }
                            val allStrokes = remember { mutableStateListOf<Pair<List<androidx.compose.ui.geometry.Offset>, Color>>() }
                            var activeColor by remember { mutableStateOf(CyberCyan) }
                            var strokeWidth by remember { mutableStateOf(10f) }
                            var isSavingSketch by remember { mutableStateOf(false) }

                            var aiDrawPrompt by remember { mutableStateOf("minimalist star outline") }
                            var isAiDrawing by remember { mutableStateOf(false) }

                            Column(
                                modifier = Modifier.fillMaxSize(),
                                verticalArrangement = Arrangement.spacedBy(10.dp)
                            ) {
                                // AI Designer Generator Suite
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                                ) {
                                    OutlinedTextField(
                                        value = aiDrawPrompt,
                                        onValueChange = { aiDrawPrompt = it },
                                        placeholder = { Text("What AI design to draw on canvas...", color = TextMuted, fontSize = 10.sp) },
                                        modifier = Modifier.weight(1.0f).height(40.dp),
                                        colors = OutlinedTextFieldDefaults.colors(
                                            focusedTextColor = Color.White, 
                                            unfocusedTextColor = Color.White, 
                                            focusedBorderColor = CyberCyan, 
                                            unfocusedBorderColor = GridSpace
                                        ),
                                        singleLine = true,
                                        textStyle = TextStyle(fontSize = 11.sp)
                                    )

                                    Button(
                                        onClick = {
                                            isAiDrawing = true
                                            coroutineScope.launch {
                                                try {
                                                    // Tell dynamic Gemini model to draw custom coordinates list
                                                    val requestPrompt = "You are an AI Sketch Artist that creates outline designs on a 300x300 grid coordinate space. Create an outline coordinate drawing of a '$aiDrawPrompt'. Return ONLY a valid JSON Array of coordinate stroke paths. No conversation, no talk, no other text! Formatting example target:\n[[{\"x\":150,\"y\":50},{\"x\":150,\"y\":250}], [{\"x\":100,\"y\":150},{\"x\":200,\"y\":150}]]"
                                                    val replyRaw = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, requestPrompt).trim()
                                                    
                                                    // strip potential markdown markers
                                                    val sanitizedString = replyRaw.replace("```json", "").replace("```", "").trim()
                                                    
                                                    val strokeArray = org.json.JSONArray(sanitizedString)
                                                    for (i in 0 until strokeArray.length()) {
                                                        val singleStrokeJson = strokeArray.getJSONArray(i)
                                                        val pointsList = mutableListOf<androidx.compose.ui.geometry.Offset>()
                                                        for (j in 0 until singleStrokeJson.length()) {
                                                            val pointObj = singleStrokeJson.getJSONObject(j)
                                                            val px = pointObj.getDouble("x").toFloat()
                                                            val py = pointObj.getDouble("y").toFloat()
                                                            pointsList.add(androidx.compose.ui.geometry.Offset(px, py))
                                                        }
                                                        if (pointsList.isNotEmpty()) {
                                                            allStrokes.add(pointsList to activeColor)
                                                        }
                                                    }
                                                } catch(ex: Exception) {
                                                    // fallback fallback smile outline
                                                    allStrokes.add(listOf(
                                                        androidx.compose.ui.geometry.Offset(102f, 150f),
                                                        androidx.compose.ui.geometry.Offset(150f, 198f),
                                                        androidx.compose.ui.geometry.Offset(198f, 150f)
                                                    ) to activeColor)
                                                } finally {
                                                    isAiDrawing = false
                                                }
                                            }
                                        },
                                        colors = ButtonDefaults.buttonColors(containerColor = CyberPink),
                                        shape = RoundedCornerShape(8.dp),
                                        modifier = Modifier.height(40.dp),
                                        enabled = !isAiDrawing
                                    ) {
                                        if (isAiDrawing) {
                                            CircularProgressIndicator(color = Color.White, modifier = Modifier.size(14.dp), strokeWidth = 2.dp)
                                        } else {
                                            Text("AI DESIGN 🤖", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                }

                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text("Swipe finger to sketch anything manually:", color = TextLight, fontSize = 11.sp)
                                    // Clear Paint board
                                    Text(
                                        "CLEAR BOARD 🔄",
                                        color = CyberPink,
                                        fontWeight = FontWeight.Bold,
                                        fontSize = 10.sp,
                                        modifier = Modifier.clickable {
                                            allStrokes.clear()
                                            currentStroke.clear()
                                        }
                                    )
                                }

                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    listOf(CyberCyan, CyberPink, SuccessGreen, Color.White, Color.Yellow).forEach { col ->
                                        Box(
                                            modifier = Modifier
                                                .size(28.dp)
                                                .background(col, CircleShape)
                                                .border(2.dp, if (activeColor == col) Color.White else Color.Transparent, CircleShape)
                                                .clickable { activeColor = col }
                                        )
                                    }
                                    Spacer(modifier = Modifier.width(10.dp))
                                    Text("Stroke size:", color = TextLight, fontSize = 9.sp)
                                    Slider(
                                        value = strokeWidth,
                                        onValueChange = { strokeWidth = it },
                                        valueRange = 4f..30f,
                                        colors = SliderDefaults.colors(thumbColor = activeColor, activeTrackColor = activeColor),
                                        modifier = Modifier.weight(1f)
                                    )
                                }

                                Canvas(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .weight(1f)
                                        .background(Color(0xFF03070E), RoundedCornerShape(12.dp))
                                        .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(12.dp))
                                        .pointerInput(Unit) {
                                            detectDragGestures(
                                                onDragStart = { offset ->
                                                    currentStroke.add(offset)
                                                },
                                                onDrag = { change, _ ->
                                                    currentStroke.add(change.position)
                                                },
                                                onDragEnd = {
                                                    val points = currentStroke.toList()
                                                    if (points.isNotEmpty()) {
                                                        allStrokes.add(points to activeColor)
                                                    }
                                                    currentStroke.clear()
                                                }
                                            )
                                        }
                                ) {
                                    allStrokes.forEach { (stroke, color) ->
                                        for (i in 0 until stroke.size - 1) {
                                            drawLine(
                                                color = color,
                                                start = stroke[i],
                                                end = stroke[i + 1],
                                                strokeWidth = strokeWidth,
                                                cap = androidx.compose.ui.graphics.StrokeCap.Round
                                            )
                                        }
                                    }
                                    for (i in 0 until currentStroke.size - 1) {
                                        drawLine(
                                            color = activeColor,
                                            start = currentStroke[i],
                                            end = currentStroke[i + 1],
                                            strokeWidth = strokeWidth,
                                            cap = androidx.compose.ui.graphics.StrokeCap.Round
                                        )
                                    }
                                }

                                Button(
                                    onClick = {
                                        isSavingSketch = true
                                        coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                                            try {
                                                val bmp = android.graphics.Bitmap.createBitmap(400, 400, android.graphics.Bitmap.Config.ARGB_8888)
                                                val canvasObj = android.graphics.Canvas(bmp)
                                                canvasObj.drawColor(android.graphics.Color.parseColor("#03070E"))
                                                val paintObj = android.graphics.Paint().apply {
                                                    strokeWidth = 8f
                                                    strokeCap = android.graphics.Paint.Cap.ROUND
                                                    isAntiAlias = true
                                                }
                                                // draw strokes onto Bitmap
                                                allStrokes.forEach { (stroke, color) ->
                                                    paintObj.color = color.toArgb()
                                                    for (i in 0 until stroke.size - 1) {
                                                        canvasObj.drawLine(stroke[i].x, stroke[i].y, stroke[i + 1].x, stroke[i + 1].y, paintObj)
                                                    }
                                                }
                                                val outStream = java.io.ByteArrayOutputStream()
                                                bmp.compress(android.graphics.Bitmap.CompressFormat.PNG, 100, outStream)
                                                val pngBytes = outStream.toByteArray()
                                                
                                                viewModel.addFileToFileManager(context, "Sketch_${System.currentTimeMillis()}.png", "Images", "", pngBytes)
                                                kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                                    android.widget.Toast.makeText(context, "Successfully saved sketch PNG inside File Manager Images!", android.widget.Toast.LENGTH_LONG).show()
                                                }
                                            } catch (e: Exception) {
                                                Log.e("PaintSketch", "Sketch compile error", e)
                                            } finally {
                                                isSavingSketch = false
                                            }
                                        }
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                                    modifier = Modifier.fillMaxWidth(),
                                    shape = RoundedCornerShape(10.dp),
                                    enabled = !isSavingSketch
                                ) {
                                    if (isSavingSketch) {
                                        CircularProgressIndicator(color = Color.Black, modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                                    } else {
                                        Text("COMPILE & SAVE PAINT IMAGE 🎨", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                                    }
                                }
                            }
                        }

