                                        verticalArrangement = Arrangement.spacedBy(8.dp)
                                    ) {
                                        Text("5 Draft Headlines curated:", color = CyberPink, fontWeight = FontWeight.Bold, fontSize = 12.sp)
                                        Text(titleResult, color = Color.White, fontSize = 11.sp, lineHeight = 16.sp)
                                        Text("📁 Drafts saved in local documents under FileManager!", color = SuccessGreen, fontSize = 9.sp, fontWeight = FontWeight.SemiBold)
                                    }
                                }
                            }
                        }

                        "yt_keywords" -> {
                            var ytKeywordsTopic by remember { mutableStateOf("Jetpack Compose layouts") }
                            var generatingKeywords by remember { mutableStateOf(false) }
                            var keywordsResult by remember { mutableStateOf("") }

                            Column(
                                modifier = Modifier.fillMaxSize(),
                                verticalArrangement = Arrangement.spacedBy(12.dp)
                            ) {
                                Text("Video Topic Focus:", color = TextLight, fontSize = 11.sp)
                                OutlinedTextField(
                                    value = ytKeywordsTopic,
                                    onValueChange = { ytKeywordsTopic = it },
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = OutlinedTextFieldDefaults.colors(focusedTextColor = Color.White, unfocusedTextColor = Color.White, focusedBorderColor = CyberCyan, unfocusedBorderColor = GridSpace),
                                    singleLine = true
                                )

                                Button(
                                    onClick = {
                                        generatingKeywords = true
                                        coroutineScope.launch {
                                            val prompt = "Generate 20 viral SEO tags, search keywords, and high indexation tags for a YouTube video about '$ytKeywordsTopic'. Separate the tags clearly with commas so they can be easily copied and pasted into YouTube Studio."
                                            val reply = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, prompt)
                                            keywordsResult = reply
                                            viewModel.addFileToFileManager(context, "YT_SEO_Tags_${System.currentTimeMillis()}.txt", "Documents", "VIDEO TOPIC: $ytKeywordsTopic\n\n$reply")
                                            generatingKeywords = false
                                        }
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                                    modifier = Modifier.fillMaxWidth(),
                                    shape = RoundedCornerShape(10.dp),
                                    enabled = !generatingKeywords
                                ) {
                                    if (generatingKeywords) {
                                        CircularProgressIndicator(color = Color.Black, modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                                    } else {
                                        Text("GENERATE VIRAL TAGS 🏷️", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                                    }
                                }

                                if (keywordsResult.isNotEmpty()) {
                                    Column(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .background(Color(0xFF03070E), RoundedCornerShape(12.dp))
                                            .border(1.dp, GridSpace, RoundedCornerShape(12.dp))
                                            .verticalScroll(rememberScrollState())
                                            .padding(14.dp),
                                        verticalArrangement = Arrangement.spacedBy(8.dp)
                                    ) {
                                        Text("YouTube Keyword Tag Array:", color = CyberCyan, fontWeight = FontWeight.Bold, fontSize = 12.sp)
                                        Text(keywordsResult, color = Color.White, fontSize = 11.sp, lineHeight = 16.sp)
                                        Text("📁 Saved under Files (Documents) for copy-paste!", color = SuccessGreen, fontSize = 9.sp, fontWeight = FontWeight.SemiBold)
                                    }
                                }
                            }
                        }

                        "code_explorer" -> {
                            var promptInput by remember { mutableStateOf("") }
                            var pastedCode by remember { mutableStateOf(
                                "<button style=\"background: linear-gradient(135deg, #6366f1, #ec4899); color: white; padding: 16px 32px; border: none; border-radius: 12px; font-weight: bold; font-family: sans-serif; font-size: 16px; box-shadow: 0 4px 15px rgba(99, 102, 241, 0.4); cursor: pointer; transition: transform 0.2s;\">\n  Explore Quantum UI 🚀\n</button>"
                            ) }
                            var selectedProfile by remember { mutableStateOf("Code Rabbit PR Reviewer") } // Code Rabbit vs Cloud Code vs GPT-4o
                            var activeSubTab by remember { mutableStateOf(0) } // 0: Live HTML View, 1: Code Review & Lint, 2: AI Prompt Generator
                            var linterOutput by remember { mutableStateOf("") }
                            var examiningCode by remember { mutableStateOf(false) }
                            var generatingCode by remember { mutableStateOf(false) }

                            Column(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .verticalScroll(rememberScrollState()),
                                verticalArrangement = Arrangement.spacedBy(12.dp)
                            ) {
                                // Profile Selector Header (Cloud Code vs Code Rabbit)
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .background(GridSpace, RoundedCornerShape(10.dp))
                                        .padding(8.dp),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    Icon(Icons.Default.Code, contentDescription = "Engine", tint = CyberCyan, modifier = Modifier.size(18.dp))
                                    Text("SELECT AI ENGINE CORE:", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    Spacer(modifier = Modifier.weight(1f))
                                    listOf("Code Rabbit", "Cloud Code").forEach { profileName ->
                                        val isSelected = selectedProfile.contains(profileName)
                                        Box(
                                            modifier = Modifier
                                                .background(if (isSelected) CyberCyan else Color.Transparent, RoundedCornerShape(6.dp))
                                                .border(1.dp, if (isSelected) CyberCyan else GridSpace, RoundedCornerShape(6.dp))
                                                .clickable { selectedProfile = if (profileName == "Code Rabbit") "Code Rabbit PR Reviewer" else "Google Cloud Code Companion" }
                                                .padding(horizontal = 8.dp, vertical = 4.dp)
                                        ) {
                                            Text(
                                                text = profileName,
                                                color = if (isSelected) Color.Black else TextMuted,
                                                fontSize = 9.sp,
                                                fontWeight = FontWeight.ExtraBold
                                            )
                                        }
                                    }
                                }

                                // Interactive Generator Box
                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .background(Color(0xFF0F172A), RoundedCornerShape(12.dp))
                                        .border(1.dp, GridSpace, RoundedCornerShape(12.dp))
                                        .padding(12.dp)
                                ) {
                                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                        Text("AI CODE & DOCUMENT GENERATOR 🪄", color = CyberCyan, fontWeight = FontWeight.Bold, fontSize = 10.sp)
                                        Text("Ask AI to generate landing web pages, algorithms, components or structures:", color = TextMuted, fontSize = 9.sp)
                                        
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            OutlinedTextField(
                                                value = promptInput,
                                                onValueChange = { promptInput = it },
                                                modifier = Modifier.weight(1f),
                                                colors = OutlinedTextFieldDefaults.colors(
                                                    focusedTextColor = Color.White,
                                                    unfocusedTextColor = Color.White,
                                                    focusedBorderColor = CyberCyan,
                                                    unfocusedBorderColor = GridSpace
                                                ),
                                                textStyle = TextStyle(fontSize = 11.sp),
                                                placeholder = { Text("e.g. Generate dark cyberpunk calculator html, premium responsive login screen...", color = TextMuted, fontSize = 10.sp) }
                                            )
                                            Button(
                                                onClick = {
                                                    if (promptInput.isNotBlank()) {
                                                        generatingCode = true
                                                        coroutineScope.launch {
                                                            val enginePrompt = when (selectedProfile) {
                                                                "Code Rabbit PR Reviewer" -> 
                                                                    "Act as Code Rabbit Elite AI PR Agent. Write clean, modern, industry-standard production code for: $promptInput. Ensure strict safety, optimization, and zero placeholders. Respond with code only inside standard markdown boundaries without unnecessary chit-chat."
                                                                else -> 
                                                                    "Act as Google Cloud Code Companion. Write lightning-fast, production-grade, cleanly structured snippets for: $promptInput. Return optimal documentation blocks, comments, and the complete source code directly inside markdown blocks without talking."
                                                            }
                                                            val result = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, enginePrompt)
                                                            // Clean markdown symbols to keep pure code where possible
                                                            val cleaned = result.replace(Regex("```[a-zA-Z]*\\n"), "").replace("```", "")
                                                            pastedCode = cleaned
                                                            generatingCode = false
                                                        }
                                                    }
                                                },
                                                colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                                                shape = RoundedCornerShape(8.dp),
                                                enabled = !generatingCode,
                                                modifier = Modifier.height(44.dp)
                                            ) {
                                                if (generatingCode) {
                                                    CircularProgressIndicator(color = Color.Black, modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                                                } else {
                                                    Text("GENERATE", color = Color.Black, fontSize = 10.sp, fontWeight = FontWeight.ExtraBold)
                                                }
                                            }
                                        }
                                    }
                                }

                                // Interactive Preset Buttons
                                Text("POPULAR MASTER templates & Web Pages:", color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                Row(
                                    modifier = Modifier.fillMaxWidth().horizontalScroll(rememberScrollState()),
                                    horizontalArrangement = Arrangement.spacedBy(6.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    listOf(
                                        "Neon Glow Button" to "<button style=\"background: linear-gradient(135deg, #0cebeb, #20e3b2, #29ffc6); color:#000; padding:14px 28px; border:none; border-radius:30px; font-weight:bold; text-transform:uppercase; letter-spacing:1px; cursor:pointer;\">Quantum Neon Link</button>",
                                        "Hologram Profile" to "<div style=\"background:#030712; border: 2px solid #00f2fe; padding:20px; border-radius:15px; font-family:monospace; color:#00f2fe; width:250px; box-shadow:0 0 15px #00f2fe;\">\n  <h3 style=\"margin:0; text-transform:uppercase;\">> SECURE PROFILE</h3>\n  <p style=\"color:#fff; margin:10px 0 0 0;\">ID: KAVYA_AI_V4</p>\n  <p style=\"color:#fff; margin:4px 0 0 0;\">Status: Operational</p>\n</div>",
                                        "Gradient Landing Page" to "<!DOCTYPE html>\n<html>\n<head>\n<style>\nbody { background: radial-gradient(circle, #0f172a 0%, #020617 100%); color:#fff; font-family: sans-serif; display:flex; flex-direction:column; align-items:center; justify-content:center; height:100vh; margin:0; }\nh1 { font-size: 42px; background: linear-gradient(135deg, #38bdf8, #818cf8); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }\np { color:#94a3b8; font-size:18px; }\n</style>\n</head>\n<body>\n<h1>Welcome to Cloud Web SDK</h1>\n<p>Seamless real-time browser code rendered directly is live!</p>\n</body>\n</html>",
                                        "Java Fibonacci" to "public class Fibonacci {\n    public static int compute(int n) {\n        if (n <= 1) return n;\n        return compute(n - 1) + compute(n - 2);\n    }\n}",
                                        "Kotlin Compose Button" to "@Composable\nfun ProfessionalCyberButton(text: String, onClick: () -> Unit) {\n    Button(\n        onClick = onClick,\n        colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),\n        shape = RoundedCornerShape(12.dp)\n    ) {\n        Text(text, color = Color.Black, fontWeight = FontWeight.Bold)\n    }\n}",
                                        "SQL Schema Catalog" to "CREATE TABLE products (\n    product_id INTEGER PRIMARY KEY AUTOINCREMENT,\n    name TEXT NOT NULL,\n    price REAL CHECK(price >= 0.0),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\nCREATE TRIGGER audit_log AFTER INSERT ON products BEGIN\n    INSERT INTO audit (action, item_id) VALUES ('INSERT', new.product_id);\nEND;"
                                    ).forEach { (label, snippet) ->
                                        Box(
                                            modifier = Modifier
                                                .background(GridSpace, RoundedCornerShape(8.dp))
                                                .border(0.5.dp, Color.White.copy(alpha = 0.12f), RoundedCornerShape(8.dp))
                                                .clickable { pastedCode = snippet }
                                                .padding(horizontal = 10.dp, vertical = 6.dp)
                                        ) {
                                            Text(label, color = CyberCyan, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                }

                                // The Code Editor Text Area
                                Text("SOURCE CODE PALETTE (EDITABLE) 📝:", color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                OutlinedTextField(
                                    value = pastedCode,
                                    onValueChange = { pastedCode = it },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(180.dp),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White,
                                        focusedBorderColor = CyberCyan,
                                        unfocusedBorderColor = GridSpace
                                    ),
                                    textStyle = TextStyle(fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace, fontSize = 10.sp),
                                    placeholder = { Text("Paste code snippet here or edit generated output...", color = TextMuted, fontSize = 10.sp) }
                                )

                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    // Save code / Document action
                                    Button(
                                        onClick = {
                                            viewModel.addFileToFileManager(
                                                context,
                                                "Code_Explorer_Output_${System.currentTimeMillis()}.txt",
                                                "Documents",
                                                pastedCode
                                            )
                                            android.widget.Toast.makeText(context, "Code saved under Files (Documents)! 📁", android.widget.Toast.LENGTH_LONG).show()
                                        },
                                        colors = ButtonDefaults.buttonColors(containerColor = SuccessGreen),
                                        shape = RoundedCornerShape(8.dp),
                                        modifier = Modifier.height(32.dp)
                                    ) {
                                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                            Icon(Icons.Default.Download, contentDescription = "Save", tint = Color.Black, modifier = Modifier.size(12.dp))
                                            Text("SAVE AS DOCUMENT 📁", color = Color.Black, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }

                                    // Clipboard Copy helper
                                    Button(
                                        onClick = {
                                            val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                            val clip = android.content.ClipData.newPlainText("Copied Code", pastedCode)
                                            clipboard.setPrimaryClip(clip)
                                            android.widget.Toast.makeText(context, "Copied to clipboard successfully! 📋", android.widget.Toast.LENGTH_SHORT).show()
                                        },
                                        colors = ButtonDefaults.buttonColors(containerColor = GridSpace),
                                        shape = RoundedCornerShape(8.dp),
                                        modifier = Modifier.height(32.dp)
                                    ) {
                                        Text("COPY CODE 📋", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                }

                                // Interactive Tab Selector for Result View
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .background(GridSpace, RoundedCornerShape(8.dp))
                                        .padding(3.dp)
                                ) {
                                    listOf("LIVE HTML BROWSER", "AI PR & CODE REVIEWER").forEachIndexed { index, label ->
                                        Box(
                                            modifier = Modifier
                                                .weight(1f)
                                                .background(if (activeSubTab == index) Color(0xFF0C101F) else Color.Transparent, RoundedCornerShape(6.dp))
                                                .clickable { activeSubTab = index }
                                                .padding(vertical = 8.dp),
                                            contentAlignment = Alignment.Center
                                        ) {
                                            Text(
                                                text = label,
                                                color = if (activeSubTab == index) (if (index == 0) CyberCyan else CyberPink) else Color.White,
                                                fontSize = 10.sp,
                                                fontWeight = FontWeight.Bold
                                            )
                                        }
                                    }
                                }

                                // Output Canvas
                                if (activeSubTab == 0) {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .height(280.dp)
                                            .background(Color.Black, RoundedCornerShape(12.dp))
                                            .border(1.9.dp, GridSpace, RoundedCornerShape(12.dp))
                                            .clip(RoundedCornerShape(12.dp))
                                    ) {
                                        AndroidView(
                                            factory = { ctx ->
                                                android.webkit.WebView(ctx).apply {
                                                    settings.javaScriptEnabled = true
                                                    settings.domStorageEnabled = true
                                                    webChromeClient = android.webkit.WebChromeClient()
                                                    webViewClient = android.webkit.WebViewClient()
                                                    setBackgroundColor(android.graphics.Color.BLACK)
                                                    tag = pastedCode
                                                    val compiledHtml = """
                                                        <!DOCTYPE html>
                                                        <html>
                                                        <head>
                                                        <meta name="viewport" content="width=device-width, initial-scale=1.0">
                                                        <style>
                                                        body { margin: 0; padding: 24px; background-color: #000000; color: #ffffff; display: flex; justify-content: center; align-items: center; min-height: 80vh; overflow: auto; }
                                                        </style>
                                                        </head>
                                                        <body>
                                                        $pastedCode
                                                        </body>
                                                        </html>
                                                    """.trimIndent()
                                                    loadDataWithBaseURL(null, compiledHtml, "text/html", "UTF-8", null)
                                                }
                                            },
                                            update = { webView ->
                                                val currentTag = webView.tag as? String
                                                if (currentTag != pastedCode) {
                                                    webView.tag = pastedCode
                                                    val compiledHtml = """
                                                        <!DOCTYPE html>
                                                        <html>
                                                        <head>
                                                        <meta name="viewport" content="width=device-width, initial-scale=1.0">
                                                        <style>
                                                        body { margin: 0; padding: 24px; background-color: #000000; color: #ffffff; display: flex; justify-content: center; align-items: center; min-height: 80vh; overflow: auto; }
                                                        </style>
                                                        </head>
                                                        <body>
                                                        $pastedCode
                                                        </body>
                                                        </html>
                                                    """.trimIndent()
                                                    webView.loadDataWithBaseURL(null, compiledHtml, "text/html", "UTF-8", null)
                                                }
                                            },
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                } else {
                                    Column(
                                        modifier = Modifier.fillMaxWidth(),
                                        verticalArrangement = Arrangement.spacedBy(8.dp)
                                    ) {
                                        Button(
                                            onClick = {
                                                examiningCode = true
                                                coroutineScope.launch {
                                                    val auditPrompt = "You are an Elite AI Compiler & Linter auditor acting as $selectedProfile. Inspect this code segment for syntactic bugs, memory leakage risks, performance bottlenecks, and recommend optimal modern refactoring patterns:\n\n$pastedCode"
                                                    linterOutput = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, auditPrompt)
                                                    examiningCode = false
                                                }
                                            },
                                            colors = ButtonDefaults.buttonColors(containerColor = CyberPink),
                                            shape = RoundedCornerShape(10.dp),
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .height(42.dp),
                                            enabled = !examiningCode
                                        ) {
                                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                                if (examiningCode) {
                                                    CircularProgressIndicator(color = Color.Black, modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                                                } else {
                                                    Icon(Icons.Default.BugReport, contentDescription = "Lint", tint = Color.Black, modifier = Modifier.size(16.dp))
                                                    Text("ANALYZE WITH AI (${selectedProfile.uppercase()}) 🤖", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 10.sp)
                                                }
                                            }
                                        }

                                        Box(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .height(280.dp)
                                                .background(Color(0xFF03070E), RoundedCornerShape(12.dp))
                                                .border(1.dp, GridSpace, RoundedCornerShape(12.dp))
                                                .padding(12.dp)
                                        ) {
                                            if (linterOutput.isNotEmpty()) {
                                                Column(modifier = Modifier.fillMaxSize().verticalScroll(rememberScrollState())) {
                                                    Text("Deep Audit Report ($selectedProfile):", color = CyberPink, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                                                    Spacer(modifier = Modifier.height(6.dp))
                                                    Text(linterOutput, color = Color.White, fontSize = 10.sp, lineHeight = 15.sp)
                                                }
                                            } else {
                                                Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                                                    Text("Click Analyze to trigger deep Code Rabbit / Cloud Code review", color = TextMuted, fontSize = 10.sp)
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        "google_maps_tool" -> {
                            GoogleMapsToolView(viewModel = viewModel)
                        }

                        "google_tools_hub" -> {
                            GoogleToolsHubView(viewModel = viewModel)
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun HomePillItem(
    icon: ImageVector,
    label: String,
    onClick: () -> Unit
) {
    Row(
        modifier = Modifier
            .background(Color(0xFF0F172A), RoundedCornerShape(20.dp))
            .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(20.dp))
            .clickable(onClick = onClick)
            .padding(horizontal = 14.dp, vertical = 8.dp),
        horizontalArrangement = Arrangement.spacedBy(6.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Icon(
            imageVector = icon,
            contentDescription = label,
            tint = CyberCyan,
