) {
    Box(
        modifier = Modifier
            .width(112.dp)
            .height(102.dp)
            .clip(RoundedCornerShape(12.dp))
            .background(
                Brush.verticalGradient(
                    colors = listOf(Color(0xFF0F172A), Color(0xFF070B16))
                )
