            Box(
                modifier = Modifier
                    .size(26.dp)
                    .background(iconBg.copy(alpha = 0.2f), CircleShape)
                    .border(1.dp, iconBg.copy(alpha = 0.5f), CircleShape),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = icon,
                    contentDescription = null,
