@Composable
fun RecentChatRowItem(
    title: String,
    timeText: String,
    icon: ImageVector,
    iconBg: Color,
    onClick: () -> Unit
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .background(Color(0xFF0A0F1D), RoundedCornerShape(16.dp))
            .border(1.dp, Color(0xFF1E293B).copy(alpha = 0.4f), RoundedCornerShape(16.dp))
            .clickable(onClick = onClick)
            .padding(12.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Box(
            modifier = Modifier
                .size(36.dp)
                .background(iconBg.copy(alpha = 0.2f), CircleShape)
                .border(1.dp, iconBg.copy(alpha = 0.3f), CircleShape),
            contentAlignment = Alignment.Center
        ) {
            Icon(
                imageVector = icon,
                contentDescription = null,
                tint = iconBg,
                modifier = Modifier.size(16.dp)
            )
        }

        Spacer(modifier = Modifier.width(12.dp))

        Column(modifier = Modifier.weight(1f)) {
            Text(
                text = title,
                fontWeight = FontWeight.Bold,
                fontSize = 12.sp,
                color = Color.White,
                maxLines = 1
            )
            Spacer(modifier = Modifier.height(2.dp))
            Text(
                text = timeText,
                fontSize = 10.sp,
                color = TextMuted
            )
        }

        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Icon(
                imageVector = Icons.Default.Star,
                contentDescription = "Favorite",
                tint = TextMuted.copy(alpha = 0.4f),
                modifier = Modifier.size(16.dp)
            )
            Icon(
                imageVector = Icons.Default.MoreHoriz,
                contentDescription = "Actions",
                tint = TextMuted.copy(alpha = 0.6f),
                modifier = Modifier.size(16.dp)
            )
        }
    }
}

sealed class MessageBlock {
    data class TextBlock(val text: String) : MessageBlock()
    data class CodeBlock(val language: String, val code: String) : MessageBlock()
}

fun parseMessageBlocks(text: String): List<MessageBlock> {
    val list = mutableListOf<MessageBlock>()
    val parts = text.split("```")
    for (i in parts.indices) {
        val part = parts[i]
        if (i % 2 == 1) {
            val lines = part.split("\n", limit = 2)
            val language = if (lines.size > 1 && !lines[0].contains(" ") && lines[0].length < 15) {
                lines[0].trim()
            } else {
                ""
            }
            val code = if (language.isNotEmpty() && lines.size > 1) {
                lines[1]
            } else {
                part
            }.trim('\n')
            list.add(MessageBlock.CodeBlock(language, code))
        } else {
            if (part.isNotEmpty()) {
                list.add(MessageBlock.TextBlock(part))
            }
        }
    }
    return list
}

@Composable
fun RenderRichAiMessage(
    text: String,
    onPreviewArtifact: (String, String) -> Unit = { _, _ -> },
    onRunSandbox: ((String, String) -> Unit)? = null
) {
    val context = LocalContext.current
    val blocks = remember(text) { parseMessageBlocks(text) }
    
    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
        blocks.forEach { block ->
            when (block) {
                is MessageBlock.CodeBlock -> {
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 4.dp),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF070A13)),
                        shape = RoundedCornerShape(8.dp),
                        border = BorderStroke(0.5.dp, Color(0xFF1E293B))
                    ) {
                        Column {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(Color(0xFF0F1422))
                                    .padding(horizontal = 12.dp, vertical = 6.dp),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = block.language.uppercase(java.util.Locale.ROOT).ifBlank { "CODE" },
                                    color = CyberCyan,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    letterSpacing = 0.5.sp
                                )
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                                ) {
                                    // PREVIEW INTERACTIVE DESIGN BUTTON
                                    val isPreviewable = remember(block.language, block.code) {
                                        val lang = block.language.lowercase()
                                        lang == "html" || lang == "xml" || lang == "svg" || lang == "kotlin" || lang == "json" || lang == "css" ||
                                        block.code.contains("<html>") || block.code.contains("<svg") || block.code.contains("@Composable")
                                    }
                                    if (isPreviewable) {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(4.dp),
                                            modifier = Modifier.clickable {
                                                onPreviewArtifact(block.code, block.language)
                                            }
                                        ) {
                                            Icon(
                                                imageVector = Icons.Default.PlayArrow,
                                                contentDescription = "Preview Design",
                                                tint = SuccessGreen,
                                                modifier = Modifier.size(13.dp)
                                            )
                                            Text("Preview", color = SuccessGreen, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }

                                    // RUN IN SANDBOX BUTTON
                                    if (onRunSandbox != null) {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(4.dp),
                                            modifier = Modifier.clickable {
                                                onRunSandbox(block.code, block.language)
                                            }
                                        ) {
                                            Icon(
                                                imageVector = Icons.Default.Code,
                                                contentDescription = "Run in Sandbox",
                                                tint = CyberCyan,
                                                modifier = Modifier.size(13.dp)
                                            )
                                            Text("Run Sandbox", color = CyberCyan, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }

                                    // COPY BUTTON
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(4.dp),
                                        modifier = Modifier.clickable {
                                            val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                            clipboard.setPrimaryClip(android.content.ClipData.newPlainText("AI Code", block.code))
                                            android.widget.Toast.makeText(context, "Code copied to clipboard! 📋", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    ) {
                                        Icon(
                                            imageVector = Icons.Default.ContentCopy,
                                            contentDescription = "Copy Code",
                                            tint = TextMuted,
                                            modifier = Modifier.size(11.dp)
                                        )
                                        Text("Copy", color = TextMuted, fontSize = 9.sp, fontWeight = FontWeight.SemiBold)
                                    }
                                }
                            }
                            
                            HorizontalScrollableCodeText(code = block.code)
                        }
                    }
                }
                is MessageBlock.TextBlock -> {
                    RenderParagraphWithFormatting(text = block.text)
                }
            }
        }
    }
}

