    Row(
        modifier = Modifier
            .fillMaxWidth()
            .horizontalScroll(rememberScrollState())
            .padding(12.dp)
    ) {
        Text(
            text = code,
            color = Color(0xFFE2E8F0),
            fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
