@Composable
fun ChatScreen(viewModel: MainViewModel) {
    val context = LocalContext.current
    val messages by viewModel.chatMessages.collectAsStateWithLifecycle()
    val isChatLoading by viewModel.isChatLoading.collectAsStateWithLifecycle()
    val selectedModel by viewModel.selectedModel.collectAsStateWithLifecycle()
    val allSessions by viewModel.allSessions.collectAsStateWithLifecycle()
    val activeSessionId by viewModel.activeSessionId.collectAsStateWithLifecycle()
    val selectedImageBytes by viewModel.selectedImageBytes.collectAsStateWithLifecycle()

    val attachedFileName by viewModel.attachedFileName.collectAsStateWithLifecycle()
    val attachedFileSize by viewModel.attachedFileSize.collectAsStateWithLifecycle()
    val attachedFileType by viewModel.attachedFileType.collectAsStateWithLifecycle()
    val isDeepResearchEnabled by viewModel.isDeepResearchEnabled.collectAsStateWithLifecycle()
    val isWebSearchEnabled by viewModel.isWebSearchEnabled.collectAsStateWithLifecycle()

    var textInput by remember { mutableStateOf("") }
    var isQuickImageCreatorOpen by remember { mutableStateOf(false) }
    var isAiHubConfiguratorOpen by remember { mutableStateOf(false) }
    var zoomImageUrl by remember { mutableStateOf<String?>(null) }

    var activePreviewCode by remember { mutableStateOf<String?>(null) }
    var activePreviewLanguage by remember { mutableStateOf<String?>(null) }

    val allMessages by viewModel.allMessages.collectAsStateWithLifecycle()
    val selectedVoiceProfile by viewModel.selectedVoiceProfile.collectAsStateWithLifecycle()
    val isVoiceListening by viewModel.isVoiceListening.collectAsStateWithLifecycle()
    val isTtsActive by viewModel.isTtsActive.collectAsStateWithLifecycle()
    val speechText by viewModel.speechText.collectAsStateWithLifecycle()

    // Session dating categorizer state maps
    val sessionLatestTimes = remember(allMessages) {
        val map = mutableMapOf<String, Long>()
        allMessages.forEach { msg ->
            if (!map.containsKey(msg.sessionId)) {
                map[msg.sessionId] = msg.timestamp
            }
        }
        map
    }

    val sessionFirstMessages = remember(allMessages) {
        val map = mutableMapOf<String, String>()
        val grouped = allMessages.groupBy { it.sessionId }
        grouped.forEach { (sid, msgs) ->
            val sorted = msgs.sortedBy { it.timestamp }
            val firstUser = sorted.firstOrNull { it.sender == "user" }?.text
            val preview = firstUser ?: sorted.firstOrNull()?.text ?: "Namaste, main Rabiya..."
            map[sid] = preview
        }
        map
    }

    val groupedSessions = remember(allSessions, sessionLatestTimes) {
        val todayList = mutableListOf<String>()
        val yesterdayList = mutableListOf<String>()
        val weekList = mutableListOf<String>()
        val olderList = mutableListOf<String>()
        
        val now = System.currentTimeMillis()
        val oneDayMs = 24 * 60 * 60 * 1000L
        
        allSessions.forEach { sid ->
            val ts = sessionLatestTimes[sid] ?: run {
                val extracted = sid.removePrefix("session_").toLongOrNull()
                extracted ?: now
            }
            val diff = now - ts
            when {
                diff < oneDayMs -> todayList.add(sid)
                diff < 2 * oneDayMs -> yesterdayList.add(sid)
                diff < 7 * oneDayMs -> weekList.add(sid)
                else -> olderList.add(sid)
            }
        }
        listOf(
            "Today" to todayList,
            "Yesterday" to yesterdayList,
            "Previous 7 Days" to weekList,
            "Older" to olderList
        ).filter { it.second.isNotEmpty() }
    }

    val configuration = androidx.compose.ui.platform.LocalConfiguration.current
    val isWideScreen = configuration.screenWidthDp >= 600
    val isMobileSidebarOpen by viewModel.isMobileSidebarOpen.collectAsStateWithLifecycle()

    // Main layout
    Row(modifier = Modifier.fillMaxSize()) {
        // Desktop Sidebar
        if (isWideScreen) {
            SidebarContent(
                modifier = Modifier.width(300.dp),
                activeSessionId = activeSessionId,
                sessionFirstMessages = sessionFirstMessages,
                sessionLatestTimes = sessionLatestTimes,
                groupedSessions = groupedSessions,
                onSessionSelect = { viewModel.selectSession(it) },
                onNewSession = { viewModel.createNewSession() },
                onClearSession = { sid -> viewModel.clearSessionFully(sid) },
                onDeleteSession = { viewModel.deleteSessionFully(it) }
            )
            VerticalDivider(color = Color(0xFF1E293B), modifier = Modifier.width(1.dp).fillMaxHeight())
        }

        // Main Chat Area
        ChatMainContent(
            viewModel = viewModel,
            isWideScreen = isWideScreen,
            textInput = textInput,
            onTextInputChange = { textInput = it },
            onOpenAiHubConfigurator = { isAiHubConfiguratorOpen = true },
            onOpenQuickImageCreator = { isQuickImageCreatorOpen = true },
            onShowZoomImage = { zoomImageUrl = it },
            onShowArtifactPreview = { code, lang ->
                activePreviewCode = code
                activePreviewLanguage = lang
            },
            modifier = Modifier.weight(1f)
        )
    }

    // SLIDING DRAWER HISTORY BAR ON PORTRAIT SCREEN
    if (!isWideScreen && isMobileSidebarOpen) {
        Dialog(
            onDismissRequest = { viewModel.setMobileSidebarOpen(false) },
            properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
        ) {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(Color.Black.copy(alpha = 0.5f))
                    .clickable { viewModel.setMobileSidebarOpen(false) }
            ) {
                SidebarContent(
                    modifier = Modifier
                        .fillMaxHeight()
                        .width(280.dp)
                        .clickable(enabled = false) { }
                        .align(Alignment.CenterStart),
                    activeSessionId = activeSessionId,
                    sessionFirstMessages = sessionFirstMessages,
                    sessionLatestTimes = sessionLatestTimes,
                    groupedSessions = groupedSessions,
                    onSessionSelect = {
                        viewModel.selectSession(it)
                        viewModel.setMobileSidebarOpen(false)
                    },
                    onNewSession = {
                        viewModel.createNewSession()
                        viewModel.setMobileSidebarOpen(false)
                    },
                    onClearSession = { sid -> viewModel.clearSessionFully(sid) },
                    onDeleteSession = { viewModel.deleteSessionFully(it) }
                )
            }
        }
    }

    if (zoomImageUrl != null) {
        Dialog(onDismissRequest = { zoomImageUrl = null }) {
            Surface(
                shape = RoundedCornerShape(24.dp),
                color = DarkBackground,
                modifier = Modifier
                    .fillMaxWidth()
                    .aspectRatio(1f)
                    .padding(8.dp)
            ) {
                Box(modifier = Modifier.fillMaxSize()) {
                    AsyncImage(
                        model = if (zoomImageUrl?.startsWith("http") == true) zoomImageUrl else java.io.File(zoomImageUrl ?: ""),
                        contentDescription = "Zoomed image",
                        modifier = Modifier.fillMaxSize(),
                        contentScale = ContentScale.Fit
                    )
                    IconButton(
                        onClick = { zoomImageUrl = null },
                        modifier = Modifier
                            .align(Alignment.TopEnd)
                            .padding(12.dp)
                            .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                    ) {
                        Icon(Icons.Default.Close, contentDescription = "Close", tint = Color.White)
                    }

                    IconButton(
                        onClick = {
                            zoomImageUrl?.let { url ->
                                viewModel.downloadImageToGallery(context, url)
                            }
                        },
                        modifier = Modifier
                            .align(Alignment.BottomEnd)
                            .padding(12.dp)
                            .background(CyberCyan.copy(alpha = 0.85f), CircleShape)
                    ) {
                        Icon(
                            imageVector = Icons.Default.ArrowDownward,
                            contentDescription = "Download Image",
                            tint = DarkBackground
                        )
                    }
                }
            }
        }
    }

    if (activePreviewCode != null) {
        ArtifactPreviewDialog(
            code = activePreviewCode!!,
            language = activePreviewLanguage ?: "html",
            onDismiss = {
                activePreviewCode = null
                activePreviewLanguage = null
            },
            onSendTweakRequest = { tweakPrompt ->
                val fullRequest = "Aapne jo design banaya hai usme ye change karein:\n$tweakPrompt\n\nReference Design Code:\n```$activePreviewLanguage\n$activePreviewCode\n```"
                viewModel.sendMessage(fullRequest)
            },
            viewModel = viewModel
        )
    }

    if (isQuickImageCreatorOpen) {
        QuickImageGeneratorDialog(viewModel = viewModel, onDismiss = { isQuickImageCreatorOpen = false })
    }

    if (isAiHubConfiguratorOpen) {
        AiHubConfiguratorDialog(
            viewModel = viewModel,
            textInput = textInput,
            onTextInputChange = { textInput = it },
            onDismiss = { isAiHubConfiguratorOpen = false }
        )
    }
}

@Composable
fun ChatMainContent(
    viewModel: MainViewModel,
