    val activeSessionId by viewModel.activeSessionId.collectAsStateWithLifecycle()
    val selectedImageBytes by viewModel.selectedImageBytes.collectAsStateWithLifecycle()

    val attachedFileName by viewModel.attachedFileName.collectAsStateWithLifecycle()
    val attachedFileSize by viewModel.attachedFileSize.collectAsStateWithLifecycle()
    val attachedFileType by viewModel.attachedFileType.collectAsStateWithLifecycle()
    val isDeepResearchEnabled by viewModel.isDeepResearchEnabled.collectAsStateWithLifecycle()
    val isWebSearchEnabled by viewModel.isWebSearchEnabled.collectAsStateWithLifecycle()
    val isVoiceListening by viewModel.isVoiceListening.collectAsStateWithLifecycle()

    val filePickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetContent()
    ) { uri ->
        uri?.let {
            try {
                val contentResolver = context.contentResolver
                val name = getFileNameFromUri(context, it)
                val size = getFileSizeFromUri(context, it)
                val type = contentResolver.getType(it) ?: "application/octet-stream"
                val text = extractFileText(context, it, name, type)
                viewModel.setAttachedFile(context, name, size, type, text)
            } catch (e: Exception) {
                Log.e("ChatScreen", "File resolve failure", e)
            }
        }
    }

    val cameraLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.TakePicturePreview()
