                                            Column {
                                                val tintColor = when (cat) {
                                                    "📝 AI WRITING" -> Color(0xFFFFB300)
                                                    "🎨 AI IMAGE GEN" -> CyberCyan
                                                    "💻 CODE EXPERT" -> SuccessGreen
                                                    else -> CyberPink
                                                }
                                                Text(cat, color = tintColor, fontWeight = FontWeight.Bold, fontSize = 8.sp)
                                                Spacer(modifier = Modifier.height(4.dp))
                                                Text(desc, color = TextLight, fontSize = 10.sp, lineHeight = 13.sp)
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(20.dp))

                        // 🛡️ Sponsored Native Card Ad (Landing Slot)
                        SleekNativeCardAd(viewModel = viewModel, modifier = Modifier.padding(horizontal = 4.dp))

                        Spacer(modifier = Modifier.height(20.dp))
                        
                        Text(
                            text = "RABIYA COLLABORATIVE SUITE CAPABILITIES:",
                            color = CyberCyan,
                            fontWeight = FontWeight.Bold,
                            fontSize = 8.5.sp,
                            letterSpacing = 1.sp,
                            modifier = Modifier.align(Alignment.Start).padding(horizontal = 8.dp)
                        )
                        Spacer(modifier = Modifier.height(8.dp))

                        androidx.compose.material3.Card(
                            colors = androidx.compose.material3.CardDefaults.cardColors(containerColor = Color(0xFF0F172A)),
                            shape = RoundedCornerShape(12.dp),
                            border = BorderStroke(1.dp, Color(0xFF1E293B)),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Column(
                                modifier = Modifier.padding(14.dp),
                                verticalArrangement = Arrangement.spacedBy(12.dp)
                            ) {
                                // HTML/CSS/JS Live Previews
                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                                    verticalAlignment = Alignment.Top
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Code,
                                        contentDescription = null,
                                        tint = CyberCyan,
                                        modifier = Modifier.size(16.dp).padding(top = 2.dp)
                                    )
                                    Column {
                                        Text(
                                            text = "HTML, JS & CSS Live Code (Artifacts)",
                                            color = Color.White,
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                        Text(
                                            text = "Aap mujhse HTML, CSS ya Javascript code likhwayein aur use yahin live preview screen (interactive canvas) par run karke explore karein! (Rabiya Artifacts Tab)",
                                            color = TextMuted,
                                            fontSize = 9.5.sp,
                                            lineHeight = 13.sp
                                        )
                                    }
                                }

                                Divider(color = Color(0xFF1E293B), thickness = 0.5.dp)

                                // Image Generation (JPG/PNG)
                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                                    verticalAlignment = Alignment.Top
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Brush,
                                        contentDescription = null,
                                        tint = CyberPink,
                                        modifier = Modifier.size(16.dp).padding(top = 2.dp)
                                    )
                                    Column {
                                        Text(
                                            text = "JPG & PNG Image Generation",
                                            color = Color.White,
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                        Text(
                                            text = "Koi bhi photo draw ya design karayein! Apne input ke aage 'Banao photo: [prompt]' ya '/image [prompt]' likhein aur use save/download/view karein.",
                                            color = TextMuted,
                                            fontSize = 9.5.sp,
                                            lineHeight = 13.sp
                                        )
                                    }
                                }

                                Divider(color = Color(0xFF1E293B), thickness = 0.5.dp)

                                // PDF, Documents & Spreadsheets scan
                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                                    verticalAlignment = Alignment.Top
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Description,
                                        contentDescription = null,
                                        tint = SuccessGreen,
                                        modifier = Modifier.size(16.dp).padding(top = 2.dp)
                                    )
                                    Column {
                                        Text(
                                            text = "PDF, Spreadsheets & Document Analysis",
                                            color = Color.White,
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                        Text(
                                            text = "Apni resume PDF, Excel spreadsheets ya standard text/code docs ko '+' attachment button se upload karein aur unpar complete analytical work run kijiye.",
                                            color = TextMuted,
                                            fontSize = 9.5.sp,
                                            lineHeight = 13.sp
                                        )
                                    }
                                }

                                Divider(color = Color(0xFF1E293B), thickness = 0.5.dp)

                                // Proactive Suggestions & Opinions
                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                                    verticalAlignment = Alignment.Top
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.AutoAwesome,
                                        contentDescription = null,
                                        tint = Color(0xFFF59E0B),
                                        modifier = Modifier.size(16.dp).padding(top = 2.dp)
                                    )
                                    Column {
                                        Text(
                                            text = "Proactive Brainstorming & Feedback",
                                            color = Color.White,
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                        Text(
                                            text = "Main aapse continuous suggestions, raye, aur opinion lekar aapse collaborate karungi, bilkul ek intelligent teammate ki tarah!",
                                            color = TextMuted,
                                            fontSize = 9.5.sp,
                                            lineHeight = 13.sp
                                        )
                                    }
                                }
                            }
                        }
                    }
                } else {
                    // CHAT MESSAGES STREAMING FEED
                    LazyColumn(
                        modifier = Modifier.fillMaxSize(),
                        contentPadding = PaddingValues(16.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        items(messages, key = { it.id }) { message ->
                            val isUser = message.sender == "user"
                            Column(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalAlignment = if (isUser) Alignment.End else Alignment.Start
                            ) {
                                // Header for assistant
                                if (!isUser) {
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                                        modifier = Modifier.padding(bottom = 6.dp, start = 4.dp)
                                    ) {
                                        Box(
                                            modifier = Modifier
                                                .size(22.dp)
                                                .background(
                                                    brush = Brush.radialGradient(colors = listOf(CyberPink, Color(0xFFC084FC))),
                                                    shape = CircleShape
                                                ),
                                            contentAlignment = Alignment.Center
                                        ) {
                                            Icon(Icons.Default.AutoAwesome, contentDescription = null, tint = Color.White, modifier = Modifier.size(11.dp))
                                        }
                                        Text("Rabiya Saheli", color = CyberPink, fontWeight = FontWeight.Bold, fontSize = 13.5.sp)
                                    }
                                }

                                Box(
                                    modifier = Modifier
                                        .background(
                                            if (isUser) Color(0xFF111A2D) else Color(0xFF1D1C2A),
                                            RoundedCornerShape(
                                                topStart = 16.dp,
                                                topEnd = 16.dp,
                                                bottomStart = if (isUser) 16.dp else 0.dp,
                                                bottomEnd = if (isUser) 0.dp else 16.dp
                                            )
                                        )
                                        .border(
                                            1.dp,
                                            if (isUser) CyberCyan.copy(alpha = 0.25f) else Color(0xFF312E4E),
                                            RoundedCornerShape(
                                                topStart = 16.dp,
                                                topEnd = 16.dp,
                                                bottomStart = if (isUser) 16.dp else 0.dp,
                                                bottomEnd = if (isUser) 0.dp else 16.dp
                                            )
                                        )
                                        .padding(14.dp)
                                        .widthIn(max = if (isWideScreen) 650.dp else 320.dp)
                                ) {
                                    androidx.compose.foundation.text.selection.SelectionContainer {
                                        Column {
                                            val fullText = message.text
                                            val thinkingRegex = Regex("<thinking>([\\s\\S]*?)</thinking>")
                                            val matchResult = thinkingRegex.find(fullText)
                                            val thinkingExcerpt = matchResult?.groups?.get(1)?.value?.trim()
                                            val bodyText = fullText.replace(thinkingRegex, "").trim()

                                            // Thinking disclosure
                                            if (thinkingExcerpt != null && thinkingExcerpt.isNotEmpty()) {
                                                var isExpanded by remember { mutableStateOf(false) }
                                                Box(
                                                    modifier = Modifier
                                                        .fillMaxWidth()
                                                        .padding(vertical = 4.dp)
                                                        .background(GridSpace.copy(alpha = 0.5f), RoundedCornerShape(10.dp))
                                                        .border(0.5.dp, CyberCyan.copy(alpha = 0.4f), RoundedCornerShape(10.dp))
                                                        .clickable { isExpanded = !isExpanded }
                                                        .padding(10.dp)
                                                ) {
                                                    Column {
                                                        Row(
                                                            modifier = Modifier.fillMaxWidth(),
                                                            verticalAlignment = Alignment.CenterVertically,
                                                            horizontalArrangement = Arrangement.SpaceBetween
                                                        ) {
                                                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                                                Text("💭", fontSize = 13.sp)
                                                                Text("Reasoning Trace Active...", fontSize = 10.sp, color = CyberCyan, fontWeight = FontWeight.Bold)
                                                            }
                                                            Icon(
                                                                imageVector = if (isExpanded) Icons.Default.ExpandLess else Icons.Default.ExpandMore,
                                                                contentDescription = null,
                                                                tint = CyberCyan,
                                                                modifier = Modifier.size(14.dp)
                                                            )
                                                        }
                                                        if (isExpanded) {
                                                            Spacer(modifier = Modifier.height(6.dp))
                                                            Text(
                                                                text = thinkingExcerpt,
                                                                color = Color(0xFF94A3B8),
                                                                fontSize = 11.sp,
                                                                lineHeight = 15.sp,
                                                                fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace
                                                            )
                                                        }
                                                    }
                                                }
                                            }

                                            if (bodyText.isNotEmpty()) {
                                                Spacer(modifier = Modifier.height(4.dp))
                                                // Regular message rendering
                                                RenderRichAiMessage(
                                                    text = bodyText,
                                                    onPreviewArtifact = { code, lang -> onShowArtifactPreview(code, lang) },
                                                    onRunSandbox = { code, lang ->
                                                        viewModel.setSandboxPrefilled(code, lang)
                                                        viewModel.triggerToolRedirect("Code Inspector & Sandbox")
                                                    }
                                                )
                                            }

                                            // ADVANCED IN-CHAT INTEGRATED IMAGE VIEWER
                                            if (!message.imageUrl.isNullOrBlank()) {
                                                Spacer(modifier = Modifier.height(10.dp))
                                                val imageModel = remember(message.imageUrl) {
                                                    if (message.imageUrl.startsWith("/")) {
                                                        java.io.File(message.imageUrl)
                                                    } else {
                                                        message.imageUrl
                                                    }
                                                }
                                                Box(
                                                    modifier = Modifier
                                                        .fillMaxWidth()
                                                        .height(180.dp)
                                                        .background(Color(0xFF0F172A), RoundedCornerShape(12.dp))
                                                        .border(1.dp, if (isUser) CyberCyan.copy(alpha = 0.4f) else CyberPink.copy(alpha = 0.4f), RoundedCornerShape(12.dp))
                                                        .clip(RoundedCornerShape(12.dp)),
                                                    contentAlignment = Alignment.Center
                                                ) {
                                                    AsyncImage(
                                                        model = imageModel,
                                                        contentDescription = "Message Attachment",
                                                        modifier = Modifier
                                                            .fillMaxSize()
                                                            .clickable {
                                                                onShowZoomImage(message.imageUrl)
                                                            },
                                                        contentScale = ContentScale.Crop
                                                    )
                                                    
                                                    // Download & Zoom icons overlay for Rabiya's generated images or user zoom
                                                    Box(
                                                        modifier = Modifier
                                                            .align(Alignment.BottomCenter)
                                                            .fillMaxWidth()
                                                            .background(Color.Black.copy(alpha = 0.5f))
                                                            .padding(horizontal = 8.dp, vertical = 4.dp)
                                                    ) {
                                                        Row(
                                                            modifier = Modifier.fillMaxWidth(),
                                                            horizontalArrangement = Arrangement.SpaceBetween,
                                                            verticalAlignment = Alignment.CenterVertically
                                                        ) {
                                                            Text(
                                                                text = if (isUser) "Attached Visual" else "Rabiya Designer AI",
                                                                color = Color.White,
                                                                fontSize = 8.sp,
                                                                fontWeight = FontWeight.Bold
                                                            )
                                                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                                                IconButton(
                                                                    onClick = { onShowZoomImage(message.imageUrl) },
                                                                    modifier = Modifier.size(20.dp)
                                                                ) {
                                                                    Icon(
                                                                        imageVector = Icons.Default.Fullscreen,
                                                                        contentDescription = "Fullscreen",
                                                                        tint = CyberCyan,
                                                                        modifier = Modifier.size(14.dp)
                                                                    )
                                                                }
                                                                if (!isUser) {
                                                                    IconButton(
                                                                        onClick = {
                                                                            viewModel.downloadImageToGallery(context, message.imageUrl)
                                                                        },
                                                                        modifier = Modifier.size(20.dp)
                                                                    ) {
                                                                        Icon(
                                                                            imageVector = Icons.Default.ArrowDownward,
                                                                            contentDescription = "Download Image",
                                                                            tint = SuccessGreen,
                                                                            modifier = Modifier.size(14.dp)
                                                                        )
                                                                    }
                                                                }
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }

                                // Message time & token indicators
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(6.dp),
                                    modifier = Modifier.padding(top = 4.dp, start = 4.dp, end = 4.dp)
                                ) {
                                    val formattedTime = remember(message.timestamp) {
                                        val sdf = java.text.SimpleDateFormat("hh:mm a", java.util.Locale.getDefault())
                                        sdf.format(java.util.Date(message.timestamp))
                                    }
                                    Text(
                                        text = formattedTime,
                                        color = TextMuted,
                                        fontSize = 8.5.sp
                                    )
                                    val tokenCount = message.text.length / 4
                                    if (tokenCount > 0) {
                                        Box(
                                            modifier = Modifier
                                                .background(CardSpace, RoundedCornerShape(4.dp))
                                                .padding(horizontal = 4.dp, vertical = 2.dp)
                                        ) {
                                            Text(
                                                text = "⚡ ${tokenCount}t",
                                                color = CyberCyan,
                                                fontSize = 8.sp,
                                                fontWeight = FontWeight.Bold
                                            )
                                        }
                                    }

                                    // Direct Quick Copy Button
                                    Box(
                                        modifier = Modifier
                                            .background(CardSpace, RoundedCornerShape(8.dp))
                                            .clickable {
                                                val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                                val clip = android.content.ClipData.newPlainText("Rabiya Message", message.text)
                                                clipboard.setPrimaryClip(clip)
                                                android.widget.Toast.makeText(context, "📋 Copied to clipboard!", android.widget.Toast.LENGTH_SHORT).show()
                                            }
                                            .padding(horizontal = 10.dp, vertical = 6.dp)
                                    ) {
                                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                            Icon(Icons.Default.ContentCopy, contentDescription = "Copy message", tint = SuccessGreen, modifier = Modifier.size(11.dp))
                                            Text("Copy Text 📋", color = TextLight, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // Small Loader for streaming responses
                if (isChatLoading) {
                    val infiniteTransition = androidx.compose.animation.core.rememberInfiniteTransition(label = "rabiya_processing")
                    val rotationAngle by infiniteTransition.animateFloat(
                        initialValue = 0f,
                        targetValue = 360f,
                        animationSpec = androidx.compose.animation.core.infiniteRepeatable(
                            animation = androidx.compose.animation.core.tween(1400, easing = androidx.compose.animation.core.LinearEasing),
                            repeatMode = androidx.compose.animation.core.RepeatMode.Restart
                        ),
                        label = "rotation"
                    )
                    val alphaPulse by infiniteTransition.animateFloat(
                        initialValue = 0.4f,
                        targetValue = 1.0f,
                        animationSpec = androidx.compose.animation.core.infiniteRepeatable(
                            animation = androidx.compose.animation.core.tween(1000, easing = androidx.compose.animation.core.FastOutSlowInEasing),
                            repeatMode = androidx.compose.animation.core.RepeatMode.Reverse
                        ),
                        label = "pulse"
                    )

                    Box(
                        modifier = Modifier
                            .align(Alignment.BottomStart)
                            .padding(16.dp)
                            .background(Color(0xFF0F172A), RoundedCornerShape(14.dp))
                            .border(1.5.dp, CyberCyan.copy(alpha = alphaPulse), RoundedCornerShape(14.dp))
                            .padding(horizontal = 14.dp, vertical = 10.dp)
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically, 
                            horizontalArrangement = Arrangement.spacedBy(10.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.AutoAwesome,
                                contentDescription = "Processing",
                                tint = CyberCyan,
                                modifier = Modifier
                                    .size(18.dp)
                                    .graphicsLayer(rotationZ = rotationAngle)
                            )
                            CircularProgressIndicator(
                                color = CyberPink,
                                modifier = Modifier.size(12.dp),
                                strokeWidth = 1.8.dp
                            )
                            Text(
                                text = "Rabiya Saheli is working... ⚡⏳",
                                color = Color.White,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier.graphicsLayer(alpha = alphaPulse)
                            )
                        }
                    }
                }
            }

            // Attached Media Strip
            if (selectedImageBytes != null || attachedFileName != null) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 14.dp, vertical = 6.dp)
                        .background(Color(0xFF0F172A), RoundedCornerShape(10.dp))
                        .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(10.dp))
                        .padding(8.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        if (selectedImageBytes != null) {
                            val bitmap = remember(selectedImageBytes) {
                                android.graphics.BitmapFactory.decodeByteArray(selectedImageBytes, 0, selectedImageBytes!!.size)
                            }
                            if (bitmap != null) {
                                AsyncImage(
                                    model = bitmap,
                                    contentDescription = "Selected photo",
                                    modifier = Modifier
                                        .size(38.dp)
                                        .clip(RoundedCornerShape(6.dp)),
                                    contentScale = ContentScale.Crop
                                )
                            }
                            Column {
                                Text("Attached Image 🖼", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Text("Will be analysed by Multimodal Core", color = TextMuted, fontSize = 9.sp)
                            }
                        } else if (attachedFileName != null) {
                            Box(
                                modifier = Modifier
                                    .size(38.dp)
                                    .background(CyberCyan.copy(alpha = 0.15f), RoundedCornerShape(6.dp)),
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(Icons.Default.FilePresent, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(20.dp))
                            }
                            Column {
                                Text(attachedFileName ?: "Document", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                val sizeText = attachedFileSize ?: "0 Bytes"
                                Text(sizeText, color = TextMuted, fontSize = 9.sp)
                            }
                        }
                    }

                    IconButton(
                        onClick = {
                            viewModel.clearAttachedFile()
                            viewModel.clearSelectedImage()
                        },
                        modifier = Modifier.size(28.dp)
                    ) {
                        Icon(Icons.Default.Close, contentDescription = "Clear file", tint = Color.White, modifier = Modifier.size(16.dp))
                    }
                }
            }

            // CORE INPUT CONTROL DECK CONTAINER
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF090E17))
                    .padding(horizontal = 14.dp, vertical = 8.dp)
            ) {
                Column {
                    // Floating context menus
                    if (isExtendMenuOpen) {
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(bottom = 8.dp),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color(0xFF1E293B))
                                    .clickable {
                                        isExtendMenuOpen = false
                                        cameraLauncher.launch(null)
                                    }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                             ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(Icons.Default.PhotoCamera, contentDescription = "Camera", tint = CyberPink, modifier = Modifier.size(11.dp))
                                    Text("Camera 📷", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color(0xFF1E293B))
                                    .clickable {
                                        isExtendMenuOpen = false
                                        imagePickerLauncher.launch("image/*")
                                    }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(Icons.Default.Photo, contentDescription = "Gallery", tint = CyberCyan, modifier = Modifier.size(11.dp))
                                    Text("Gallery 🖼", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color(0xFF1E293B))
                                    .clickable {
                                        isExtendMenuOpen = false
                                        filePickerLauncher.launch("*/*")
                                    }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(Icons.Default.UploadFile, contentDescription = "File", tint = SuccessGreen, modifier = Modifier.size(11.dp))
                                    Text("File 📄", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color(0xFF1E293B))
                                    .clickable {
                                        isExtendMenuOpen = false
                                        filePickerLauncher.launch("application/pdf")
                                    }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(Icons.Default.Description, contentDescription = "PDF", tint = Color.Red, modifier = Modifier.size(11.dp))
                                    Text("Resume PDF 📑", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color(0xFF1E293B))
                                    .clickable {
                                        viewModel.clearSessionFully(activeSessionId)
                                        android.widget.Toast.makeText(context, "Session Cleared!", android.widget.Toast.LENGTH_SHORT).show()
                                    }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(Icons.Default.Refresh, contentDescription = "Clear", tint = SuccessGreen, modifier = Modifier.size(11.dp))
                                    Text("Reset Chat 🔄", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }

                    // Text Field Box "Ask anything..."
                    OutlinedTextField(
                        value = textInput,
                        onValueChange = { onTextInputChange(it) },
                        placeholder = { Text("Ask anything...", color = Color(0xFF64748B), fontSize = 13.sp) },
                        modifier = Modifier.fillMaxWidth(),
                        shape = RoundedCornerShape(20.dp),
                        maxLines = 4,
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedBorderColor = CyberCyan,
                            unfocusedBorderColor = GridSpace
                        ),
                        trailingIcon = {
                            if (textInput.isNotBlank()) {
                                var isEnhancing by remember { mutableStateOf(false) }
                                IconButton(
                                    onClick = {
                                        isEnhancing = true
                                        viewModel.optimizePrompt(textInput) { enhanced ->
                                            onTextInputChange(enhanced)
                                            isEnhancing = false
                                            android.widget.Toast.makeText(context, "⚡ Prompt Optimized by AI!", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    },
                                    enabled = !isEnhancing
                                ) {
                                    if (isEnhancing) {
                                        CircularProgressIndicator(
                                            color = CyberCyan,
                                            modifier = Modifier.size(16.dp),
                                            strokeWidth = 2.dp
                                        )
                                    } else {
                                        Icon(
                                            imageVector = Icons.Default.AutoAwesome,
                                            contentDescription = "Optimize Prompt",
                                            tint = CyberCyan,
                                            modifier = Modifier.size(18.dp)
                                        )
                                    }
                                }
                            }
                        },
                        keyboardOptions = KeyboardOptions(imeAction = ImeAction.Send),
                        keyboardActions = KeyboardActions(onSend = {
                            if (textInput.isNotBlank() || selectedImageBytes != null) {
                                if (selectedImageBytes != null) {
                                    viewModel.processMultimodalRequest(context, textInput.ifBlank { "Describe this image saheli!" })
                                } else {
                                    viewModel.sendMessage(textInput)
                                }
                                onTextInputChange("")
                                softwareKeyboardController?.hide()
                            }
                        })
                    )

                    Spacer(modifier = Modifier.height(8.dp))

                    // HORIZONTAL ACTIONS AND SHORTCUTS ROW
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        // Left-side utilities row [ + ][ 🌐 Search ][ ✂ Tools ][ 🖼 Image ][ More ∧ ]
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            // [ + ] Upload selector
                            Box(
                                modifier = Modifier
                                    .size(36.dp)
                                    .clip(CircleShape)
                                    .background(if (isExtendMenuOpen) CyberCyan.copy(alpha = 0.2f) else CardSpace)
                                    .clickable { isExtendMenuOpen = !isExtendMenuOpen },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(Icons.Default.Add, contentDescription = "Uploads", tint = if (isExtendMenuOpen) CyberCyan else Color.White, modifier = Modifier.size(16.dp))
                            }

                            // [ 🌐 Search ] Grounding
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(10.dp))
                                    .background(if (isWebSearchEnabled) CyberCyan.copy(alpha = 0.2f) else CardSpace)
                                    .border(1.dp, if (isWebSearchEnabled) CyberCyan else Color.Transparent, RoundedCornerShape(10.dp))
                                    .clickable { viewModel.toggleWebSearch() }
                                    .padding(horizontal = 12.dp, vertical = 7.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(Icons.Default.Language, contentDescription = "Search", tint = if (isWebSearchEnabled) CyberCyan else TextMuted, modifier = Modifier.size(13.dp))
                                    Text("Search", color = if (isWebSearchEnabled) CyberCyan else TextLight, fontSize = 10.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            // [ 📋 Paste ] Clipboard paste action
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(10.dp))
                                    .background(CardSpace)
                                    .clickable {
                                        val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                        val pasteText = clipboard.primaryClip?.getItemAt(0)?.text?.toString() ?: ""
                                        if (pasteText.isNotEmpty()) {
                                            onTextInputChange(textInput + pasteText)
                                            android.widget.Toast.makeText(context, "Pasted from clipboard!", android.widget.Toast.LENGTH_SHORT).show()
                                        } else {
                                            android.widget.Toast.makeText(context, "Clipboard is empty!", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    }
                                    .padding(horizontal = 12.dp, vertical = 7.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(Icons.Default.ContentPaste, contentDescription = "Paste", tint = CyberCyan, modifier = Modifier.size(13.dp))
                                    Text("Paste", color = TextLight, fontSize = 10.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            // [ ✂ Tools ] Shortcut activator
                            Box(
                                modifier = Modifier
                                    .size(36.dp)
                                    .clip(CircleShape)
                                    .background(CardSpace)
                                    .clickable { onOpenAiHubConfigurator() },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(Icons.Default.ContentCut, contentDescription = "Tools", tint = TextLight, modifier = Modifier.size(15.dp))
                            }

                            // [ 🖼 Image ] Palette drawer
                            Box(
                                modifier = Modifier
                                    .size(36.dp)
                                    .clip(CircleShape)
                                    .background(CardSpace)
                                    .clickable { onOpenQuickImageCreator() },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(Icons.Default.Palette, contentDescription = "Design Image", tint = CyberCyan, modifier = Modifier.size(15.dp))
                            }

                            // [ More ∧ ] Templates menu dropdown helper
                            Box {
                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(10.dp))
                                        .background(CardSpace)
                                        .clickable { isMoreTemplatesOpen = true }
                                        .padding(horizontal = 12.dp, vertical = 7.dp)
                                ) {
                                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(3.dp)) {
                                        Text("More", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        Icon(Icons.Default.KeyboardArrowUp, contentDescription = null, tint = TextMuted, modifier = Modifier.size(13.dp))
                                    }
                                }

                                DropdownMenu(
                                    expanded = isMoreTemplatesOpen,
                                    onDismissRequest = { isMoreTemplatesOpen = false },
                                    modifier = Modifier.background(Color(0xFF0F172A))
                                ) {
                                    templates.forEach { (title, fullPrompt, icon) ->
                                        DropdownMenuItem(
                                            text = {
                                                Row(horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
                                                    Icon(icon, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(14.dp))
                                                    Text(title, color = Color.White, fontSize = 11.5.sp)
                                                }
                                            },
                                            onClick = {
                                                viewModel.triggerToolRedirect(title)
                                                isMoreTemplatesOpen = false
                                            }
                                        )
                                    }
                                }
                            }
                        }

                        // Right-side voice input mic and send action buttons
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            // Microphone speak recorder
                            Box(
                                modifier = Modifier
                                    .size(36.dp)
                                    .clip(CircleShape)
                                    .background(if (isVoiceListening) CyberPink.copy(alpha = 0.2f) else CardSpace)
                                    .border(1.dp, if (isVoiceListening) CyberPink else Color.Transparent, CircleShape)
                                    .clickable {
                                        (context as? MainActivity)?.safeToggleVoice(context) {
                                            viewModel.toggleVoiceListening(context)
                                        }
                                    },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = if (isVoiceListening) Icons.Default.MicNone else Icons.Default.Mic,
                                    contentDescription = "Voice dictation",
                                    tint = if (isVoiceListening) CyberPink else Color.White,
                                    modifier = Modifier.size(15.dp)
                                )
                            }

                            // Send icon action
                            Box(
                                modifier = Modifier
                                    .size(36.dp)
                                    .clip(CircleShape)
                                    .background(if (textInput.isNotBlank() || selectedImageBytes != null) CyberCyan else Color(0xFF1E293B))
                                    .clickable {
                                        if (textInput.isNotBlank() || selectedImageBytes != null) {
                                            if (selectedImageBytes != null) {
                                                viewModel.processMultimodalRequest(context, textInput.ifBlank { "Describe this image saheli!" })
                                            } else {
                                                viewModel.sendMessage(textInput)
                                            }
                                            onTextInputChange("")
                                            softwareKeyboardController?.hide()
                                        }
                                    },
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(Icons.Default.Send, contentDescription = "Send", tint = if (textInput.isNotBlank() || selectedImageBytes != null) Color.Black else Color.White, modifier = Modifier.size(15.dp))
                                }
                            }
                        }
                    }
                }
            }
        }

    // Choose model dialog
    if (isModelSelectorOpen) {
        Dialog(onDismissRequest = { isModelSelectorOpen = false }) {
            Surface(
                shape = RoundedCornerShape(20.dp),
                color = CardSpace,
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp)
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text("CHOOSE NEURAL ENGINE MODULE", fontWeight = FontWeight.ExtraBold, color = Color.White, fontSize = 13.sp)
                    Spacer(modifier = Modifier.height(12.dp))
                    listOf(
                        "Rabiya Core-v3 (Gemini 3.5 Flash)" to "Official Google AI Studio Endpoint Sweet Companion",
                        "Rabiya Ultra-Pro-v3 (Gemini 3.1 Pro)" to "Advanced Reasoning & Cognitive Pro Intelligence (Advance Brain)",
                        "GPT-4o Deep Intelligence" to "Direct OpenAI high-reasoning flow",
                        "Claude 3.5 Sonnet (Direct Cloud)" to "Directly powered by sk-ant Anthropic Cloud Engine"
                    ).forEach { (name, label) ->
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clickable {
                                    viewModel.updateSelectedModel(name)
                                    isModelSelectorOpen = false
                                }
                                .padding(vertical = 12.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(16.dp)
                                    .border(1.2.dp, if (selectedModel == name) CyberCyan else TextMuted, CircleShape)
                                    .padding(3.dp)
                            ) {
                                if (selectedModel == name) {
                                    Box(modifier = Modifier.fillMaxSize().background(CyberCyan, CircleShape))
                                }
                            }
                            Column {
                                Text(name, color = Color.White, fontWeight = FontWeight.Bold, fontSize = 13.sp)
                                Text(label, color = TextMuted, fontSize = 11.sp)
                            }
                        }
                    }
                }
            }
        }
    }
}


// ==========================================
// 🎨 SIDEBAR HELPER COMPOSABLE - SAHELI CHAT SIDEBAR REDESIGN
// ==========================================
@Composable
fun SidebarContent(
    modifier: Modifier = Modifier,
    activeSessionId: String,
    sessionFirstMessages: Map<String, String>,
    sessionLatestTimes: Map<String, Long>,
    groupedSessions: List<Pair<String, List<String>>>,
    onSessionSelect: (String) -> Unit,
    onNewSession: () -> Unit,
    onClearSession: (String) -> Unit,
    onDeleteSession: (String) -> Unit
) {
    Column(
        modifier = modifier
            .fillMaxHeight()
            .background(Color(0xFF0B0E14))
            .padding(14.dp)
    ) {
        // Logo & Title
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 12.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Box(
                modifier = Modifier
                    .size(28.dp)
                    .background(
                        brush = Brush.radialGradient(colors = listOf(CyberCyan, CyberPink)),
                        shape = RoundedCornerShape(8.dp)
                    ),
                contentAlignment = Alignment.Center
            ) {
                Icon(Icons.Default.AutoAwesome, contentDescription = null, tint = Color.White, modifier = Modifier.size(16.dp))
            }
            Text(
                text = "SAHELI CHAT",
                color = Color.White,
                fontSize = 15.sp,
                fontWeight = FontWeight.Black,
                letterSpacing = 1.5.sp
            )
        }

        Spacer(modifier = Modifier.height(8.dp))

        // + New Chat button with ⌘ K shortcut display
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .clip(RoundedCornerShape(12.dp))
                .background(Color(0xFF0F172A))
                .border(1.dp, Color(0xFF334155), RoundedCornerShape(12.dp))
                .clickable { onNewSession() }
                .padding(horizontal = 14.dp, vertical = 11.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(Icons.Default.Add, contentDescription = "New Chat", tint = CyberCyan, modifier = Modifier.size(16.dp))
                    Text("New Chat", color = Color.White, fontSize = 12.5.sp, fontWeight = FontWeight.Bold)
                }
                Text(
                    text = "⌘ K",
                    color = Color(0xFF64748B),
                    fontSize = 11.sp,
                    fontWeight = FontWeight.SemiBold
                )
            }
        }

        Spacer(modifier = Modifier.height(20.dp))

        // Scrollable timeline section
        Column(
            modifier = Modifier
                .weight(1f)
                .verticalScroll(rememberScrollState()),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            groupedSessions.forEach { (heading, list) ->
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    Text(
                        text = heading.uppercase(),
                        color = Color(0xFF64748B),
                        fontSize = 9.sp,
                        fontWeight = FontWeight.Black,
                        letterSpacing = 1.sp,
                        modifier = Modifier.padding(start = 6.dp, bottom = 4.dp)
                    )
                    list.forEach { sid ->
                        val isSelected = sid == activeSessionId
                        val previewText = sessionFirstMessages[sid] ?: "Namaste, main Rabiya hoon..."
                        val ts = sessionLatestTimes[sid]
                        val timeStr = remember(ts) {
                            if (ts != null) {
                                val sdf = java.text.SimpleDateFormat("h:mm a", java.util.Locale.getDefault())
                                sdf.format(java.util.Date(ts))
                            } else {
                                "8:18 PM"
                            }
                        }

                        var isMenuExpanded by remember { mutableStateOf(false) }

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(10.dp))
                                .background(if (isSelected) Color(0xFF1E293B).copy(alpha = 0.5f) else Color.Transparent)
                                .border(
                                    1.dp,
                                    if (isSelected) Color(0xFF38BDF8).copy(alpha = 0.4f) else Color.Transparent,
                                    RoundedCornerShape(10.dp)
                                )
                                .clickable { onSessionSelect(sid) }
                                .padding(horizontal = 10.dp, vertical = 10.dp)
                        ) {
                            Column(modifier = Modifier.fillMaxWidth()) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Text(
                                        text = previewText,
                                        color = if (isSelected) Color.White else Color(0xFF94A3B8),
                                        fontSize = 12.sp,
                                        fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Medium,
                                        maxLines = 1,
                                        overflow = TextOverflow.Ellipsis,
                                        modifier = Modifier.weight(1f)
                                    )
                                    Box {
                                        Icon(
                                            imageVector = Icons.Default.MoreVert,
                                            contentDescription = "Session Actions",
                                            tint = if (isSelected) Color.White else Color(0xFF475569),
                                            modifier = Modifier
                                                .size(16.dp)
                                                .clickable { isMenuExpanded = true }
                                        )
                                        DropdownMenu(
                                            expanded = isMenuExpanded,
                                            onDismissRequest = { isMenuExpanded = false },
                                            modifier = Modifier.background(Color(0xFF1F2937))
                                        ) {
                                            DropdownMenuItem(
                                                text = { Text("Clear Msg History", color = Color.White, fontSize = 12.sp) },
                                                onClick = {
                                                    onClearSession(sid)
                                                    isMenuExpanded = false
                                                }
                                            )
                                            DropdownMenuItem(
                                                text = { Text("Delete This Chat", color = CyberPink, fontSize = 12.sp) },
                                                onClick = {
                                                    onDeleteSession(sid)
                                                    isMenuExpanded = false
                                                }
                                            )
                                        }
                                    }
                                }
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = timeStr,
                                    color = Color(0xFF475569),
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Medium
                                )
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(14.dp))

        // Profile block at bottom of custom sidebar
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .clip(RoundedCornerShape(14.dp))
                .background(Color(0xFF0F172A))
                .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(14.dp))
                .padding(10.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .size(32.dp)
                            .background(CyberPink.copy(alpha = 0.2f), CircleShape)
                            .border(1.dp, CyberPink.copy(alpha = 0.5f), CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Text("👩", fontSize = 16.sp)
                    }
                    Column {
                        Text(
                            text = "Rabiya Saheli",
                            color = Color.White,
                            fontSize = 11.5.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            text = "Free Plan",
                            color = CyberPink,
                            fontSize = 9.5.sp,
                            fontWeight = FontWeight.Black
                        )
                    }
                }
                Icon(
                    imageVector = Icons.Default.KeyboardArrowDown,
                    contentDescription = null,
                    tint = Color(0xFF475569),
                    modifier = Modifier.size(16.dp)
                )
            }
        }
    }
}

// ==========================================
// 🧠 5AA. ADAPTIVE AI HUB DIRECTORY (20 CORE FEATURES)
// ==========================================
@Composable
fun AiHubConfiguratorDialog(
    viewModel: MainViewModel,
    textInput: String,
    onTextInputChange: (String) -> Unit,
    onDismiss: () -> Unit
) {
    val context = LocalContext.current
    val isDeepResearchEnabled by viewModel.isDeepResearchEnabled.collectAsStateWithLifecycle()
    val isWebSearchEnabled by viewModel.isWebSearchEnabled.collectAsStateWithLifecycle()
    val isAgentModeActive by viewModel.isAgentModeActive.collectAsStateWithLifecycle()
    val selectedPersona by viewModel.selectedPersona.collectAsStateWithLifecycle()
    val customGptPrompt by viewModel.customGptPrompt.collectAsStateWithLifecycle()
    val memoryItems by viewModel.allMemoryItems.collectAsStateWithLifecycle()
    val selectedModel by viewModel.selectedModel.collectAsStateWithLifecycle()

    var customKbText by remember { mutableStateOf(customGptPrompt) }
    var activeSubTab by remember { mutableStateOf("Core") } // Core, Prompt, Personas
    var isFullScreen by remember { mutableStateOf(true) }

    androidx.compose.ui.window.Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Surface(
            modifier = if (isFullScreen) {
                Modifier.fillMaxSize()
            } else {
                Modifier
                    .fillMaxWidth(0.95f)
                    .fillMaxHeight(0.9f)
                    .testTag("ai_hub_dialog")
            },
            shape = if (isFullScreen) RoundedCornerShape(0.dp) else RoundedCornerShape(20.dp),
            color = Color(0xFF090D1A),
            border = if (isFullScreen) null else BorderStroke(1.5.dp, Brush.linearGradient(listOf(CyberCyan, CyberPink)))
        ) {
            Column(modifier = Modifier.fillMaxSize()) {
                // Header Panel
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF0C1226))
                        .padding(16.dp)
                ) {
                    Column {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text(
                                "AI INTEGRATION CONTROL NODE",
                                color = Color.White,
                                fontWeight = FontWeight.Bold,
                                fontSize = 14.sp
                            )
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                IconButton(onClick = { isFullScreen = !isFullScreen }) {
                                    Icon(
                                        imageVector = if (isFullScreen) Icons.Default.FullscreenExit else Icons.Default.Fullscreen,
                                        contentDescription = "Toggle Fullscreen",
                                        tint = CyberCyan,
                                        modifier = Modifier.size(20.dp)
                                    )
                                }
                                IconButton(onClick = onDismiss) {
                                    Icon(Icons.Default.Close, contentDescription = "Close", tint = TextMuted)
                                }
                            }
                        }
                        Text(
                            "Configure and verify the Top 20 Advanced AI System Features and real-time models.",
                            color = TextMuted,
                            fontSize = 10.sp
                        )
                    }
                }

                // Sub-tabs Row
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF0A0F21))
                        .padding(horizontal = 8.dp, vertical = 6.dp),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    listOf("Core" to "⚙️ CORE SETTINGS", "Prompt" to "📑 PROMPT LIB", "Personas" to "🎭 PERSONA HUB").forEach { (tab, label) ->
                        val isSel = (activeSubTab == tab)
                        Box(
                            modifier = Modifier
                                .weight(1f)
                                .background(if (isSel) CyberPink.copy(alpha = 0.2f) else Color.Transparent, RoundedCornerShape(8.dp))
                                .border(1.dp, if (isSel) CyberPink else Color.Transparent, RoundedCornerShape(8.dp))
                                .clickable { activeSubTab = tab }
                                .padding(vertical = 8.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(label, color = if (isSel) Color.White else TextMuted, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }

                // Scrollable Content
                Box(modifier = Modifier.weight(1f)) {
                    LazyColumn(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(16.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        if (activeSubTab == "Core") {
                            // Custom Base Knowledge Prompt / custom GPT Apps Config
                            item {
                                Column(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .background(CardSpace, RoundedCornerShape(12.dp))
                                        .padding(14.dp)
                                ) {
                                    Text("🗂️ CUSTOM GPT / CUSTOM KNOWLEDGE BASE (FEATURES #8 & #20)", color = CyberCyan, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    Spacer(modifier = Modifier.height(6.dp))
                                    Text("Add custom instructions to override the AI's core behavior rules or build specialized target workflows.", color = TextMuted, fontSize = 9.sp)
                                    Spacer(modifier = Modifier.height(10.dp))
                                    OutlinedTextField(
                                        value = customKbText,
                                        onValueChange = { customKbText = it },
                                        placeholder = { Text("Example: Respond purely in bullet points like a Cyber Security expert compiler...", color = TextMuted, fontSize = 10.sp) },
                                        modifier = Modifier.fillMaxWidth(),
                                        maxLines = 4,
                                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                                        shape = RoundedCornerShape(8.dp)
                                    )
                                    Spacer(modifier = Modifier.height(8.dp))
                                    Button(
                                        onClick = {
                                            viewModel.updateCustomGptPrompt(customKbText)
                                            android.widget.Toast.makeText(context, "🪄 Knowledge Base Guidelines Synchronized!", android.widget.Toast.LENGTH_SHORT).show()
                                        },
                                        colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                                        modifier = Modifier.align(Alignment.End),
                                        shape = RoundedCornerShape(8.dp),
                                        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 6.dp)
                                    ) {
                                        Text("UPDATE AI LAWS", color = DarkBackground, fontWeight = FontWeight.Bold, fontSize = 9.sp)
                                    }
                                }
                            }

                            // Switch selections for Deep Research, Web Browsing, Agent Mode etc.
