@Composable
fun ToggleFeatureCard(
    title: String,
    description: String,
    isActive: Boolean,
    onCheckedChange: (Boolean) -> Unit,
    tintColor: Color
) {
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .background(CardSpace, RoundedCornerShape(12.dp))
            .padding(12.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column(modifier = Modifier.weight(1f)) {
                Text(title, color = tintColor, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                Spacer(modifier = Modifier.height(2.dp))
                Text(description, color = TextMuted, fontSize = 9.sp, lineHeight = 12.sp)
            }
            Spacer(modifier = Modifier.width(10.dp))
            Switch(
                checked = isActive,
                onCheckedChange = onCheckedChange,
                colors = SwitchDefaults.colors(
                    checkedThumbColor = tintColor,
                    checkedTrackColor = tintColor.copy(alpha = 0.3f),
                    uncheckedThumbColor = Color.Gray,
                    uncheckedTrackColor = Color.DarkGray
                ),
                modifier = Modifier.scale(0.8f)
            )
        }
    }
}

@Composable
fun FeatureStatusRow(
    title: String,
    status: String,
    color: Color
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.Top
    ) {
        Column(modifier = Modifier.weight(1f)) {
            Text(title, color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
            Spacer(modifier = Modifier.height(1.dp))
            Text(status, color = TextMuted, fontSize = 8.sp, lineHeight = 11.sp)
        }
        Spacer(modifier = Modifier.width(6.dp))
        Text("ACTIVE ONLINE", color = color, fontSize = 8.sp, fontWeight = FontWeight.Bold)
    }
}

// ==========================================
// 🛠️ ROBUST MULTI-FALLBACK IMAGE ENGINE DOWNLOADER
// ==========================================
fun fetchImageBytesRobustly(
    prompt: String,
    model: String,
    width: Int,
    height: Int,
    seed: String,
    negativePrompt: String = ""
): ByteArray {
    val client = okhttp3.OkHttpClient.Builder()
        .connectTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
        .readTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
        .followRedirects(true)
        .build()

    val encodedPrompt = java.net.URLEncoder.encode(prompt, "UTF-8").replace("+", "%20")
    val encodedNeg = if (negativePrompt.isNotBlank()) java.net.URLEncoder.encode(negativePrompt, "UTF-8").replace("+", "%20") else ""
    val negQuery = if (negativePrompt.isNotBlank()) "&negative=$encodedNeg" else ""

    // Try Pollinations.ai FIRST as it is the most reliable, free, cloud-friendly API offering stunning quality
    val urlsToTry = mutableListOf<String>()
    
    // 1. Primary: Pollinations with the requested model
    urlsToTry.add("https://image.pollinations.ai/p/$encodedPrompt?width=$width&height=$height&seed=$seed&model=$model&nologo=true$negQuery")
    // 2. Secondary: Pollinations defaulting to flux (ultra-stable)
    if (model != "flux") {
        urlsToTry.add("https://image.pollinations.ai/p/$encodedPrompt?width=$width&height=$height&seed=$seed&model=flux&nologo=true$negQuery")
    }
    // 3. Tertiary: Pollinations simple prompt-only URL (simplest possible request, cannot fail)
    urlsToTry.add("https://image.pollinations.ai/p/$encodedPrompt?width=$width&height=$height&seed=$seed")
    // 4. Fallback 1: api.airforce with model
    urlsToTry.add("https://api.airforce/v1/imaging/draw?prompt=$encodedPrompt&model=$model&width=$width&height=$height&seed=$seed")
    // 5. Fallback 2: api.airforce with flux
    if (model != "flux") {
        urlsToTry.add("https://api.airforce/v1/imaging/draw?prompt=$encodedPrompt&model=flux&width=$width&height=$height&seed=$seed")
    }

    var lastException: Exception? = null
    for (url in urlsToTry) {
        try {
            android.util.Log.d("ImageFetchRobust", "Attempting image fetch from URL: $url")
            val request = okhttp3.Request.Builder()
                .url(url)
                .header("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36")
                .header("Accept", "image/png,image/jpeg,image/webp,*/*")
                .build()
            
            client.newCall(request).execute().use { response ->
                if (response.isSuccessful) {
                    val bytes = response.body?.bytes()
                    if (bytes != null && bytes.size > 1000) {
                        val isPng = bytes.size >= 4 && bytes[0] == 0x89.toByte() && bytes[1] == 0x50.toByte() && bytes[2] == 0x4E.toByte() && bytes[3] == 0x47.toByte()
                        val isJpeg = bytes.size >= 3 && bytes[0] == 0xFF.toByte() && bytes[1] == 0xD8.toByte() && bytes[2] == 0xFF.toByte()
                        val isWebp = bytes.size >= 4 && bytes[0] == 'R'.toByte() && bytes[1] == 'I'.toByte() && bytes[2] == 'F'.toByte() && bytes[3] == 'F'.toByte()
                        val isGif = bytes.size >= 3 && bytes[0] == 'G'.toByte() && bytes[1] == 'I'.toByte() && bytes[2] == 'F'.toByte()
                        
                        if (isPng || isJpeg || isWebp || isGif) {
                            android.util.Log.d("ImageFetchRobust", "Successfully obtained valid image of size: ${bytes.size} bytes from URL: $url")
                            return bytes
                        } else {
                            val sample = String(bytes.copyOfRange(0, minOf(bytes.size, 150)), java.nio.charset.StandardCharsets.UTF_8).trim().lowercase()
                            android.util.Log.e("ImageFetchRobust", "Url $url returned non-image content: $sample")
                        }
                    }
                } else {
                    android.util.Log.e("ImageFetchRobust", "Request to $url failed with code: ${response.code}")
                }
                Unit
            }
        } catch (e: Exception) {
            android.util.Log.e("ImageFetchRobust", "Error fetching from $url", e)
            lastException = e
        }
    }
    
    throw lastException ?: Exception("No image could be generated after trying all public APIs.")
}

