@Composable
fun QuickImageGeneratorDialog(
    viewModel: MainViewModel,
    tool: ToolInfo? = null,
    onDismiss: () -> Unit
) {
    var currentPrompt by remember { 
        mutableStateOf(
            when (tool?.title) {
                "Logo Maker" -> "A minimalist, clean vector logo for "
                "Background Remover" -> "Erase background from the selected image"
                "Image Edit" -> "Specify changes to apply..."
