            }
        ) 
    }
    var negativePrompt by remember { mutableStateOf("blurry, low quality, deformed, worst quality, noise, bad hands") }
    var selectedStyle by remember { 
        mutableStateOf(
            when (tool?.title) {
                "AI Art" -> "Anime"
                "Logo Maker" -> "Synthwave"
                else -> "Realistic"
            }
        ) 
    }
    var selectedAspectRatio by remember { mutableStateOf("1:1") }
    var hdMode by remember { mutableStateOf(true) }
