    var selectedImageEngine by remember { mutableStateOf("Gemini Image Pro") }
    var selectedCharacter by remember { mutableStateOf("Default (No Character)") }
    var currentSeed by remember { mutableStateOf((1000..99999).random().toString()) }
    var currentImageUrl by remember { mutableStateOf<String?>(null) }
    var isProcessing by remember { mutableStateOf(false) }
    var isEnhancingPrompt by remember { mutableStateOf(false) }
    var characterConsistency by remember { mutableStateOf(false) }
    var inpaintPrompt by remember { mutableStateOf("place a beautiful flower crown") }
    var bgReplacePrompt by remember { mutableStateOf("a luxury studio background with warm soft volumetric lights") }
    var objectToErase by remember { mutableStateOf("unwanted objects") }
    var avatarMood by remember { mutableStateOf("cyberpunk digital warrior") }
    var activeTab by remember { 
        mutableStateOf(
            when (tool?.title) {
                "Background Remover", "Image Edit" -> 1 // 1: EDIT BG
                "Enhance Image" -> 2 // 2: EDIT PRO
                else -> 0 // 0: GENERATE
            }
        ) 
    }
    
    val generatorSubFeatures = remember(tool) {
        when (tool?.title) {
            "Image Generation" -> listOf(
                "Text to Image" to "fully construct a physical visual presentation directly mapped from the textual description",
                "Style selection" to "incorporate the user selected aesthetic style and color spectrum preferences beautifully",
                "HD generation" to "render with ultra high-definition crisp outlines, high-end DSLR realistic capture, and rich 8k resolution textures",
                "Aspect ratio control" to "apply balanced compositional alignment conforming to the selected display framing standards",
                "Prompt enhancer" to "leverage deep semantic details to expand the clarity and artistic richness of the prompt"
            )
            "Image Edit" -> listOf(
                "Object removal" to "intelligently erase specified negative components and details seamlessly filling the textures",
                "Object addition" to "expertly add new creative items or characters with matching ambient lighting",
                "Background editing" to "seamlessly modify backgrounds and shadows retaining focal subject details",
                "Inpainting" to "apply precise localized edit strokes conforming to focus brush boundaries",
                "Outpainting" to "extend borders and outpaint surroundings to construct an expanded panorama canvas"
            )
            "AI Art" -> listOf(
                "Anime style" to "render with breathtaking high-end Japanese anime key visual, colorful vibrant splash artwork",
                "Realistic style" to "render with physical organic lighting, detailed real-world textures, master ambient occlusions",
                "3D style" to "render as gorgeous 3D digital model, detailed cartoon game asset, octanerender style shadow profile",
                "Cartoon style" to "render with adorable stylized caricature proportions, smooth gradients, and cheerful aesthetics",
                "Digital painting" to "render as detailed speedpainting with rich digital brushstrokes and high-impact concept design"
            )
            "Enhance Image" -> listOf(
                "Upscaling" to "supersample and upscale the frame to ultra high resolution, reducing pixelation",
                "Sharpening" to "sharpen blurry outlines, recover fine micro-textures, and define structural edges",
                "Noise removal" to "clean up digital artifacts, sensor grain, and dark shadows noise smoothly",
                "Face enhancement" to "restore beautiful symmetrical facial details, clear expressive eyes, and natural skin textures",
                "Old photo restore" to "repair scratch marks, restore sepia aged photo faded colors, and remove historic dust noise"
            )
            "Poster Maker" -> listOf(
                "AI poster generation" to "arrange components with beautiful graphic design composition, solid focal structures, and promotional layouts",
                "Template selection" to "align visual alignment directly with premium high-impact corporate, retro, minimalist, or movie templates",
                "Custom text" to "ensure readable contrast borders for text overlays and commercial titles within safe design zones",
                "Marketing poster" to "style with conversion-optimized visual triggers, high contrast CTA balance, and bold colors",
                "HD export" to "encode with ultra-high-definition canvas proportions suitable for lossless massive printing outputs"
            )
            else -> emptyList()
        }
    }

    var activeToolSubFeatures by remember(tool) {
        mutableStateOf(
            when (tool?.title) {
                "Image Generation" -> setOf("Text to Image", "Style selection", "HD generation", "Aspect ratio control", "Prompt enhancer")
                "Image Edit" -> setOf("Object removal", "Object addition", "Background editing", "Inpainting", "Outpainting")
                "AI Art" -> setOf("Anime style", "Realistic style", "3D style", "Cartoon style", "Digital painting")
                "Enhance Image" -> setOf("Upscaling", "Sharpening", "Noise removal", "Face enhancement", "Old photo restore")
                "Poster Maker" -> setOf("AI poster generation", "Template selection", "Custom text", "Marketing poster", "HD export")
                else -> emptySet()
            }
        )
    }

    // Inpaint drawing state
    val drawPoints = remember { mutableStateListOf<androidx.compose.ui.geometry.Offset>() }
    
    // Multi variations panel
    var variationsList = remember { mutableStateListOf<String>() }

    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val roboFiles by viewModel.roboFiles.collectAsStateWithLifecycle()
    val localImagesList = remember(roboFiles) {
        roboFiles.filter { it.type == "Images" }.sortedByDescending { it.timestamp }
    }

    // Helper generation trigger
    fun runGenerate(editModeSuffix: String = "") {
        isProcessing = true
        coroutineScope.launch(Dispatchers.IO) {
            try {
                // Style formulation
                val styleSuffix = when (selectedStyle) {
                    "Realistic" -> ", photorealistic organic daylight portrait, 50mm focus lens, DSLR capture, natural textures"
                    "Anime" -> ", stunning gorgeous anime master key art, detailed aesthetic backdrop, colorful splash illustration, masterpiece"
                    "3D Render" -> ", realistic hyper-detailed cinematic 3D render, octanerender raytraced lights, volumetric shadows, high fidelity"
                    "Cartoon" -> ", playful 3D pixar style animation keyframe, cute rendering, beautiful saturated tones"
                    "Cinematic" -> ", moody cinematic movie film screen capture, cinematic contrast grading, anamorphic flare, mysterious lighting"
                    "Synthwave" -> ", retro 1980s synthwave neon glowing aesthetic, dark background with laser grids and violet stars"
                    "Watercolor" -> ", high quality analog watercolor painting sketch, paper texture accents, detailed soft aesthetic design"
                    else -> ""
                }

                // HD multiplier
                val hdQuality = if (hdMode) ", hyper-detailed ultra precision raw capture, cinematic crisp details, 8k resolution focus" else ""
                
                // Aspect ratios dimension calculation
                val (w, h) = when (selectedAspectRatio) {
                    "16:9" -> 1280 to 720
                    "9:16" -> 720 to 1280
                    "4:5" -> 800 to 1000
                    "2:3" -> 800 to 1200
                    else -> 1024 to 1024 // 1:1
                }

                val characterSuffix = when (selectedCharacter) {
                    "Rabiya (Beautiful Assistant)" -> ", a highly professional, beautiful Indian woman named Rabiya, wearing an elegant business suit, warm friendly smile, detailed expressive eyes, natural soft studio lighting"
                    "Tech Entrepreneur" -> ", a confident young tech entrepreneur wearing a modern casual blazer and smart glasses, in a high-tech startup workspace with holographic elements in the background, cinematic volumetric lighting"
                    "Cyberpunk Warrior" -> ", a fierce cyberpunk digital warrior, futuristic glowing neon gear, leather jacket, standing on a rainy street of neon Tokyo, intricate cybernetic details, masterpiece"
                    "Spiritual Yogi" -> ", a peaceful spiritual yogi in deep lotus meditation, golden divine aura, serene facial expression, background of misty Himalayas at sunrise, highly detailed concept art"
                    "Fantasy Knight" -> ", a brave medieval fantasy knight in polished silver armor, holding a glowing magical sword, standing on a dramatic cliff looking over a misty fantasy valley, cinematic film look"
                    "Adorable 3D Chibi" -> ", a cute 3D chibi character, giant glowing expressive cartoon eyes, soft stylized details, pastel color theme, Unreal Engine 5 render style, Pixar style keyframe"
                    "Corporate Executive" -> ", a highly confident, elegant corporate executive, tailored business attire, standing in a luxury high-rise modern office background, professional corporate profile"
                    else -> ""
                }

                val basePrompt = if (currentPrompt.isBlank()) {
                    if (characterSuffix.isNotEmpty()) "A professional portrait$characterSuffix"
                    else "A beautiful realistic studio portrait of woman relaxed smiling in simple elegant setting"
                } else {
                    "$currentPrompt$characterSuffix"
                }

                val extraFeaturesPrompt = buildString {
                    if (activeToolSubFeatures.isNotEmpty()) {
                        activeToolSubFeatures.forEach { feat ->
                            val text = when (feat) {
                                "Text to Image" -> "fully construct a physical visual presentation directly mapped from the textual description"
                                "Style selection" -> "incorporate the user selected aesthetic style and color spectrum preferences beautifully"
                                "HD generation" -> "render with ultra high-definition crisp outlines, high-end DSLR realistic capture, and rich 8k resolution textures"
                                "Aspect ratio control" -> "apply Composition alignment conforming to selected display framing standards"
                                "Prompt enhancer" -> "leverage deep semantic details to expand high-end clarity and artistic richness of the prompt"
                                "Object removal" -> "intelligently erase specified negative components and details seamlessly filling the textures"
                                "Object addition" -> "expertly add new creative items or characters with matching ambient lighting"
                                "Background editing" -> "seamlessly modify backgrounds and shadows retaining focal subject details"
                                "Inpainting" -> "apply precise localized edit strokes conforming to focus brush boundaries"
                                "Outpainting" -> "extend borders and outpaint surroundings to construct an expanded panorama canvas"
                                "Anime style" -> "render in majestic Japanese animation keyframe style, with gorgeous light accents and splash visual watercolor details"
                                "Realistic style" -> "render with physical organic lighting, detailed real-world textures, master ambient occlusions"
                                "3D style" -> "render as gorgeous high-fidelity 3D digital model, with volumetric ray-traced shadows and high lights"
                                "Cartoon style" -> "render with lovely stylized caricature proportions, smooth gradients, and cheerful aesthetics"
                                "Digital painting" -> "render as detailed speedpainting with rich digital brushstrokes and high-impact concept design"
                                "Upscaling" -> "supersample and upscale the frame to ultra high resolution, reducing pixelation"
                                "Sharpening" -> "sharpen blurry outlines, recover fine micro-textures, and define structural edges"
                                "Noise removal" -> "clean up digital artifacts, sensor grain, and dark shadows noise smoothly"
                                "Face enhancement" -> "restore beautiful symmetrical facial details, clear expressive eyes, and natural skin textures"
                                "Old photo restore" -> "repair scratch marks, restore sepia aged photo faded colors, and remove historic dust noise"
                                "AI poster generation" -> "arrange components with beautiful graphic design composition, solid focal structures, and promotional layouts"
                                "Template selection" -> "align visual alignment directly with premium high-impact corporate, retro, minimalist, or movie templates"
                                "Custom text" -> "ensure readable contrast borders for text overlays and commercial titles within safe design zones"
                                "Marketing poster" -> "style with conversion-optimized visual triggers, high contrast CTA balance, and bold colors"
                                "HD export" -> "encode with ultra-high-definition canvas proportions suitable for lossless massive printing outputs"
                                else -> ""
                            }
                            if (text.isNotEmpty()) {
                                append(", $text")
                            }
                        }
                    }
                }

                val fullPromptText = "$basePrompt$styleSuffix$hdQuality$extraFeaturesPrompt$editModeSuffix"
                val fallbackModel = when (selectedImageEngine) {
                    "Meta AI Realism" -> "flux-realism"
                    "Gemini Image Pro" -> "flux"
                    "DALL-E 3 Ultra" -> "flux"
                    "Midjourney v6" -> "any-dark"
                    "DeepAI Image Gen" -> "flux-anime"
                    else -> "flux"
                }

                val bodyBytes = fetchImageBytesRobustly(
                    prompt = fullPromptText,
                    model = fallbackModel,
                    width = w,
                    height = h,
                    seed = currentSeed,
                    negativePrompt = negativePrompt
                )

                val cleanLabel = basePrompt.take(15).replace(" ", "_").replace(Regex("[^a-zA-Z0-9_]"), "")
                val imgFilename = "Studio_${cleanLabel}_${System.currentTimeMillis()}.png"
                
                // Directly write synchronously on background thread
                val rootDir = java.io.File(context.filesDir, "FileManager")
                val catDir = java.io.File(rootDir, "Images")
                if (!catDir.exists()) catDir.mkdirs()
                val localFile = java.io.File(catDir, imgFilename)
                localFile.writeBytes(bodyBytes)
                
                viewModel.refreshRoboFiles(context)
                
                kotlinx.coroutines.withContext(Dispatchers.Main) {
                    currentImageUrl = localFile.absolutePath
                }
            } catch (e: Exception) {
                Log.e("AdvancedStudio", "Generate failed", e)
                kotlinx.coroutines.withContext(Dispatchers.Main) {
                    android.widget.Toast.makeText(context, "Image generation failed: ${e.localizedMessage}", android.widget.Toast.LENGTH_LONG).show()
                }
            } finally {
                kotlinx.coroutines.withContext(Dispatchers.Main) {
                    isProcessing = false
                }
            }
        }
    }

