// ==========================================
// 🚀 AI FILM DESIGN & CINEMA STUDIO DIALOG: REELGEN & LIP-SYNC STUDIO
// ==========================================
@Composable
fun ImageToVideoCreatorDialog(
    viewModel: MainViewModel,
    onDismiss: () -> Unit
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val filesList by viewModel.roboFiles.collectAsStateWithLifecycle()
    
    val localImages = remember(filesList) {
        filesList.filter { it.type == "Images" || it.name.endsWith(".png") || it.name.endsWith(".jpg") || it.name.endsWith(".jpeg") }
    }
    val localVoices = remember(filesList) {
        filesList.filter { it.type == "Voice" || it.name.endsWith(".mp3") || it.name.endsWith(".wav") }
    }
    
    var selectedImageFile by remember { mutableStateOf<RoboFile?>(null) }
    var selectedVoiceFile by remember { mutableStateOf<RoboFile?>(null) }
    
    // Sliders to align lip synchronization coordinates on selected face image
    var mouthAnchorX by remember { mutableFloatStateOf(0.50f) }
    var mouthAnchorY by remember { mutableFloatStateOf(0.68f) }
    var mouthAnchorSize by remember { mutableFloatStateOf(35f) }
    
    // Prompt Inputs & Script Generation
    var promptForShortsTopic by remember { mutableStateOf("") }
    var userNarrativeScript by remember { mutableStateOf("") }
    var selectedLanguageCode by remember { mutableStateOf("hi") } // hi, en, ur
    var selectedTone by remember { mutableStateOf("Motivational / High Energy") }
    
    var isScriptGenerating by remember { mutableStateOf(false) }
    var imageGeneratingState by remember { mutableStateOf(false) }
    var promptForImage by remember { mutableStateOf("") }
    var voiceGeneratingState by remember { mutableStateOf(false) }
    
    // Vocal profiles
    val speakingArtists = remember {
        listOf(
            Triple("Zara - Warm Urdu / Poetical Profile", "hi", "Female"),
            Triple("Arjun - Indian Accent Energetic Male", "hi", "Male"),
            Triple("Sarah - British Narrator Voice (Rich Theme)", "en", "Female"),
            Triple("John - American Professional Explainer", "en", "Male"),
            Triple("Rabiya Core - Cosmic High Resonance", "hi", "Female")
        )
    }
    var selectedArtistIndex by remember { mutableIntStateOf(0) }
    var selectedEmotionStyle by remember { mutableStateOf("Excited") }
    val emotionalPresences = listOf("Excited", "Dramatic", "Warm", "Mysterious / Cosmic", "Sad Output")
    
    // Media Playback State
    var isReelPlaying by remember { mutableStateOf(false) }
    var activePlayer: android.media.MediaPlayer? by remember { mutableStateOf(null) }
    var currentPlaybackProgress by remember { mutableStateOf(0) }
    var totalAudioDurationMs by remember { mutableStateOf(1) }
    var lipSyncPulseFactor by remember { mutableFloatStateOf(1f) }
    
    // Subtitles generator variables
    var subtitleWordsList = remember { mutableStateListOf<String>() }
    var activeWordIndex by remember { mutableIntStateOf(-1) }
    
    // Interactive render progress console indicators
    var renderProgress by remember { mutableFloatStateOf(0f) }
    var renderingState by remember { mutableStateOf(false) }
    val renderOutputLogs = remember { mutableStateListOf<String>("Digital workstation idle. Anchors awaiting configuration...") }
    
    // Completed assets outputs
    var completedVideoPath by remember { mutableStateOf<String?>(null) }
    var completedVideoName by remember { mutableStateOf<String?>(null) }
    var playInteractivePreview by remember { mutableStateOf(false) }
    
    var isAuditionPlaying by remember { mutableStateOf(false) }
    var auditionPlayer: android.media.MediaPlayer? by remember { mutableStateOf(null) }
    
    // Media controllers dispose routines
    DisposableEffect(Unit) {
        onDispose {
            auditionPlayer?.release()
            activePlayer?.release()
        }
    }
    
    // Coroutine tracking elapsed playback positions for Lip-Sync and Captions matching
    LaunchedEffect(isReelPlaying, activePlayer) {
        if (isReelPlaying && activePlayer != null) {
            try {
                totalAudioDurationMs = activePlayer?.duration ?: 1
                if (totalAudioDurationMs <= 0) totalAudioDurationMs = 5000 // safeguard fallback
                
                while (isReelPlaying && activePlayer != null && activePlayer?.isPlaying == true) {
                    val currentPos = activePlayer?.currentPosition ?: 0
                    currentPlaybackProgress = currentPos
                    
                    // Lip sync pulse factor modulated by audio time and high fidelity variations
                    lipSyncPulseFactor = 1.0f + (0.9f * kotlin.math.sin(currentPos / 45.0).toFloat() * (0.6f + 0.4f * (0..1).random()))
                    
                    // Track dynamic subtitles index matching word timelines
                    if (subtitleWordsList.isNotEmpty()) {
                        val durationPerWord = totalAudioDurationMs / subtitleWordsList.size
                        val currentWordMappedIdx = currentPos / durationPerWord
                        activeWordIndex = currentWordMappedIdx.coerceAtMost(subtitleWordsList.size - 1)
                    }
                    
                    kotlinx.coroutines.delay(25)
                }
                isReelPlaying = false
                activeWordIndex = -1
                lipSyncPulseFactor = 1f
            } catch (e: Exception) {
                Log.e("LipSync", "Error tracing play progress", e)
                isReelPlaying = false
            }
        }
    }
    
    // Activity Result Launcher to pick any custom portrait from phone gallery
    val imagePickerLauncher = rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri ->
        uri?.let {
            try {
                val inputStream = context.contentResolver.openInputStream(it)
                val bytes = inputStream?.readBytes()
                if (bytes != null) {
                    val filename = "CineLips_Portrait_${System.currentTimeMillis()}.jpg"
                    viewModel.addFileToFileManager(context, filename, "Images", "", bytes)
                    
                    // Auto-detect and select the newly uploaded file reference
                    val path = java.io.File(context.filesDir, "FileManager/Images/$filename").absolutePath
                    val newObj = RoboFile(filename, "${bytes.size / 1024} KB", "Images", path)
                    selectedImageFile = newObj
                    android.widget.Toast.makeText(context, "Uploaded & selected customized portrait frame! 📸", android.widget.Toast.LENGTH_SHORT).show()
                }
            } catch (e: Exception) {
                android.widget.Toast.makeText(context, "Portrait load failed: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
            }
        }
    }
    
    Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Surface(
            modifier = Modifier
                .fillMaxWidth(0.96f)
                .fillMaxHeight(0.94f)
                .padding(4.dp)
                .border(2.dp, Brush.horizontalGradient(listOf(CyberCyan, CyberPink)), RoundedCornerShape(24.dp)),
            shape = RoundedCornerShape(24.dp),
            color = DarkBackground
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(14.dp)
                    .verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(14.dp)
            ) {
                // DIALOG HEADER DISPLAY
                Row(
                    modifier = Modifier.fillMaxWidth().padding(bottom = 4.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        Box(
                            modifier = Modifier
                                .size(32.dp)
                                .background(CyberCyan.copy(alpha = 0.15f), CircleShape)
                                .border(1.dp, CyberCyan, CircleShape),
                            contentAlignment = Alignment.Center
                        ) {
                            Icon(Icons.Default.Slideshow, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(16.dp))
                        }
                        Column {
                            Text("CINEFACE AI REELS STUDIO 🎬", color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Black, letterSpacing = 0.8.sp)
                            Text("Automatic Instant Image to Talking Lip-Synced Video Node Generator", color = TextMuted, fontSize = 8.5.sp)
                        }
                    }
                    IconButton(
                        onClick = onDismiss,
                        modifier = Modifier
                            .size(30.dp)
                            .background(Color(0xFF131A2D), CircleShape)
                    ) {
                        Icon(Icons.Default.Close, contentDescription = "Close", tint = CyberPink, modifier = Modifier.size(16.dp))
                    }
                }
                
                Divider(color = GridSpace, thickness = 1.2.dp)

                // 🛡️ Sponsored Admob Banner under cineface studio header
                AdMobBanner(modifier = Modifier.padding(vertical = 4.dp))
                
                // MAIN STEP 1: LOAD THE FACE BACKGROUND PORTRAIT
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(CardSpace, RoundedCornerShape(16.dp))
                        .border(1.dp, GridSpace, RoundedCornerShape(16.dp))
                        .padding(12.dp)
                ) {
                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("1. TALKING AVATAR FACE (PORTRAIT BACKGROUND)", color = CyberPink, fontSize = 10.5.sp, fontWeight = FontWeight.Bold)
                            Text(
                                text = if (selectedImageFile != null) "🔒 FACE DETECTED" else "⚠️ PHOTO REQUIRED",
                                color = if (selectedImageFile != null) SuccessGreen else CyberPink,
                                fontSize = 8.sp,
                                fontWeight = FontWeight.ExtraBold,
                                modifier = Modifier
                                    .background(if (selectedImageFile != null) SuccessGreen.copy(alpha = 0.15f) else CyberPink.copy(alpha = 0.15f), RoundedCornerShape(4.dp))
                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                            )
                        }
                        
                        // Picture gallery preview carousel
                        if (localImages.isNotEmpty()) {
                            Text("Choose from library draft coordinates:", color = TextMuted, fontSize = 8.5.sp)
                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(8.dp),
                                modifier = Modifier.fillMaxWidth().padding(vertical = 2.dp)
