                                            if (streamBytes != null) {
                                                val targetVideoFileName = "AI_CineLips_Reel_${System.currentTimeMillis()}.mp4"
                                                viewModel.addFileToFileManager(context, targetVideoFileName, "Video", "Reel video generated from custom image, speech audio, and automatic aligned lip animation.", streamBytes)
                                                
                                                kotlinx.coroutines.delay(800)
                                                val path = java.io.File(context.filesDir, "FileManager/Video/$targetVideoFileName").absolutePath
                                                
                                                completedVideoPath = path
                                                completedVideoName = targetVideoFileName
                                                viewModel.downloadRoboFile(context, RoboFile(targetVideoFileName, "${streamBytes.size / 1024} KB", "Video", path))
                                            }
                                        }
                                    }
                                } catch (e: Exception) {
                                    Log.e("CineSpace", "Video compilation stream error", e)
                                }
                            }
                            
                            renderProgress = 1.0f
                            renderOutputLogs.add("✅ VIDEO LIP-SYNC REEL COMPILED SUCCESSFULLY!")
                            renderOutputLogs.add(">> Asset registered in File Manager (Video) and Downloads folder!")
                            renderingState = false
                            playInteractivePreview = true
                        }
                    },
                    modifier = Modifier.fillMaxWidth().height(48.dp),
                    colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                    shape = RoundedCornerShape(12.dp),
                    enabled = !renderingState
                ) {
                    Text(
                        if (renderingState) "ALIGNING FACIAL VECTOR APERTURE GRIDS... ✨" else "GENERATE SHORTS LIP-SYNC REEL 🚀",
                        color = DarkBackground,
                        fontWeight = FontWeight.Black,
                        fontSize = 11.sp,
                        letterSpacing = 0.5.sp
                    )
                }
                
                // RENDER LOG CONSOLE OUTPUT BOX
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(GridSpace, RoundedCornerShape(12.dp))
                        .padding(10.dp)
                ) {
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                            Text("STUDIO CONSOLE MONITOR", color = CyberCyan, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                            if (renderingState) {
                                Text("COMPILING: ${(renderProgress * 100).toInt()}%", color = CyberPink, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                        
                        if (renderingState) {
                            LinearProgressIndicator(
                                progress = { renderProgress },
                                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
                                color = CyberCyan,
                                trackColor = Color(0xFF070B15)
                            )
                        }
                        
                        Column(
                            verticalArrangement = Arrangement.spacedBy(3.dp),
                            modifier = Modifier
                                .heightIn(max = 110.dp)
                                .fillMaxWidth()
                                .verticalScroll(rememberScrollState())
                        ) {
                            renderOutputLogs.forEach { log ->
                                Text(">> $log", color = TextMuted, fontSize = 8.sp, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                            }
                        }
                    }
                }
                
                // HIGH FIDELITY 9:16 VERTICAL SHORTS CINEMA PLAYER
                if (playInteractivePreview && selectedImageFile != null) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(CardSpace, RoundedCornerShape(16.dp))
                            .border(1.dp, CyberCyan.copy(alpha = 0.35f), RoundedCornerShape(16.dp))
                            .padding(14.dp)
                    ) {
                        Column(
                            verticalArrangement = Arrangement.spacedBy(10.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("🎥 9:16 AUTOMATED YOUTUBE SHORTS MONITOR", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                
                                Button(
                                    onClick = {
                                        completedVideoPath?.let { path ->
                                            val original = java.io.File(path)
                                            if (original.exists()) {
                                                viewModel.downloadRoboFile(context, RoboFile(completedVideoName ?: "ai_reel.mp4", "1000 KB", "Video", path))
                                                android.widget.Toast.makeText(context, "Saved video file directly to phone Gallery!", android.widget.Toast.LENGTH_SHORT).show()
                                            }
                                        }
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = CyberPink),
                                    shape = RoundedCornerShape(8.dp),
                                    contentPadding = PaddingValues(horizontal = 10.dp, vertical = 2.dp)
                                ) {
                                    Text("DOWNLOAD MP4 TO GALLERY 📥", color = Color.White, fontSize = 7.5.sp, fontWeight = FontWeight.Black)
                                }
                            }
                            
                            // VERTICAL 9:16 PHONE SCREEN MOCKUP GRID WITH INTERACTIVE ANIMATION OVERLAYS
                            Box(
                                modifier = Modifier
                                    .width(180.dp)
                                    .height(290.dp)
                                    .border(3.dp, Color(0xFF131A2D), RoundedCornerShape(16.dp))
                                    .clip(RoundedCornerShape(16.dp))
                                    .background(Color.Black),
                                contentAlignment = Alignment.Center
                            ) {
                                // Background base talking portrait img
                                AsyncImage(
                                    model = selectedImageFile?.absolutePath,
                                    contentDescription = "Portrait active speaking frame",
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = ContentScale.Crop
                                )
                                
                                // Ambient particle/mood flames overlays reflecting Selected Emotion Presence
                                Box(modifier = Modifier.fillMaxSize()) {
                                    val particleColor = when (selectedEmotionStyle) {
                                        "Excited" -> CyberCyan
                                        "Dramatic" -> CyberPink
                                        "Warm" -> Color(0xFFFFB300)
                                        "Sad Output" -> Color(0xFF1E88E5)
                                        else -> GridSpace
                                    }
                                    
                                    // Simulated floating particle arrays on top of image
                                    repeat(6) { idx ->
                                        val randomXFactor = remember { (10..90).random() / 100f }
                                        val randomYFactor = remember { (20..80).random() / 100f }
                                        val animatedOpacity by animateFloatAsState(
                                            targetValue = if (isReelPlaying) 0.8f else 0.1f,
                                            animationSpec = infiniteRepeatable(
                                                animation = tween((1200..2000).random(), easing = LinearEasing),
                                                repeatMode = RepeatMode.Reverse
                                            ),
                                            label = ""
                                        )
                                        Box(
                                            modifier = Modifier
                                                .fillMaxSize()
                                                .drawBehind {
                                                    drawCircle(
                                                        color = particleColor.copy(alpha = animatedOpacity),
                                                        radius = (2..5).random().toFloat() * (if (isReelPlaying) 1.5f else 1f),
                                                        center = androidx.compose.ui.geometry.Offset(this.size.width * randomXFactor, this.size.height * randomYFactor)
                                                    )
                                                }
                                        )
                                    }
                                }
                                
                                // LIVE LIP-SYNC TARGET AREA (Animated glowing lips vector rig overlaying mouth coordinates)
                                BoxWithConstraints(modifier = Modifier.fillMaxSize()) {
                                    val hOffset = maxHeight * mouthAnchorY
                                    val wOffset = maxWidth * mouthAnchorX
                                    
                                    Box(
                                        modifier = Modifier
                                            .offset(x = wOffset - 25.dp, y = hOffset - 25.dp)
                                            .size(50.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        // Display animated lip deforming vector mesh active when playing
                                        Canvas(modifier = Modifier.fillMaxSize()) {
                                            val ampFactor = if (isReelPlaying) lipSyncPulseFactor else 0.1f
                                            
                                            // Render animated glowing speech wave contours around the anchor area
                                            drawCircle(
                                                color = CyberCyan.copy(alpha = if (isReelPlaying) 0.5f else 0.15f),
                                                radius = mouthAnchorSize * (0.6f + 0.4f * ampFactor),
                                                style = androidx.compose.ui.graphics.drawscope.Stroke(width = 1.6f)
                                            )
                                            
                                            drawCircle(
                                                color = CyberPink.copy(alpha = if (isReelPlaying) 0.35f else 0.05f),
                                                radius = mouthAnchorSize * (0.9f + 0.7f * ampFactor),
                                                style = androidx.compose.ui.graphics.drawscope.Stroke(width = 1f)
                                            )
                                            
                                            val mw = this.size.width
                                            val mh = this.size.height
                                            val centerTopY = mh / 2f
                                            // The core speaking mouth shape (deforming lip vector)
                                            val closedPath = androidx.compose.ui.graphics.Path().apply {
                                                moveTo(mw * 0.25f, centerTopY)
                                                // Top lip curve deforms upward with volume amp
                                                quadraticBezierTo(mw * 0.5f, centerTopY - (12f * ampFactor), mw * 0.75f, centerTopY)
                                                // Bottom lip curve deforms downward with volume amp
                                                quadraticBezierTo(mw * 0.5f, centerTopY + (16f * ampFactor), mw * 0.25f, centerTopY)
                                            }
                                            
                                            drawPath(
                                                path = closedPath,
                                                color = CyberPink.copy(alpha = 0.85f),
                                                style = androidx.compose.ui.graphics.drawscope.Fill
                                            )
                                        }
                                    }
                                }
                                
                                // DETAILED SOUND WAVES INTEGRATION GRAPH FLOATING AT THE BOTTOM
                                if (isReelPlaying) {
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.BottomCenter)
                                            .fillMaxWidth()
                                            .height(35.dp)
                                            .background(
                                                Brush.verticalGradient(
                                                    colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.8f))
                                                )
                                            ),
                                        contentAlignment = Alignment.BottomCenter
                                    ) {
                                        Row(
                                            horizontalArrangement = Arrangement.spacedBy(3.dp),
                                            verticalAlignment = Alignment.Bottom,
                                            modifier = Modifier.padding(bottom = 6.dp)
                                        ) {
                                            repeat(10) { idx ->
                                                val randomHeightHeight = remember { (4..24).random() }
                                                val animatedHeightScale by animateFloatAsState(
                                                    targetValue = if (isReelPlaying) 1.2f else 0.1f,
                                                    animationSpec = infiniteRepeatable(
                                                        animation = tween(250 + (idx * 30), easing = LinearOutSlowInEasing),
                                                        repeatMode = RepeatMode.Reverse
                                                    ),
                                                    label = ""
                                                )
                                                Box(
                                                    modifier = Modifier
                                                        .width(3.dp)
                                                        .height((randomHeightHeight * animatedHeightScale).dp)
                                                        .background(CyberCyan, RoundedCornerShape(1.dp))
                                                )
                                            }
                                        }
                                    }
                                }
                                
                                // VIRAL ENGAGING KINETIC CAPTION SUBTITLES OVERLAY FLASHING WORD-BY-WORD
                                if (isReelPlaying && activeWordIndex in subtitleWordsList.indices) {
                                    val activeWordString = subtitleWordsList[activeWordIndex]
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.Center)
                                            .padding(horizontal = 10.dp)
                                            .background(Color.Black.copy(alpha = 0.75f), RoundedCornerShape(8.dp))
                                            .padding(horizontal = 12.dp, vertical = 6.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = activeWordString,
                                            color = Color(0xFFFFF135), // Famous bright yellow trendy text captions!
                                            fontSize = 11.5.sp,
                                            fontWeight = FontWeight.Black,
                                            textAlign = TextAlign.Center,
                                            letterSpacing = 0.5.sp,
                                            style = androidx.compose.ui.text.TextStyle(
                                                shadow = androidx.compose.ui.graphics.Shadow(
                                                    color = Color.Black,
                                                    offset = androidx.compose.ui.geometry.Offset(1.5f, 1.5f),
                                                    blurRadius = 3f
                                                )
                                            )
                                        )
                                    }
                                }
                                
                                // Watermark
                                Text(
                                    "YOUTUBE SHORTS - RABIYA AI REELS",
                                    color = Color.White.copy(alpha = 0.45f),
                                    fontSize = 5.5.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .align(Alignment.BottomStart)
                                        .padding(8.dp)
                                )
                            }
                            
                            // Audio player button controller actions
                            Row(
                                horizontalArrangement = Arrangement.spacedBy(10.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Button(
                                    onClick = {
                                        if (isReelPlaying) {
                                            activePlayer?.pause()
                                            isReelPlaying = false
                                        } else {
                                            selectedVoiceFile?.let { voiceFile ->
                                                try {
                                                    activePlayer?.release()
                                                    val mp = android.media.MediaPlayer()
                                                    mp.setDataSource(voiceFile.absolutePath)
                                                    mp.setOnPreparedListener {
                                                        mp.start()
                                                        activePlayer = mp
                                                        isReelPlaying = true
                                                    }
                                                    mp.setOnCompletionListener {
                                                        isReelPlaying = false
                                                        activeWordIndex = -1
                                                    }
                                                    mp.prepareAsync()
                                                } catch (ex: Exception) {
                                                    android.widget.Toast.makeText(context, "Sound playback failed: ${ex.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                                                }
                                            }
                                        }
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = if (isReelPlaying) CyberPink else CyberCyan),
                                    shape = RoundedCornerShape(10.dp)
                                ) {
                                    Icon(
                                        imageVector = if (isReelPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,
                                        contentDescription = "Trigger Speech",
                                        tint = if (isReelPlaying) Color.White else DarkBackground,
                                        modifier = Modifier.size(16.dp)
                                    )
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Text(
                                        if (isReelPlaying) "STOP AUDIO LOOP" else "PLAY REEL AUDIO 🔔",
                                        color = if (isReelPlaying) Color.White else DarkBackground,
                                        fontSize = 9.sp,
                                        fontWeight = FontWeight.Black
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

// ==========================================
// 🎙️ AUTO CAPTION SUBTITLE STUDIO DIALOG & METRIC SYSTEM

// ==========================================
data class SubtitleSegment(
    val startMs: Long,
    val endMs: Long,
    val text: String
)

@Composable
fun AutoCaptionSubtitleDialog(
    viewModel: MainViewModel,
    onDismiss: () -> Unit
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val scope = rememberCoroutineScope()
    val filesList by viewModel.roboFiles.collectAsStateWithLifecycle()
    
    val localVideos = remember(filesList) {
        filesList.filter { it.type == "Video" || it.name.lowercase().endsWith(".mp4") || it.name.lowercase().endsWith(".mkv") || it.name.lowercase().endsWith(".mov") }
    }
    
    var selectedVideoFile by remember { mutableStateOf<RoboFile?>(null) }
    
    var selectedLanguage by remember { mutableStateOf("Hindi") }
    val languages = listOf("Hindi", "English", "Urdu", "Spanish", "French", "German")
    
    var selectedStylePreset by remember { mutableStateOf("Dynamic Neon Kinetic") }
    val stylePresets = listOf("Dynamic Neon Kinetic", "Karaoke Bouncing", "Clean Minimalist", "Bold Cyberpunk", "Retro VHS")
    
    var fontSizeVal by remember { mutableFloatStateOf(18f) }
    
    var selectedColorName by remember { mutableStateOf("CyberCyan") }
    val colorNames = listOf("CyberCyan", "CyberPink", "Amber Gold", "Pure White", "Neon Purple", "Lime Green")
    
    var selectedAlignment by remember { mutableStateOf("Bottom Center") }
    val alignments = listOf("Top Center", "Center", "Bottom Center")
    
    var customTranscriptHint by remember { mutableStateOf("") }
    
    var isProcessing by remember { mutableStateOf(false) }
    var processingProgress by remember { mutableFloatStateOf(0f) }
    val processingLogs = remember { mutableStateListOf<String>("System initialized. Choose a video or record voice below to generate captions.") }
    val captionTracks = remember { mutableStateListOf<SubtitleSegment>() }
    var isCaptionProcessed by remember { mutableStateOf(false) }
    
    var isPlaying by remember { mutableStateOf(false) }
    var currentPlaybackMs by remember { mutableLongStateOf(0L) }
    val totalPlaybackMs = remember(captionTracks) {
        if (captionTracks.isEmpty()) 15000L else captionTracks.last().endMs + 800
    }
    
    LaunchedEffect(isPlaying, totalPlaybackMs) {
        if (isPlaying) {
            while (isPlaying) {
                kotlinx.coroutines.delay(100)
                val next = currentPlaybackMs + 100
                currentPlaybackMs = if (next >= totalPlaybackMs) 0L else next
            }
        }
    }
    
    val videoPickerLauncher = rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri ->
        if (uri != null) {
            scope.launch(Dispatchers.IO) {
                try {
                    val resolver = context.contentResolver
                    var displayName = "video_${System.currentTimeMillis()}.mp4"
                    val cursor = resolver.query(uri, null, null, null, null)
                    cursor?.use {
                        if (it.moveToFirst()) {
                            val nameIdx = it.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                            if (nameIdx != -1) displayName = it.getString(nameIdx)
                        }
                    }
                    
                    val inputStream = resolver.openInputStream(uri)
                    val bytes = inputStream?.readBytes()
                    inputStream?.close()
                    
                    if (bytes != null) {
                        viewModel.addFileToFileManager(context, displayName, "Video", "", bytes)
                        val path = java.io.File(context.filesDir, "FileManager/Video/$displayName").absolutePath
                        withContext(Dispatchers.Main) {
                            selectedVideoFile = RoboFile(displayName, "${bytes.size / 1024} KB", "Video", path)
                            android.widget.Toast.makeText(context, "✅ Picked Video: $displayName", android.widget.Toast.LENGTH_SHORT).show()
                        }
                    }
                } catch (e: Exception) {
                    withContext(Dispatchers.Main) {
                        android.widget.Toast.makeText(context, "Failed to load video: ${e.message}", android.widget.Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }
    }
    
    val activeColor = when (selectedColorName) {
        "CyberCyan" -> CyberCyan
        "CyberPink" -> CyberPink
        "Amber Gold" -> Color(0xFFFFB300)
        "Pure White" -> Color.White
        "Neon Purple" -> Color(0xFF8B5CF6)
        "Lime Green" -> Color(0xFF22C55E)
        else -> Color.White
    }
    
    fun generateCustomSubtitles(text: String): List<SubtitleSegment> {
        val words = text.split(" ").filter { it.isNotBlank() }
        if (words.isEmpty()) return emptyList()
        val list = mutableListOf<SubtitleSegment>()
        
        val wordsPerSegment = when {
            words.size <= 6 -> 2
            words.size <= 12 -> 3
            else -> 4
        }
        
        var currentStartMs = 0L
        val segmentDurationMs = 3000L
        
        for (i in words.indices step wordsPerSegment) {
            val endIdx = minOf(i + wordsPerSegment, words.size)
            val chunk = words.subList(i, endIdx)
            val chunkText = chunk.joinToString(" ")
            list.add(
                SubtitleSegment(
                    startMs = currentStartMs,
                    endMs = currentStartMs + segmentDurationMs - 300,
                    text = chunkText
                )
            )
            currentStartMs += segmentDurationMs
        }
        return list
    }
    
    Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Surface(
            modifier = Modifier
                .fillMaxWidth(0.96f)
                .fillMaxHeight(0.94f)
                .padding(6.dp)
                .border(2.dp, CyberCyan.copy(alpha = 0.5f), RoundedCornerShape(24.dp)),
            shape = RoundedCornerShape(24.dp),
            color = DarkBackground
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(16.dp)
                    .verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(14.dp)
            ) {
                // Header display
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Box(
                            modifier = Modifier
                                .background(CyberCyan.copy(alpha = 0.15f), CircleShape)
                                .padding(10.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.ClosedCaption,
                                contentDescription = "Auto Caption Logo",
                                tint = CyberCyan,
                                modifier = Modifier.size(24.dp)
                            )
                        }
                        Column {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                Text(
                                    "AUTO CAPTION SUBTITLE",
                                    fontWeight = FontWeight.ExtraBold,
                                    color = Color.White,
                                    fontSize = 15.sp,
                                    letterSpacing = 0.8.sp
                                )
                                Box(
                                    modifier = Modifier
                                        .background(CyberPink.copy(alpha = 0.2f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 5.dp, vertical = 2.dp)
                                ) {
                                    Text("PRO AI", color = CyberPink, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                            Text(
                                "Voice stream speech analyzer & automatic subtitle overlays",
                                color = TextMuted,
                                fontSize = 10.sp
                            )
                        }
                    }
                    IconButton(onClick = onDismiss) {
                        Icon(Icons.Default.Close, contentDescription = "Dismiss", tint = Color.LightGray)
                    }
                }
                
                // 🛡️ Sponsored Admob Banner under caption header
                AdMobBanner(modifier = Modifier.padding(vertical = 4.dp))
                
                // Video details picker
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(CardSpace, RoundedCornerShape(16.dp))
                        .border(1.dp, Color(0xFF1E2945), RoundedCornerShape(16.dp))
                        .padding(14.dp)
                ) {
                    Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("1. SELECT VIDEO FILE FOR SUBTITLES", color = CyberCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Button(
                                onClick = { videoPickerLauncher.launch("video/*") },
                                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF1D4ED8)),
                                contentPadding = PaddingValues(horizontal = 12.dp, vertical = 4.dp),
                                shape = RoundedCornerShape(8.dp)
                            ) {
                                Icon(Icons.Default.Upload, contentDescription = "Upload Icon", modifier = Modifier.size(12.dp), tint = Color.White)
                                Spacer(modifier = Modifier.width(4.dp))
                                Text("Upload New Video 📥", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                        
                        if (selectedVideoFile != null) {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(GridSpace, RoundedCornerShape(12.dp))
                                    .padding(10.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
