                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                    Icon(Icons.Default.Movie, contentDescription = "Video Badge", tint = CyberPink, modifier = Modifier.size(22.dp))
                                    Column {
                                        Text(selectedVideoFile!!.name, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold, maxLines = 1, overflow = TextOverflow.Ellipsis)
