                        ) {
                            processingLogs.forEach { log ->
                                Text(">> $log", color = TextMuted, fontSize = 8.sp, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                            }
                        }
                    }
                }
                
                // Live visual player mockup
                if (isCaptionProcessed && captionTracks.isNotEmpty()) {
                    val activeTrack = remember(currentPlaybackMs, captionTracks) {
                        captionTracks.find { currentPlaybackMs in it.startMs..it.endMs }
                    }
                    
                    Box(
