                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("3. SUBTITLED VIDEO WYSIWYG PREVIEW PORT", color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Button(
                                        onClick = {
                                            scope.launch(Dispatchers.IO) {
                                                try {
                                                    val videoBaseName = selectedVideoFile?.name ?: "auto_caption_demo.mp4"
                                                    val finalOutputName = "Captioned_${System.currentTimeMillis()}_$videoBaseName"
                                                    
                                                    val rootDir = java.io.File(context.filesDir, "FileManager")
