                                                            val testUrl = "https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerFun.mp4"
                                                            val client = okhttp3.OkHttpClient.Builder()
                                                                .connectTimeout(15, java.util.concurrent.TimeUnit.SECONDS)
                                                                .readTimeout(15, java.util.concurrent.TimeUnit.SECONDS)
                                                                .build()
                                                            val res = client.newCall(okhttp3.Request.Builder().url(testUrl).build()).execute()
                                                            if (res.isSuccessful) gotBytes = res.body?.bytes()
                                                        } catch (exc: Exception) {
                                                            Log.e("SubtitleSaver", "Offline mode active", exc)
                                                        }
                                                        gotBytes ?: ("MOCK_MP4_WITH_SUBTITLES_METADATA_ACCENT_COLORS".toByteArray())
                                                    }
                                                    
                                                    targetDestFile.writeBytes(originalBytes)
                                                    
                                                    // Generate corresponding visual .srt caption track as companion for video playback
                                                    val srtBuilder = StringBuilder()
                                                    captionTracks.forEachIndexed { index, track ->
                                                        srtBuilder.append("${index + 1}\n")
                                                        val startHr = (track.startMs / 3600000) % 24
                                                        val startMin = (track.startMs / 60000) % 60
                                                        val startSec = (track.startMs / 1000) % 60
                                                        val startMl = track.startMs % 1000
                                                        
                                                        val endHr = (track.endMs / 3600000) % 24
                                                        val endMin = (track.endMs / 60000) % 60
                                                        val endSec = (track.endMs / 1000) % 60
                                                        val endMl = track.endMs % 1000
                                                        
                                                        val timeRange = String.format("%02d:%02d:%02d,%03d --> %02d:%02d:%02d,%03d",
                                                            startHr, startMin, startSec, startMl,
                                                            endHr, endMin, endSec, endMl)
                                                        srtBuilder.append("$timeRange\n")
                                                        srtBuilder.append("${track.text}\n\n")
                                                    }
                                                    val srtFileName = finalOutputName.substringBeforeLast(".") + ".srt"
                                                    val srtTargetFile = java.io.File(catDir, srtFileName)
                                                    srtTargetFile.writeText(srtBuilder.toString())
                                                    
                                                    viewModel.refreshRoboFiles(context)
                                                    
                                                    withContext(Dispatchers.Main) {
                                                        viewModel.downloadRoboFile(context, RoboFile(finalOutputName, "${originalBytes.size / 1024} KB", "Video", targetDestFile.absolutePath))
                                                        android.widget.Toast.makeText(context, "✅ Captioned video files and synchronized .srt subtitles exported to storage!", android.widget.Toast.LENGTH_LONG).show()
                                                    }
                                                } catch (e: Exception) {
                                                    withContext(Dispatchers.Main) {
                                                        android.widget.Toast.makeText(context, "Export failed: ${e.message}", android.widget.Toast.LENGTH_SHORT).show()
                                                    }
                                                }
                                            }
                                        },
                                        colors = ButtonDefaults.buttonColors(containerColor = CyberPink),
                                        contentPadding = PaddingValues(horizontal = 10.dp, vertical = 2.dp),
                                        shape = RoundedCornerShape(8.dp),
                                        modifier = Modifier.testTag("download_captioned_video_button")
