                                        tint = CyberCyan.copy(alpha = 0.15f),
                                        modifier = Modifier.size(64.dp)
                                    )
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text(
                                        "PLAYBACK FEED: ${selectedVideoFile?.name ?: "DEMO_WAVE.MP4"}",
                                        color = TextMuted.copy(alpha = 0.5f),
                                        fontSize = 8.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                                
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .padding(14.dp),
                                    contentAlignment = when (selectedAlignment) {
                                        "Top Center" -> Alignment.TopCenter
                                        "Center" -> Alignment.Center
                                        "Bottom Center" -> Alignment.BottomCenter
                                        else -> Alignment.BottomCenter
                                    }
                                ) {
                                    if (activeTrack != null) {
                                        val styleColor = activeColor
                                        val styleShadow = androidx.compose.ui.graphics.Shadow(
                                            color = Color.Black,
                                            offset = androidx.compose.ui.geometry.Offset(2f, 2f),
                                            blurRadius = 4f
                                        )
                                        
                                        when (selectedStylePreset) {
                                            "Dynamic Neon Kinetic" -> {
                                                Box(
                                                    modifier = Modifier
                                                        .background(Color.Black.copy(alpha = 0.65f), RoundedCornerShape(6.dp))
                                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                                        .border(1.dp, CyberCyan, RoundedCornerShape(6.dp))
                                                ) {
                                                    Text(
                                                        text = activeTrack.text.uppercase(),
                                                        color = CyberCyan,
                                                        fontSize = fontSizeVal.sp,
                                                        fontWeight = FontWeight.ExtraBold,
                                                        textAlign = TextAlign.Center,
                                                        letterSpacing = 1.sp,
                                                        style = androidx.compose.ui.text.TextStyle(shadow = styleShadow)
                                                    )
                                                }
                                            }
                                            "Karaoke Bouncing" -> {
                                                val splitWords = activeTrack.text.split(" ")
                                                val activeWordIdx = ((currentPlaybackMs / 600) % splitWords.size).toInt().coerceIn(0, splitWords.size - 1)
                                                
                                                Row(
                                                    horizontalArrangement = Arrangement.spacedBy(4.dp),
                                                    modifier = Modifier
                                                        .background(Color.Black.copy(alpha = 0.5f), RoundedCornerShape(10.dp))
                                                        .padding(horizontal = 10.dp, vertical = 4.dp)
                                                ) {
                                                    splitWords.forEachIndexed { idx, word ->
                                                        Text(
                                                            text = word,
                                                            color = if (idx == activeWordIdx) CyberPink else styleColor,
                                                            fontSize = (fontSizeVal + if (idx == activeWordIdx) 3 else 0).sp,
                                                            fontWeight = FontWeight.Black,
                                                            style = androidx.compose.ui.text.TextStyle(shadow = styleShadow)
                                                        )
                                                    }
                                                }
                                            }
                                            "Clean Minimalist" -> {
                                                Box(
                                                    modifier = Modifier
                                                        .background(Color.White.copy(alpha = 0.85f), RoundedCornerShape(3.dp))
                                                        .padding(horizontal = 12.dp, vertical = 2.dp)
                                                ) {
                                                    Text(
                                                        text = activeTrack.text.lowercase(),
                                                        color = Color(0xFF0F172A),
                                                        fontSize = (fontSizeVal - 2).sp,
                                                        fontWeight = FontWeight.SemiBold,
                                                        textAlign = TextAlign.Center
                                                    )
                                                }
                                            }
                                            "Bold Cyberpunk" -> {
                                                Row(
                                                    modifier = Modifier
                                                        .background(Color(0xFFFFD700), RoundedCornerShape(0.dp))
                                                        .border(2.dp, Color.Black)
                                                        .padding(horizontal = 8.dp, vertical = 3.dp),
                                                    verticalAlignment = Alignment.CenterVertically
                                                ) {
                                                    Text(
                                                        text = "[AI] ${activeTrack.text.uppercase()}",
                                                        color = Color.Black,
                                                        fontSize = fontSizeVal.sp,
                                                        fontWeight = FontWeight.ExtraBold,
                                                        fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace
                                                    )
                                                }
                                            }
                                            "Retro VHS" -> {
                                                Column(
                                                    horizontalAlignment = Alignment.CenterHorizontally,
                                                    verticalArrangement = Arrangement.spacedBy(2.dp)
                                                ) {
                                                    Text(
                                                        text = "VCR PLAY  0:00:${currentPlaybackMs / 1000}",
                                                        color = Color(0xFF22C55E),
                                                        fontSize = 9.sp,
                                                        fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                                                        fontWeight = FontWeight.Bold
                                                    )
                                                    Text(
                                                        text = activeTrack.text,
                                                        color = styleColor,
                                                        fontSize = fontSizeVal.sp,
                                                        fontWeight = FontWeight.Bold,
                                                        style = androidx.compose.ui.text.TextStyle(shadow = styleShadow),
                                                        textAlign = TextAlign.Center
                                                    )
                                                }
                                            }
                                        }
                                    }
                                }
                                
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .padding(8.dp),
                                    contentAlignment = Alignment.TopEnd
                                ) {
                                    Text(
                                        text = "${formatMs(currentPlaybackMs)} / ${formatMs(totalPlaybackMs)}",
                                        color = CyberCyan,
                                        fontSize = 8.5.sp,
                                        fontWeight = FontWeight.Bold,
                                        fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                                        modifier = Modifier
                                            .background(Color.Black.copy(alpha = 0.5f), RoundedCornerShape(4.dp))
                                            .padding(horizontal = 4.dp, vertical = 2.dp)
                                    )
                                }
                            }
                            
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(10.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                IconButton(
                                    onClick = { isPlaying = !isPlaying },
                                    modifier = Modifier.size(34.dp)
                                ) {
                                    Icon(
                                        imageVector = if (isPlaying) Icons.Default.PauseCircle else Icons.Default.PlayCircle,
                                        contentDescription = "Play Control Toggle",
                                        tint = CyberCyan,
                                        modifier = Modifier.size(30.dp)
                                    )
                                }
                                
                                Slider(
                                    value = currentPlaybackMs.toFloat(),
                                    onValueChange = { currentPlaybackMs = it.toLong() },
                                    valueRange = 0f..totalPlaybackMs.toFloat(),
                                    modifier = Modifier.weight(1f),
                                    colors = SliderDefaults.colors(
                                        thumbColor = CyberPink,
                                        activeTrackColor = CyberPink,
                                        inactiveTrackColor = GridSpace
                                    )
                                )
                            }
                        }
                    }
                }
                
                Spacer(modifier = Modifier.height(10.dp))
            }
        }
    }
}

fun formatMs(ms: Long): String {
    val totalSecs = ms / 1000
    val minutes = totalSecs / 60
    val remainderSecs = totalSecs % 60
    return String.format("%02d:%02d", minutes, remainderSecs)
}

