                                .padding(16.dp)
                        ) {
                            Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                                Text("🎭 MULTI-SPEAKER SCRIPT OPERATOR", color = CyberPink, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Text(
                                    text = "Nayi digital drama scripting setup! Name prefix (e.g. Kabir: or Rabiya:) likhein. Audio pipeline unke styles par sequentially chalega.",
                                    color = TextMuted,
                                    fontSize = 8.5.sp
                                )

                                OutlinedTextField(
                                    value = scriptContent,
                                    onValueChange = { scriptContent = it },
                                    modifier = Modifier.fillMaxWidth(),
                                    maxLines = 8,
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White,
                                        focusedBorderColor = CyberPink
                                    )
                                )

                                Button(
                                    onClick = {
                                        if (isDialoguePlaying) {
                                            isDialoguePlaying = false
                                            activeDialogueHighlightLine = null
                                        } else {
                                            isDialoguePlaying = true
                                            coroutineScope.launch {
                                                val lines = scriptContent.split("\n").filter { it.isNotBlank() }
                                                for (index in lines.indices) {
                                                    if (!isDialoguePlaying) break
                                                    val rawLine = lines[index]
                                                    activeDialogueHighlightLine = index
                                                    
                                                    // Resolve Speaker Name and Dialogue line
                                                    val parts = rawLine.split(":", limit = 2)
                                                    val speakerName = parts.getOrNull(0)?.trim() ?: "Rabiya"
                                                    val speakerDialogue = parts.getOrNull(1)?.trim() ?: rawLine

                                                    // Pick suitable voice match
                                                    val resolvedVoice = allVoices.firstOrNull { 
                                                        it.first.lowercase().contains(speakerName.lowercase()) 
                                                    }?.first ?: "Rabiya (Natural Sufi Companion)"

                                                    kotlinx.coroutines.withContext(Dispatchers.Main) {
                                                        viewModel.generateRealHumanVoiceAndSpeak(speakerDialogue, resolvedVoice, languageSelected)
                                                    }

                                                    // Dynamic sleep spacing
                                                    kotlinx.coroutines.delay(4500)
                                                }
                                                activeDialogueHighlightLine = null
                                                isDialoguePlaying = false
                                            }
                                        }
                                    },
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = if (isDialoguePlaying) CyberPink else CyberCyan
                                    ),
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Text(
                                        text = if (isDialoguePlaying) "HALT SEQUENTIAL PLAY DRAMA" else "ASSEMBLE & PLAY SEQUENTIAL DRAMA 🎭",
