                                                        Icon(Icons.Default.VolumeUp, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(12.dp))
                                                        Spacer(modifier = Modifier.width(6.dp))
                                                    }
                                                    Text(l, color = if (active) CyberCyan else Color.White, fontSize = 9.5.sp)
                                                }
                                            }
                                        }
                                    }
