                                            Text(label, color = if (isSel) CyberCyan else TextMuted, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                }

                                val codeSnippet = when (activeApiCodeTab) {
                                    0 -> "curl -X POST \"https://api.pollinations.ai/p/vocalizer?speed=$speedVal&pitch=$pitchVal\" \\\n" +
                                            "  -H \"Content-Type: application/json\" \\\n" +
                                            "  -d '{\"text\": \"Hey companion!\", \"voice\": \"$selectedVoiceProfile\"}'"
                                    1 -> "val client = OkHttpClient()\n" +
                                            "val payload = \"\"\"{\n" +
                                            "  \"input\": \"Hey companion!\",\n" +
                                            "  \"voice\": \"$selectedVoiceProfile\"\n" +
                                            "}\"\"\".toRequestBody(\"json\".toMediaType())\n" +
                                            "val request = Request.Builder()\n" +
                                            "  .url(\"https://api.openai.com/v1/audio/speech\")\n" +
                                            "  .post(payload).build()"
                                    2 -> "import requests\n" +
                                            "res = requests.post(\n" +
                                            "  \"https://api.openai.com/v1/audio/speech\",\n" +
                                            "  headers={\"Authorization\": \"Bearer api_key\"},\n" +
                                            "  json={\"model\": \"tts-1\", \"input\": \"dialogue\", \"voice\": \"alloy\"}\n" +
                                            ")"
                                    else -> "const fs = require('fs');\n" +
                                            "fetch('https://api.openai.com/v1/audio/speech', {\n" +
                                            "  method: 'POST',\n" +
                                            "  headers: { 'Authorization': 'Bearer API_KEY_HERE' },\n" +
                                            "  body: JSON.stringify({ model: 'tts-1', input: 'sample', voice: 'alloy' })\n" +
                                            "}).then(res => res.buffer()).then(out => fs.writeFileSync('out.mp3', out));"
                                }

                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .background(GridSpace, RoundedCornerShape(8.dp))
                                        .padding(10.dp)
                                ) {
                                    Text(
                                        text = codeSnippet,
                                        color = SuccessGreen,
                                        fontSize = 8.5.sp,
                                        fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace
