                                    contentPadding = androidx.compose.foundation.layout.PaddingValues(horizontal = 8.dp, vertical = 2.dp),
                                    modifier = androidx.compose.ui.Modifier.height(24.dp)
                                ) {
                                    Text(if (showVocalizerLogs) "HIDE LOGS 👁️‍🗨️" else "SHOW LOGS 👁️", fontSize = 8.sp, color = if (showVocalizerLogs) Color.White else DarkBackground, fontWeight = FontWeight.Bold)
                                }
                            }
                            if (showVocalizerLogs) {
                                Spacer(modifier = Modifier.height(4.dp))
                                logs.forEach { log ->
                                    Text(text = log, color = TextLight, fontSize = 11.sp, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}


// =========================================================================
// 📁 FILE MANAGER COMPOSABLE SCREEN LAYOUT
// =========================================================================
@Composable
fun FileManagerScreen(viewModel: MainViewModel) {
    val context = LocalContext.current
    val roboFiles by viewModel.roboFiles.collectAsStateWithLifecycle()
    val copiedFile by viewModel.copiedFile.collectAsStateWithLifecycle()
    val isServerRunning by viewModel.isServerRunning.collectAsStateWithLifecycle()
    val serverUrls by viewModel.serverUrls.collectAsStateWithLifecycle()
    val serverSecurityPin by viewModel.serverSecurityPin.collectAsStateWithLifecycle()
    val scope = rememberCoroutineScope()
    
    var selectedFolder by remember { mutableStateOf<String?>(null) } // null = Main folders, or "Images", "Voice", "Video", "PDFs", "Documents", "InternalStorage/<folderName>"
    var searchQuery by remember { mutableStateOf("") }
    var fileToView by remember { mutableStateOf<com.example.RoboFile?>(null) }
    var showCreateFolderDialog by remember { mutableStateOf(false) }
    var newFolderName by remember { mutableStateOf("") }
    var areUrlsVisible by remember { mutableStateOf(false) }

    LaunchedEffect(Unit) {
        viewModel.refreshRoboFiles(context)
    }

    // Interactive file picker launcher for SIMULATED USB direct data transfers
    val filePickerLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri ->
        if (uri != null) {
            scope.launch(Dispatchers.IO) {
                try {
                    val resolver = context.contentResolver
                    var displayName = "uploaded_${System.currentTimeMillis()}"
                    val cursor = resolver.query(uri, null, null, null, null)
                    cursor?.use {
                        if (it.moveToFirst()) {
                            val nameIdx = it.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                            if (nameIdx != -1) {
                                displayName = it.getString(nameIdx)
                            }
                        }
                    }
                    
                    val inputStream = resolver.openInputStream(uri)
                    val bytes = inputStream?.readBytes()
                    inputStream?.close()
                    
                    if (bytes != null) {
                        val destCategory = if (selectedFolder != null && selectedFolder!!.startsWith("InternalStorage/")) {
                            selectedFolder!!
                        } else {
                            "InternalStorage/Downloads"
                        }
                        
                        viewModel.addFileToFileManager(context, displayName, destCategory, "", bytes)
                        withContext(Dispatchers.Main) {
                            android.widget.Toast.makeText(context, "✅ Transferred $displayName successfully into $destCategory folder!", android.widget.Toast.LENGTH_LONG).show()
                        }
                    }
                } catch (e: Exception) {
                    withContext(Dispatchers.Main) {
                        android.widget.Toast.makeText(context, "❌ USB Transfer failure: ${e.localizedMessage}", android.widget.Toast.LENGTH_LONG).show()
                    }
                }
            }
        }
    }

    // Calculations of Storage limits (8 GB total partition)
    val totalCapacityBytes = 8L * 1024L * 1024L * 1024L // 8.00 GB
    val usedBytes = remember(roboFiles) {
        viewModel.getUsedStorageBytes(context)
    }
    val usedBytesFormatted = remember(usedBytes) {
        if (usedBytes < 1024) "$usedBytes B"
        else if (usedBytes < 1024 * 1024) "${usedBytes / 1024} KB"
        else if (usedBytes < 1024 * 1024 * 1024) "${String.format("%.2f", usedBytes.toDouble() / (1024.0 * 1024.0))} MB"
        else "${String.format("%.2f", usedBytes.toDouble() / (1024.0 * 1024.0 * 1024.0))} GB"
    }
    val usedPct = (usedBytes.toFloat() / totalCapacityBytes.toFloat()).coerceIn(0f, 1f)

    // Dynamic list of directories/subfolders inside InternalStorage/
    val internalStorageSubfolders = remember(roboFiles) {
        val rootDir = java.io.File(context.filesDir, "FileManager")
        val internalDir = java.io.File(rootDir, "InternalStorage")
        val defaults = listOf("Music", "Photos", "Videos", "Documents", "Downloads")
        val subs = internalDir.listFiles()?.filter { it.isDirectory }?.map { it.name } ?: emptyList()
        (defaults + subs).distinct().sorted()
    }

    // Dialog for creating custom folders dynamically
    if (showCreateFolderDialog) {
        AlertDialog(
            onDismissRequest = { showCreateFolderDialog = false },
            title = { Text("CREATING NEW STORAGE DIRECTORY", color = CyberPink, fontWeight = FontWeight.Black, fontSize = 14.sp) },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text("De ke folder name banayein, Rabiya storage systems organize karengi. Custom folders under physical phone storage exist recursively.", color = TextLight, fontSize = 11.sp)
                    OutlinedTextField(
                        value = newFolderName,
                        onValueChange = { newFolderName = it },
                        placeholder = { Text("e.g. StudyNotes, PrivateBackup", color = TextMuted, fontSize = 12.sp) },
                        modifier = Modifier.fillMaxWidth(),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = CyberPink,
                            unfocusedBorderColor = GridSpace,
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White
                        ),
                        singleLine = true
                    )
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        if (newFolderName.isNotBlank()) {
                            viewModel.createInternalStorageSubfolder(context, newFolderName.trim())
                            android.widget.Toast.makeText(context, "✨ Custom subfolder \"${newFolderName.trim()}\" has been registered successfully!", android.widget.Toast.LENGTH_SHORT).show()
                            newFolderName = ""
                        }
                        showCreateFolderDialog = false
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = CyberPink)
                ) {
                    Text("CREATE FOLDER", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                }
            },
            dismissButton = {
                TextButton(onClick = { showCreateFolderDialog = false }) {
                    Text("CANCEL", color = TextLight, fontSize = 11.sp)
                }
            },
            containerColor = CardSpace,
            shape = RoundedCornerShape(16.dp)
        )
    }

    // Main layout
    if (selectedFolder == null) {
        // Categories folders grid
        val imgCount = roboFiles.count { it.type == "Images" }
        val voiceCount = roboFiles.count { it.type == "Voice" }
        val videoCount = roboFiles.count { it.type == "Video" }
        val pdfCount = roboFiles.count { it.type == "PDFs" }
        val docCount = roboFiles.count { it.type == "Documents" }

        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // Header card
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(
                            Brush.linearGradient(listOf(Color(0xFF161E33), Color(0xFF0F1424))),
                            RoundedCornerShape(16.dp)
                        )
                        .border(1.dp, CyberCyan.copy(alpha = 0.3f), RoundedCornerShape(16.dp))
                        .padding(16.dp)
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(16.dp)
                    ) {
                        Image(
                            painter = androidx.compose.ui.res.painterResource(id = R.drawable.img_rabiya_logo_new_1784261401445),
                            contentDescription = "Rabiya File Core",
                            modifier = Modifier
                                .size(56.dp)
                                .clip(RoundedCornerShape(12.dp))
                                .border(1.5.dp, CyberCyan, RoundedCornerShape(12.dp))
                        )
                        Column {
                            Text(
                                "📁 INTEGRATED FILE CORE v3.5",
                                color = CyberCyan,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Bold,
                                letterSpacing = 1.sp
                            )
                            Text(
                                "Aapki intelligent AI companion Rabiya dwara sanchalit secure file repository. Clear organization with USB Link & standard folders.",
                                color = TextMuted,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Medium
                            )
                        }
                    }
                }
            }

            // SECTION 1: SYSTEM FILE MANAGER CARD (Folders inside it!)
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(CardSpace, RoundedCornerShape(18.dp))
                        .border(1.dp, CyberCyan.copy(alpha = 0.15f), RoundedCornerShape(18.dp))
                        .padding(14.dp)
                ) {
                    Column(verticalArrangement = Arrangement.spacedBy(11.dp)) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(
                                imageVector = Icons.Default.Folder,
                                contentDescription = null,
                                tint = CyberCyan,
                                modifier = Modifier.size(18.dp)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text(
                                "📁 SYSTEM FILE MANAGER",
                                color = CyberCyan,
                                fontSize = 12.sp,
                                fontWeight = FontWeight.Bold,
                                letterSpacing = 0.5.sp
                            )
                        }
                        
                        Text(
                            "These folders automatically hold core resources, resume text templates, generated images and vocal logs compiled by Rabiya companion.",
                            color = TextMuted,
                            fontSize = 11.sp
                        )
                        
                        Divider(color = GridSpace, thickness = 1.dp, modifier = Modifier.padding(vertical = 2.dp))
                        
                        // Internal grid/rows of folders
                        val foldersList = listOf(
                            FolderItem("Images", "Photos & Background Designs", Icons.Default.Image, Color(0xFFEC407A), imgCount),
                            FolderItem("Voice", "Voice Syntheses & Vocal Records", Icons.Default.Mic, Color(0xFF26A69A), voiceCount),
                            FolderItem("Video", "Simulated presentations & guides", Icons.Default.PlayCircle, Color(0xFFFF7043), videoCount),
                            FolderItem("PDFs", "Resume specifications & templates", Icons.Default.Description, Color(0xFFAB47BC), pdfCount),
                            FolderItem("Documents", "Generated specifications & copies", Icons.Default.Article, Color(0xFF42A5F5), docCount)
                        )
                        
                        foldersList.forEach { folder ->
                            FolderRowItemSimple(folder) {
                                selectedFolder = folder.name
                            }
                        }
                    }
                }
            }

            // SECTION 2: PHYSICAL PHONE STORAGE (Located below / niche)
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(CardSpace, RoundedCornerShape(18.dp))
                        .border(1.dp, CyberPink.copy(alpha = 0.15f), RoundedCornerShape(18.dp))
                        .padding(14.dp)
                ) {
                    Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.Default.Storage,
                                    contentDescription = null,
                                    tint = CyberPink,
                                    modifier = Modifier.size(18.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    "💾 PHONE INTERNAL STORAGE",
                                    color = CyberPink,
                                    fontSize = 12.sp,
                                    fontWeight = FontWeight.Bold,
                                    letterSpacing = 0.5.sp
                                )
                            }
                            
                            Box(
                                modifier = Modifier
                                    .background(CyberPink.copy(alpha = 0.15f), RoundedCornerShape(6.dp))
                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                            ) {
                                Text("8.00 GB", color = CyberPink, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                        
                        Text(
                            "Simulate your phone drives. Transfer custom MP3 music files, videos, and images dynamically or copy/paste existing directory contents.",
                            color = TextMuted,
                            fontSize = 11.sp
                        )
                        
                        // Storage Space Linear progress visual
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Text(
                                    text = "Space Used: $usedBytesFormatted / 8.00 GB",
                                    color = TextLight,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold
                                )
                                Text(
                                    text = "${String.format("%.1f", usedPct * 100)}%",
                                    color = CyberPink,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                            
                            // Bar
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(8.dp)
                                    .clip(CircleShape)
                                    .background(GridSpace)
                            ) {
                                Box(
                                    modifier = Modifier
                                        .fillMaxHeight()
                                        .fillMaxWidth(usedPct)
                                        .clip(CircleShape)
                                        .background(
                                            Brush.horizontalGradient(listOf(CyberPink, CyberCyan))
                                        )
                                )
                            }
                        }
                        
                        Divider(color = GridSpace, thickness = 1.dp, modifier = Modifier.padding(vertical = 4.dp))
                        
                        // Storage Action row
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Button(
                                onClick = { showCreateFolderDialog = true },
                                modifier = Modifier.weight(1.0f),
                                colors = ButtonDefaults.buttonColors(containerColor = CyberPink),
                                shape = RoundedCornerShape(10.dp),
                                contentPadding = PaddingValues(vertical = 8.dp)
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                                ) {
                                    Icon(Icons.Default.CreateNewFolder, contentDescription = null, tint = Color.Black, modifier = Modifier.size(14.dp))
                                    Text("CREATE FOLDER", color = Color.Black, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                            
                            val isClipboardActive = copiedFile != null
                            Button(
                                onClick = { viewModel.pasteCopiedFile(context, "InternalStorage/Downloads") },
                                enabled = isClipboardActive,
                                modifier = Modifier.weight(1.0f),
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = CyberCyan,
                                    disabledContainerColor = GridSpace
                                ),
                                shape = RoundedCornerShape(10.dp),
                                contentPadding = PaddingValues(vertical = 8.dp)
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.ContentPaste,
                                        contentDescription = null,
                                        tint = if (isClipboardActive) Color.Black else TextMuted,
                                        modifier = Modifier.size(14.dp)
                                    )
                                    Text("PASTE FILE", color = if (isClipboardActive) Color.Black else TextMuted, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                        
                        // Active clipboard banner
                        if (copiedFile != null) {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(GridSpace, RoundedCornerShape(8.dp))
                                    .padding(8.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(6.dp),
                                    modifier = Modifier.weight(1f)
                                ) {
                                    Icon(Icons.Default.ContentCopy, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(12.dp))
                                    Text(
                                        text = "Copied: \"${copiedFile!!.name}\"",
                                        color = TextLight,
                                        fontSize = 9.sp,
                                        maxLines = 1,
                                        overflow = TextOverflow.Ellipsis
                                    )
                                }
                                Text(
                                    text = "CLEAR CLIPBOARD",
                                    color = CyberPink,
                                    fontSize = 8.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .clickable { viewModel.clearClipboard() }
                                        .padding(horizontal = 4.dp)
                                )
                            }
                        }
                        
                        // Phone Storage Files list
                        Text(
                            text = "STORAGE ROOT COMPARTMENTS (${internalStorageSubfolders.size})",
                            color = TextMuted,
                            fontSize = 9.sp,
                            fontWeight = FontWeight.Bold,
                            letterSpacing = 0.5.sp,
                            modifier = Modifier.padding(top = 4.dp)
                        )
                        
                        Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                            internalStorageSubfolders.forEach { subName ->
                                val subFolderType = "InternalStorage/$subName"
                                val fileCount = roboFiles.count { it.type == subFolderType }
                                val folderItemObj = FolderItem(
                                    name = subName,
                                    description = "Files mapped in physical phone storage",
                                    icon = when (subName.lowercase()) {
                                        "music" -> Icons.Default.MusicNote
                                        "photos" -> Icons.Default.Image
                                        "videos" -> Icons.Default.PlayCircle
                                        "documents" -> Icons.Default.Description
                                        "downloads" -> Icons.Default.Download
                                        else -> Icons.Default.FolderOpen
                                    },
                                    iconColor = CyberPink,
                                    count = fileCount
                                )
                                FolderRowItemSimple(folderItemObj) {
                                    selectedFolder = subFolderType
                                }
                            }
                        }
                    }
                }
            }
        }
    } else {
        // Detailed category view
        val folderName = selectedFolder!!
        val filteredList = roboFiles.filter { 
            it.type == folderName && 
            (searchQuery.isBlank() || it.name.lowercase().contains(searchQuery.lowercase())) 
        }

        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            item {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        modifier = Modifier
                            .clickable { selectedFolder = null }
                            .padding(vertical = 4.dp, horizontal = 8.dp)
                    ) {
                        Icon(Icons.Default.ArrowBack, contentDescription = "Back", tint = CyberCyan)
                        Text("Folders", color = CyberCyan, fontSize = 13.sp, fontWeight = FontWeight.Bold)
                    }

                    Box(
                        modifier = Modifier
                            .background(CyberCyan.copy(alpha = 0.12f), CircleShape)
                            .padding(horizontal = 12.dp, vertical = 4.dp)
                    ) {
                        Text(
                            text = "$folderName directory (${filteredList.size})".uppercase(),
                            color = CyberCyan,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Black,
                            letterSpacing = 1.sp
                        )
                    }
                }
            }

            // Clipboard Paste banners inside detail lists
            if (copiedFile != null) {
                item {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(CyberCyan.copy(alpha = 0.12f), RoundedCornerShape(10.dp))
                            .border(1.dp, CyberCyan.copy(alpha = 0.4f), RoundedCornerShape(10.dp))
                            .padding(10.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        Column(modifier = Modifier.weight(1f)) {
                            Text("Clipboard: \"${copiedFile!!.name}\"", color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold, maxLines = 1, overflow = TextOverflow.Ellipsis)
                            Text("Press Paste to copy this file inside $folderName", color = TextMuted, fontSize = 8.sp)
                        }
                        
                        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            Text(
                                "Cancel",
                                color = CyberPink,
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier
                                    .clickable { viewModel.clearClipboard() }
                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                            )
                            Text(
                                "Paste",
                                color = SuccessGreen,
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier
                                    .clickable { viewModel.pasteCopiedFile(context, folderName) }
                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                            )
                        }
                    }
                }
            }

            // Search Bar
            item {
                OutlinedTextField(
                    value = searchQuery,
                    onValueChange = { searchQuery = it },
                    placeholder = { Text("Search files inside $folderName...", color = TextMuted, fontSize = 12.sp) },
                    leadingIcon = { Icon(Icons.Default.Search, contentDescription = "Search", tint = TextMuted) },
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(CardSpace, RoundedCornerShape(12.dp)),
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = CyberCyan,
                        unfocusedBorderColor = GridSpace,
                        focusedTextColor = Color.White,
                        unfocusedTextColor = Color.White
                    ),
                    shape = RoundedCornerShape(12.dp),
                    singleLine = true
                )
            }

            if (filteredList.isEmpty()) {
                item {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 48.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            Icon(Icons.Default.FolderOpen, contentDescription = "Empty", tint = TextMuted, modifier = Modifier.size(56.dp))
                            Spacer(modifier = Modifier.height(12.dp))
                            Text("No files registered yet", color = TextLight, fontWeight = FontWeight.Bold, fontSize = 14.sp)
                            Text(
                                "Generate voice notes or upload document attachments in the Chat page to populate this section.",
                                color = TextMuted,
                                fontSize = 11.sp,
                                textAlign = TextAlign.Center,
                                modifier = Modifier.padding(horizontal = 24.dp)
                            )
                        }
                    }
                }
            } else {
                items(filteredList, key = { it.absolutePath }) { roboFile ->
                    FileRowItem(
                        file = roboFile, 
                        onOpen = { fileToView = roboFile },
                        onDownload = { viewModel.downloadRoboFile(context, roboFile) },
                        onDelete = { viewModel.deleteRoboFile(context, roboFile) },
                        onShare = { viewModel.shareRoboFile(context, roboFile) },
                        onCopy = {
                            viewModel.copyFileToClipboard(roboFile)
                            val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                            val textToCopy = if (roboFile.contentPreview.isNotBlank()) roboFile.contentPreview else roboFile.absolutePath
                            val clip = android.content.ClipData.newPlainText("Rabiya File", textToCopy)
                            clipboard.setPrimaryClip(clip)
                            android.widget.Toast.makeText(context, "File copied to Rabiya's clipboard drive!", android.widget.Toast.LENGTH_SHORT).show()
                        }
                    )
                }
            }
        }
    }

    // File Preview Dialog Modal
    if (fileToView != null) {
        val file = fileToView!!
        Dialog(onDismissRequest = { fileToView = null }) {
            Surface(
                modifier = Modifier
                    .fillMaxWidth()
                    .wrapContentHeight()
                    .padding(16.dp),
                shape = RoundedCornerShape(20.dp),
                color = CardSpace,
                tonalElevation = 8.dp
            ) {
                Column(
                    modifier = Modifier.padding(20.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = file.name,
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 15.sp,
                        textAlign = TextAlign.Center,
                        modifier = Modifier.fillMaxWidth()
                    )
                    Text(
                        text = "Category: ${file.type} • ${file.size}",
                        color = CyberCyan,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Medium,
                        modifier = Modifier.padding(top = 4.dp, bottom = 16.dp)
                    )

                    Divider(color = GridSpace, modifier = Modifier.padding(bottom = 16.dp))

                    // Media previews
                    val ext = file.name.substringAfterLast(".", "").lowercase()
                    val isImage = file.type == "Images" || ext == "png" || ext == "jpg" || ext == "jpeg" || ext == "gif"
                    val isAudio = file.type == "Voice" || ext == "mp3" || ext == "wav" || ext == "ogg" || ext == "m4a"
                    val isVideo = file.type == "Video" || ext == "mp4" || ext == "avi" || ext == "mpeg"

                    when {
                        isImage -> {
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(240.dp)
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(GridSpace),
                                contentAlignment = Alignment.Center
                            ) {
                                AsyncImage(
                                    model = if (file.absolutePath.startsWith("http")) file.absolutePath else java.io.File(file.absolutePath),
                                    contentDescription = "Preview Image",
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = ContentScale.Fit
                                )
                            }
                        }
                        isVideo -> {
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(240.dp)
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color.Black),
                                contentAlignment = Alignment.Center
                            ) {
                                AndroidView(
                                    factory = { ctx ->
                                        android.widget.VideoView(ctx).apply {
                                            setVideoPath(file.absolutePath)
                                            val mc = android.widget.MediaController(ctx)
                                            mc.setAnchorView(this)
                                            setMediaController(mc)
                                            setOnPreparedListener { mp ->
                                                mp.isLooping = true
                                            }
                                            start()
                                        }
                                    },
                                    modifier = Modifier.fillMaxSize()
                                )
                            }
                        }
                        isAudio -> {
                            var isPlaying by remember { mutableStateOf(false) }
                            var player: android.media.MediaPlayer? by remember { mutableStateOf(null) }

                            DisposableEffect(file) {
                                val p = android.media.MediaPlayer()
                                try {
                                    p.setDataSource(file.absolutePath)
                                    p.setOnPreparedListener {
                                        player = p
                                    }
                                    p.prepareAsync()
                                } catch (e: Exception) {
                                    android.util.Log.e("FileManager", "Error preparing media player", e)
                                }
                                onDispose {
                                    p.release()
                                }
                            }

                            Column(
                                horizontalAlignment = Alignment.CenterHorizontally,
                                modifier = Modifier.padding(vertical = 12.dp)
                            ) {
                                // Pulsing music icon or graphic
                                Box(
                                    modifier = Modifier
                                        .size(72.dp)
                                        .background(GridSpace, CircleShape)
                                        .border(1.dp, CyberCyan, CircleShape),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = if (isPlaying) Icons.Default.VolumeUp else Icons.Default.MusicNote,
                                        contentDescription = "Audio note",
                                        tint = CyberCyan,
                                        modifier = Modifier.size(32.dp)
                                    )
                                }
                                Spacer(modifier = Modifier.height(16.dp))
                                Button(
                                    onClick = {
                                        player?.let { p ->
                                            if (isPlaying) {
                                                p.pause()
                                                isPlaying = false
                                            } else {
                                                p.start()
                                                isPlaying = true
                                                p.setOnCompletionListener {
                                                    isPlaying = false
                                                }
                                            }
                                        }
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = CyberCyan)
                                ) {
                                    Text(
                                        text = if (isPlaying) "PAUSE AUDIO" else "PLAY SOUND",
                                        color = Color.Black,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }
                        else -> {
                            // View document txt/specs
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .heightIn(max = 240.dp)
                                    .background(GridSpace, RoundedCornerShape(12.dp))
                                    .padding(12.dp)
                                    .verticalScroll(rememberScrollState())
                            ) {
                                Text(
                                    text = if (file.contentPreview.isNotBlank()) file.contentPreview else "No readable text content available.",
                                    color = TextLight,
                                    fontSize = 11.sp,
                                    fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace
                                )
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(20.dp))
                    Button(
                        onClick = { fileToView = null },
                        colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.1f)),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Text("CLOSE PREVIEW", color = Color.White, fontWeight = FontWeight.Bold)
                    }
                }
            }
        }
    }
}

// Subordinate Layout helper data classes
data class FolderItem(
    val name: String,
    val description: String,
    val icon: ImageVector,
    val iconColor: Color,
    val count: Int
)

@Composable
fun FolderRowItemSimple(folder: FolderItem, onClick: () -> Unit) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(10.dp))
            .background(GridSpace)
            .clickable(onClick = onClick)
            .padding(12.dp),
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.SpaceBetween
    ) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(10.dp),
            modifier = Modifier.weight(1f)
        ) {
            Box(
                modifier = Modifier
                    .size(36.dp)
                    .background(folder.iconColor.copy(alpha = 0.15f), CircleShape),
                contentAlignment = Alignment.Center
            ) {
                Icon(folder.icon, contentDescription = null, tint = folder.iconColor, modifier = Modifier.size(18.dp))
            }
            Column {
                Text(folder.name, color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                Text(folder.description, color = TextMuted, fontSize = 9.sp, maxLines = 1, overflow = androidx.compose.ui.text.style.TextOverflow.Ellipsis)
            }
        }
        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
            Box(
                modifier = Modifier
                    .background(Color.White.copy(alpha = 0.1f), RoundedCornerShape(8.dp))
                    .padding(horizontal = 6.dp, vertical = 2.dp)
            ) {
                Text("${folder.count} files", color = Color.White, fontSize = 9.sp)
            }
            Icon(Icons.Default.ChevronRight, contentDescription = null, tint = TextMuted, modifier = Modifier.size(16.dp))
        }
    }
}

@Composable
fun StorageFileRowItem(
    file: com.example.RoboFile,
    onOpen: () -> Unit,
    onCopy: () -> Unit,
    onDownload: () -> Unit,
    onDelete: () -> Unit,
    onShare: () -> Unit
) {
    val ext = file.name.substringAfterLast(".", "").lowercase()
    val isMusic = ext == "mp3" || ext == "wav" || ext == "ogg" || ext == "m4a"
    val isImage = ext == "png" || ext == "jpg" || ext == "jpeg" || ext == "gif"
    val isVideo = ext == "mp4" || ext == "avi" || ext == "mpeg"
    val isPdf = ext == "pdf"
    
    val icon = when {
        isMusic -> Icons.Default.MusicNote
        isImage -> Icons.Default.Image
        isVideo -> Icons.Default.PlayCircle
        isPdf -> Icons.Default.Description
        else -> Icons.Default.Article
    }
    
    val iconColor = when {
        isMusic -> SuccessGreen
        isImage -> Color(0xFFEC407A)
        isVideo -> Color(0xFFFF7043)
        isPdf -> Color(0xFFAB47BC)
        else -> Color(0xFF42A5F5)
    }

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(10.dp))
            .background(GridSpace)
            .clickable(onClick = onOpen)
            .padding(8.dp),
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.SpaceBetween
    ) {
        Row(
            modifier = Modifier.weight(1f),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Box(
