                    .size(32.dp)
                    .background(iconColor.copy(alpha = 0.15f), CircleShape),
                contentAlignment = Alignment.Center
            ) {
                Icon(icon, contentDescription = null, tint = iconColor, modifier = Modifier.size(16.dp))
            }
            
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    text = file.name,
                    color = Color.White,
                    fontSize = 11.sp,
                    fontWeight = FontWeight.Bold,
                    maxLines = 1,
                    overflow = androidx.compose.ui.text.style.TextOverflow.Ellipsis
                )
                Text(
                    text = "Size: ${file.size} • PHONE STORAGE",
                    color = TextMuted,
                    fontSize = 8.sp
                )
            }
        }
        
        Row(horizontalArrangement = Arrangement.spacedBy(2.dp)) {
            IconButton(onClick = onCopy, modifier = Modifier.size(24.dp)) {
                Icon(Icons.Default.ContentCopy, contentDescription = "Copy", tint = CyberCyan, modifier = Modifier.size(12.dp))
            }
            IconButton(onClick = onDownload, modifier = Modifier.size(24.dp)) {
                Icon(Icons.Default.Download, contentDescription = "Download", tint = SuccessGreen, modifier = Modifier.size(12.dp))
            }
            IconButton(onClick = onShare, modifier = Modifier.size(24.dp)) {
                Icon(Icons.Default.Share, contentDescription = "Share", tint = CyberCyan, modifier = Modifier.size(12.dp))
            }
            IconButton(onClick = onDelete, modifier = Modifier.size(24.dp)) {
                Icon(Icons.Default.Delete, contentDescription = "Delete", tint = CyberPink, modifier = Modifier.size(12.dp))
            }
        }
    }
}

@Composable
fun FolderCard(item: FolderItem, onClick: () -> Unit) {
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(16.dp))
            .background(CardSpace)
            .border(1.dp, Color.White.copy(alpha = 0.05f), RoundedCornerShape(16.dp))
            .clickable(onClick = onClick)
            .padding(16.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(14.dp),
                modifier = Modifier.weight(1f)
            ) {
                Box(
                    modifier = Modifier
                        .size(44.dp)
                        .background(item.iconColor.copy(alpha = 0.12f), CircleShape)
                        .border(1.dp, item.iconColor.copy(alpha = 0.4f), CircleShape),
                    contentAlignment = Alignment.Center
                ) {
                    Icon(item.icon, contentDescription = item.name, tint = item.iconColor, modifier = Modifier.size(20.dp))
                }
                Column {
                    Text(item.name.uppercase(), color = Color.White, fontWeight = FontWeight.Bold, fontSize = 13.sp)
                    Text(item.description, color = TextMuted, fontSize = 11.sp, lineHeight = 14.sp)
                }
            }
            Box(
                modifier = Modifier
                    .background(item.iconColor.copy(alpha = 0.1f), RoundedCornerShape(8.dp))
                    .padding(horizontal = 10.dp, vertical = 4.dp),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    text = "${item.count}",
                    color = item.iconColor,
                    fontWeight = FontWeight.Black,
                    fontSize = 11.sp
                )
            }
        }
    }
}

@Composable
fun FileRowItem(
    file: com.example.RoboFile,
    onOpen: () -> Unit,
    onDownload: () -> Unit,
    onDelete: () -> Unit,
    onCopy: () -> Unit,
    onShare: () -> Unit
) {
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(12.dp))
            .background(CardSpace)
            .padding(12.dp)
    ) {
        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    val icon = when (file.type) {
                        "Images" -> Icons.Default.Image
                        "Voice" -> Icons.Default.Mic
                        "Video" -> Icons.Default.PlayCircle
                        "PDFs" -> Icons.Default.Description
                        else -> Icons.Default.Article
                    }
                    val iconColor = when {
                        file.type == "Images" -> Color(0xFFEC407A)
                        file.type == "Voice" -> Color(0xFF26A69A)
                        file.type == "Video" -> Color(0xFFFF7043)
                        file.type == "PDFs" -> Color(0xFFAB47BC)
                        else -> Color(0xFF42A5F5)
                    }

                    // Simple thumbnail preview for images!
                    if (file.type == "Images") {
                        Box(
                            modifier = Modifier
                                .size(36.dp)
                                .clip(RoundedCornerShape(6.dp))
                                .background(GridSpace),
                            contentAlignment = Alignment.Center
                        ) {
                            val fileObj = java.io.File(file.absolutePath)
                            if (fileObj.exists()) {
                                val bitmap = android.graphics.BitmapFactory.decodeFile(fileObj.absolutePath)
                                if (bitmap != null) {
                                    Image(
                                        bitmap = bitmap.asImageBitmap(),
                                        contentDescription = "Thumb",
                                        modifier = Modifier.fillMaxSize(),
                                        contentScale = ContentScale.Crop
                                    )
                                } else {
                                    Icon(icon, contentDescription = null, tint = iconColor, modifier = Modifier.size(16.dp))
                                }
                            } else {
                                Icon(icon, contentDescription = null, tint = iconColor, modifier = Modifier.size(16.dp))
                            }
                        }
                    } else {
                        Box(
                            modifier = Modifier
                                .size(36.dp)
                                .background(iconColor.copy(alpha = 0.12f), RoundedCornerShape(6.dp)),
                            contentAlignment = Alignment.Center
                        ) {
                            Icon(icon, contentDescription = null, tint = iconColor, modifier = Modifier.size(18.dp))
                        }
                    }

                    Column(modifier = Modifier.weight(1f)) {
                        Text(
                            text = file.name,
                            color = Color.White,
                            fontWeight = FontWeight.Bold,
                            fontSize = 12.sp,
                            maxLines = 1
                        )
                        Text(
                            text = "Size: ${file.size} • Modified: Just Now",
                            color = TextMuted,
                            fontSize = 10.sp
                        )
                    }
                }
            }

            // Quick actions line
            Divider(color = GridSpace, thickness = 0.8.dp)
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                // View button
                Row(
                    modifier = Modifier
                        .clickable(onClick = onOpen)
                        .padding(4.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Icon(Icons.Default.Visibility, contentDescription = "Open", tint = CyberCyan, modifier = Modifier.size(14.dp))
                    Text("OPEN", color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                }

                // Copy button
                Row(
                    modifier = Modifier
                        .clickable(onClick = onCopy)
                        .padding(4.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Icon(Icons.Default.ContentCopy, contentDescription = "Copy", tint = Color.LightGray, modifier = Modifier.size(14.dp))
                    Text("COPY", color = Color.LightGray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                }

                // Download button
                Row(
                    modifier = Modifier
                        .clickable(onClick = onDownload)
                        .padding(4.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Icon(Icons.Default.Download, contentDescription = "Save out", tint = Color.LightGray, modifier = Modifier.size(14.dp))
                    Text("SAVE OUT", color = Color.LightGray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                }

                // Share button
                Row(
                    modifier = Modifier
                        .clickable(onClick = onShare)
                        .padding(4.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Icon(Icons.Default.Share, contentDescription = "Share", tint = CyberCyan, modifier = Modifier.size(14.dp))
                    Text("SHARE", color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                }

                // Delete button
                Row(
                    modifier = Modifier
                        .clickable(onClick = onDelete)
                        .padding(4.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Icon(Icons.Default.Delete, contentDescription = "Delete", tint = CyberPink, modifier = Modifier.size(14.dp))
                    Text("DELETE", color = CyberPink, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                }
            }
        }
    }
}

