        "calculator" -> {
            var isFullScreen by remember { mutableStateOf(true) }
            androidx.compose.ui.window.Dialog(
                onDismissRequest = { activeSpecializedDialog = null },
                properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = !isFullScreen)
            ) {
                var calcInput by remember { mutableStateOf("") }
                var calcResult by remember { mutableStateOf("") }
                var isScientificMode by remember { mutableStateOf(false) }
                var calcHistory by remember { mutableStateOf(listOf<String>()) }

                // Safe mathematical expression evaluator
                val evaluateExpr: (String) -> String = { exprStr ->
                    try {
                        val cleanExpr = exprStr.replace("π", "3.14159265").replace("e", "2.71828182")
                        if (cleanExpr.isBlank()) ""
                        else {
                            object {
                                var pos = -1
                                var ch = 0

                                fun nextChar() {
                                    ch = if (++pos < cleanExpr.length) cleanExpr[pos].code else -1
                                }

                                fun eat(charToEat: Int): Boolean {
                                    while (ch == ' '.code) nextChar()
                                    if (ch == charToEat) {
                                        nextChar()
                                        return true
                                    }
                                    return false
                                }

                                fun parse(): Double {
                                    nextChar()
                                    val x = parseExpression()
                                    if (pos < cleanExpr.length) throw RuntimeException("Unexpected: " + ch.toChar())
                                    return x
                                }

                                fun parseExpression(): Double {
                                    var x = parseTerm()
                                    while (true) {
                                        if (eat('+'.code)) x += parseTerm()
                                        else if (eat('-'.code)) x -= parseTerm()
                                        else break
                                    }
                                    return x
                                }

                                fun parseTerm(): Double {
                                    var x = parseFactor()
                                    while (true) {
                                        if (eat('*'.code)) x *= parseFactor()
                                        else if (eat('/'.code)) {
                                            val denom = parseFactor()
                                            if (denom == 0.0) throw ArithmeticException("Division by zero")
                                            x /= denom
                                        }
                                        else break
                                    }
                                    return x
                                }

                                fun parseFactor(): Double {
                                    if (eat('+'.code)) return parseFactor()
                                    if (eat('-'.code)) return -parseFactor()

                                    var x: Double
                                    val startPos = pos
                                    if (eat('('.code)) {
                                        x = parseExpression()
                                        eat(')'.code)
                                    } else if ((ch >= '0'.code && ch <= '9'.code) || ch == '.'.code) {
                                        while ((ch >= '0'.code && ch <= '9'.code) || ch == '.'.code) nextChar()
                                        x = cleanExpr.substring(startPos, pos).toDouble()
                                    } else if (ch >= 'a'.code && ch <= 'z'.code) {
                                        while (ch >= 'a'.code && ch <= 'z'.code) nextChar()
                                        val func = cleanExpr.substring(startPos, pos)
                                        x = parseFactor()
                                        x = when (func) {
                                            "sqrt" -> kotlin.math.sqrt(x)
                                            "sin" -> kotlin.math.sin(Math.toRadians(x))
                                            "cos" -> kotlin.math.cos(Math.toRadians(x))
                                            "tan" -> kotlin.math.tan(Math.toRadians(x))
                                            "ln" -> kotlin.math.ln(x)
                                            else -> throw RuntimeException("Unsupported function: $func")
                                        }
                                    } else {
                                        throw RuntimeException("Unexpected standard token")
                                    }

                                    if (eat('^'.code)) x = java.lang.Math.pow(x, parseFactor())
                                    return x
                                }
                            }.parse().toString()
                        }
                    } catch (e: Exception) {
                        "Ref error"
                    }
                }

                Surface(
                    shape = if (isFullScreen) RoundedCornerShape(0.dp) else RoundedCornerShape(24.dp),
                    color = Color(0xFF0B0F19),
                    modifier = if (isFullScreen) {
                        Modifier.fillMaxSize()
                    } else {
                        Modifier
                            .fillMaxWidth()
                            .padding(12.dp)
                            .border(1.5.dp, CyberCyan, RoundedCornerShape(24.dp))
                    }
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                Icon(Icons.Default.Keyboard, contentDescription = null, tint = CyberCyan)
                                Text("NEURAL PRO ADVANCED CALCULATOR", fontWeight = FontWeight.ExtraBold, color = Color.White, fontSize = 12.sp)
                            }
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                IconButton(onClick = { isFullScreen = !isFullScreen }) {
                                    Icon(
                                        imageVector = if (isFullScreen) Icons.Default.FullscreenExit else Icons.Default.Fullscreen,
                                        contentDescription = "Toggle Fullscreen",
                                        tint = CyberCyan
                                    )
                                }
                                IconButton(onClick = { activeSpecializedDialog = null }) {
                                    Icon(Icons.Default.Close, contentDescription = "Close", tint = TextMuted)
                                }
                            }
                        }

                        // Display screen
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF03070E), RoundedCornerShape(12.dp))
                                .padding(12.dp),
                            contentAlignment = Alignment.CenterEnd
                        ) {
                            Column(horizontalAlignment = Alignment.End) {
                                Text(calcInput.ifEmpty { "0" }, color = Color.Gray, fontSize = 13.sp)
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(calcResult.ifEmpty { "0" }, color = CyberCyan, fontSize = 22.sp, fontWeight = FontWeight.Black)
                            }
                        }

                        // Scientific and Constants Controls
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("Scientific Modes & Constants", color = TextLight, fontSize = 11.sp, fontWeight = FontWeight.SemiBold)
                            Box(
                                modifier = Modifier
                                    .background(if (isScientificMode) CyberCyan.copy(alpha = 0.2f) else CardSpace, RoundedCornerShape(8.dp))
                                    .border(1.dp, if (isScientificMode) CyberCyan else GridSpace, RoundedCornerShape(8.dp))
                                    .clickable { isScientificMode = !isScientificMode }
                                    .padding(horizontal = 10.dp, vertical = 6.dp)
                            ) {
                                Text(
                                    text = if (isScientificMode) "SCIENTIFIC EXP ON 🧪" else "STANDARD MODE",
                                    color = if (isScientificMode) CyberCyan else Color.Gray,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }

                        if (isScientificMode) {
                            // Scientific constants & operators
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                listOf("sin(", "cos(", "tan(", "sqrt(", "ln(", "π", "e").forEach { op ->
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .height(34.dp)
                                            .background(Color(0xFF1E293B), RoundedCornerShape(6.dp))
                                            .clickable {
                                                if (op in listOf("π", "e")) {
                                                    calcInput += op
                                                } else {
                                                    calcInput += op
                                                }
                                            },
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(op, color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                listOf("(", ")", "^", "φ (1.618)").forEach { op ->
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .height(34.dp)
                                            .background(Color(0xFF131A2D), RoundedCornerShape(6.dp))
                                            .clickable {
                                                calcInput += if (op.startsWith("φ")) "1.61803" else op
                                            },
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(op.replace(" (1.618)", ""), color = CyberPink, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                        }

                        // Pad grid
                        val keys = listOf(
                            listOf("7", "8", "9", "/"),
                            listOf("4", "5", "6", "*"),
                            listOf("1", "2", "3", "-"),
                            listOf("C", "0", "=", "+")
                        )

                        Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                            keys.forEach { row ->
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                                ) {
                                    row.forEach { char ->
                                        Box(
                                            modifier = Modifier
                                                .weight(1f)
                                                .height(40.dp)
                                                .background(
                                                    if (char == "C") Color(0xFF991B1B)
                                                    else if (char == "=") CyberCyan
                                                    else if (char in listOf("+", "-", "*", "/")) Color(0xFF1E293B)
                                                    else Color(0xFF0F172A),
                                                    RoundedCornerShape(8.dp)
                                                )
                                                .clickable {
                                                    when (char) {
                                                        "C" -> {
                                                            calcInput = ""
                                                            calcResult = ""
                                                        }
                                                        "=" -> {
                                                            val calculated = evaluateExpr(calcInput)
                                                            calcResult = calculated
                                                            if (calculated != "Ref error" && calculated.isNotEmpty()) {
                                                                calcHistory = listOf("$calcInput = $calculated") + calcHistory.take(4)
                                                            }
                                                        }
                                                        else -> {
                                                            calcInput += char
                                                        }
                                                    }
                                                },
                                            contentAlignment = Alignment.Center
                                        ) {
                                            Text(
                                                text = char,
                                                color = if (char == "=") Color.Black else Color.White,
                                                fontWeight = FontWeight.Bold,
                                                fontSize = 14.sp
                                            )
                                        }
                                    }
                                }
                            }
                        }

                        // Calculator history log panel
                        if (calcHistory.isNotEmpty()) {
                            Divider(color = GridSpace, thickness = 1.dp, modifier = Modifier.padding(vertical = 4.dp))
                            Text("RECENT CALCULATIONS (CLICK TO RELOAD):", color = CyberPink, fontSize = 8.sp, fontWeight = FontWeight.Bold, modifier = Modifier.align(Alignment.Start))
                            Column(verticalArrangement = Arrangement.spacedBy(4.dp), modifier = Modifier.fillMaxWidth()) {
                                calcHistory.forEach { log ->
                                    Box(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .background(Color(0xFF03070E), RoundedCornerShape(8.dp))
                                            .clickable {
                                                val parts = log.split(" = ")
                                                if (parts.isNotEmpty()) {
                                                    calcInput = parts[0]
                                                    calcResult = parts.getOrNull(1) ?: ""
                                                }
                                            }
                                            .padding(horizontal = 10.dp, vertical = 6.dp)
                                    ) {
                                        Text(log, color = Color.LightGray, fontSize = 10.sp, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        "currency" -> {
            var isFullScreen by remember { mutableStateOf(true) }
            androidx.compose.ui.window.Dialog(
                onDismissRequest = { activeSpecializedDialog = null },
                properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = !isFullScreen)
            ) {
                var inputAmount by remember { mutableStateOf("100") }
                var selectedSource by remember { mutableStateOf("USD") }
                var selectedTarget by remember { mutableStateOf("PKR") }
                var customBankSurchargePercent by remember { mutableStateOf(1.5f) } // 0% to 5% simulation
                var showMultiConvertMode by remember { mutableStateOf(true) }

                val rates = mapOf(
                    "USD" to 1.0,
                    "PKR" to 278.5,
                    "INR" to 83.3,
                    "EUR" to 0.92,
                    "GBP" to 0.79,
                    "CAD" to 1.36,
                    "AED" to 3.67,
                    "SAR" to 3.75
                )

