                                colors = SliderDefaults.colors(thumbColor = CyberPink, activeTrackColor = CyberPink, inactiveTrackColor = GridSpace),
                                modifier = Modifier.height(20.dp)
                            )
                        }

                        val amt = inputAmount.toDoubleOrNull() ?: 1.0
                        val sourceRate = rates[selectedSource] ?: 1.0
                        val surchargeMultiplier = 1.0 + (customBankSurchargePercent / 100.0)

                        if (showMultiConvertMode) {
                            Text("SIMULTANEOUS CONVERSIONS (WITH SPREAD):", color = CyberCyan, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                rates.filter { it.key != selectedSource }.forEach { (targetCode, targetRate) ->
                                    val finalComp = (amt / sourceRate) * targetRate * surchargeMultiplier
                                    Row(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .background(Color(0xFF03070E), RoundedCornerShape(10.dp))
                                            .padding(horizontal = 12.dp, vertical = 8.dp),
