                                                    "INR" -> "🇮🇳 $targetCode"
                                                    "EUR" -> "🇪🇺 $targetCode"
                                                    "GBP" -> "🇬🇧 $targetCode"
                                                    "CAD" -> "🇨🇦 $targetCode"
                                                    "AED" -> "🇦🇪 $targetCode"
                                                    "SAR" -> "🇸🇦 $targetCode"
                                                    else -> "🏳️ $targetCode"
                                                },
                                                color = Color.White,
                                                fontSize = 11.sp,
                                                fontWeight = FontWeight.Bold
                                            )
                                        }
                                        Text(String.format("%.3f %s", finalComp, targetCode), color = CyberCyan, fontSize = 12.sp, fontWeight = FontWeight.ExtraBold)
                                    }
                                }
                            }
                        } else {
                            // Single target view
                            Text("To Target Currency:", color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                val targetList = listOf("PKR", "INR", "EUR", "CAD", "AED", "SAR")
                                targetList.take(6).forEach { code ->
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .background(if (selectedTarget == code) CyberPink.copy(alpha = 0.2f) else Color(0xFF0F172A), RoundedCornerShape(6.dp))
                                            .border(1.dp, if (selectedTarget == code) CyberPink else Color.Transparent, RoundedCornerShape(6.dp))
                                            .clickable { selectedTarget = code }
                                            .padding(vertical = 6.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(code, color = Color.White, fontWeight = FontWeight.Bold, fontSize = 10.sp)
                                    }
                                }
                            }

                            val targetRate = rates[selectedTarget] ?: 1.0
                            val computed = (amt / sourceRate) * targetRate * surchargeMultiplier

                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(Color(0xFF03070E), RoundedCornerShape(12.dp))
                                    .padding(12.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Text("$amt $selectedSource =", color = Color.Gray, fontSize = 10.sp)
                                    Text(String.format("%.4f %s", computed, selectedTarget), color = CyberCyan, fontSize = 18.sp, fontWeight = FontWeight.ExtraBold)
                                }
                            }
                        }

                        // Historical Trend Simulated Canvas Chart
                        Spacer(modifier = Modifier.height(4.dp))
                        Text("SIMULATED 6-MONTH MARKET TREND INDEX:", color = Color.Gray, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                        androidx.compose.foundation.Canvas(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(56.dp)
                                .background(Color(0xFF03070E), RoundedCornerShape(10.dp))
                                .padding(vertical = 8.dp, horizontal = 16.dp)
                        ) {
                            val bars = listOf(0.4f, 0.6f, 0.55f, 0.75f, 0.68f, 0.9f)
                            val spacing = size.width / (bars.size + 1)
                            for (i in bars.indices) {
                                val barHeight = size.height * bars[i]
                                drawRect(
                                    color = if (i == bars.size - 1) CyberPink else CyberCyan.copy(alpha = 0.8f),
                                    topLeft = androidx.compose.ui.geometry.Offset(
                                        x = (i + 1) * spacing - 6f,
                                        y = size.height - barHeight
                                    ),
                                    size = androidx.compose.ui.geometry.Size(12f, barHeight)
                                )
                            }
                        }
                    }
                }
            }
