                                "Weight" -> listOf("Kg to Lbs", "Lbs to Kg", "Grams to Oz")
                                "Length" -> listOf("Meters to Feet", "Km to Miles", "Miles to Km")
                                else -> listOf("Celsius to F", "F to Celsius", "Celsius to K")
                            }

                            optionList.forEach { type ->
                                Box(
