                            "Lbs to Kg" -> numeric / 2.20462
                            "Grams to Oz" -> numeric * 0.035274
                            "Meters to Feet" -> numeric * 3.28084
                            "Km to Miles" -> numeric * 0.621371
                            "Miles to Km" -> numeric / 0.621371
                            "Celsius to F" -> (numeric * 9 / 5) + 32
