                        Button(
                            onClick = {
                                if (newsQuery.isNotBlank()) {
                                    isFetching = true
                                    coroutineScope.launch {
                                        try {
                                            val prompt = "Provide exactly $headlineCount high quality, realistic current news summaries about $newsQuery. Format beautifully, keeping each item on its own bullet line starting with - "
                                            val responseText = viewModel.getLLMResponseForModel("Rabiya Core-v3 (Gemini 3.5 Flash)", prompt)
                                            val splitList = responseText.split("\n").filter { it.trim().isNotEmpty() && (it.contains("-") || it.contains("*")) }.take(headlineCount)
                                            newsResult = if (splitList.isEmpty()) responseText.split("\n").take(headlineCount) else splitList
                                            // Save copy inside FileManager
                                            viewModel.addFileToFileManager(context, "News_${newsQuery.replace(" ", "_")}_${System.currentTimeMillis()}.txt", "Documents", responseText)
                                        } catch (e: Exception) {
                                            newsResult = listOf("Failed to fetch custom filtered news headlines")
                                        } finally {
                                            isFetching = false
                                        }
                                    }
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                            modifier = Modifier.fillMaxWidth(),
                            shape = RoundedCornerShape(10.dp),
                            enabled = !isFetching
                        ) {
                            if (isFetching) {
                                CircularProgressIndicator(color = Color.Black, modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                            } else {
                                Text("SYNTHESIZE LIVE HEADLINES 📡", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                            }
                        }

                        Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                            val itemsToShow = newsResult.ifEmpty {
                                listOf(
                                    "- Google releases state of the art Gemini 3.5 Flash engines.",
                                    "- DeepMind announces Rabiya Advanced Core-v3 with multiagent focus.",
                                    "- Android 17 EdgeToEdge window safe insets become mandatory."
                                ).take(headlineCount)
                            }
                            itemsToShow.forEach { item ->
                                Box(modifier = Modifier.fillMaxWidth().background(Color(0xFF03070E), RoundedCornerShape(10.dp)).padding(8.dp)) {
                                    Text(item, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Medium)
                                }
                            }
                        }
                    }
                }
            }
        }

        "barcode" -> {
            var isFullScreen by remember { mutableStateOf(true) }
            androidx.compose.ui.window.Dialog(
                onDismissRequest = { activeSpecializedDialog = null },
                properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = !isFullScreen)
            ) {
                var barcodeResult by remember { mutableStateOf("No scan yet") }
                var isScanning by remember { mutableStateOf(false) }
                var focusType by remember { mutableStateOf("Wide Barcode") } // Wide Barcode, Square QR, Circular Scan
                var beepEnabled by remember { mutableStateOf(true) }
                var manualBarcodeText by remember { mutableStateOf("") }
                val context = LocalContext.current
                val coroutineScope = rememberCoroutineScope()

                Surface(
                    shape = if (isFullScreen) RoundedCornerShape(0.dp) else RoundedCornerShape(24.dp),
                    color = Color(0xFF0B0F19),
                    modifier = if (isFullScreen) {
                        Modifier.fillMaxSize()
                    } else {
                        Modifier
                            .fillMaxWidth()
                            .padding(12.dp)
                            .border(1.5.dp, CyberCyan, RoundedCornerShape(24.dp))
                    }
                ) {
                    Column(modifier = Modifier.padding(18.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("📸 NEURAL SCANNING SIMULATOR PRO", fontWeight = FontWeight.Bold, color = Color.White, fontSize = 12.sp)
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                IconButton(onClick = { isFullScreen = !isFullScreen }) {
                                    Icon(
                                        imageVector = if (isFullScreen) Icons.Default.FullscreenExit else Icons.Default.Fullscreen,
                                        contentDescription = "Toggle Fullscreen",
                                        tint = CyberCyan
                                    )
                                }
                                IconButton(onClick = { activeSpecializedDialog = null }) {
                                    Icon(Icons.Default.Close, contentDescription = "Close", tint = TextMuted)
                                }
                            }
                        }

                        // Target scan focus options
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(4.dp)
                        ) {
                            listOf("Wide Barcode", "Square QR", "IRIS Focus").forEach { type ->
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .background(if (focusType == type) CyberCyan.copy(alpha = 0.2f) else Color(0xFF0F172A), RoundedCornerShape(6.dp))
                                        .border(1.dp, if (focusType == type) CyberCyan else Color.Transparent, RoundedCornerShape(6.dp))
                                        .clickable { focusType = type }
                                        .padding(vertical = 5.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(type, color = Color.White, fontWeight = FontWeight.Bold, fontSize = 10.sp)
                                }
                            }
                        }

                        // Simulated Viewport
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(140.dp)
                                .background(Color.Black, RoundedCornerShape(12.dp)),
                            contentAlignment = Alignment.Center
                        ) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center) {
                                if (isScanning) {
                                    CircularProgressIndicator(color = CyberPink, modifier = Modifier.size(24.dp))
                                    Spacer(modifier = Modifier.height(8.dp))
                                    Text("LOCKING TARGET SPECTRUM...", color = CyberPink, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                } else {
                                    // Custom visual border based on focus type
                                    Box(
                                        modifier = Modifier
                                            .size(
                                                width = if (focusType == "Wide Barcode") 180.dp else 90.dp,
                                                height = if (focusType == "Wide Barcode") 40.dp else 90.dp
                                            )
                                            .border(
                                                width = 1.5.dp,
                                                color = CyberCyan,
                                                shape = if (focusType == "IRIS Focus") CircleShape else RoundedCornerShape(8.dp)
                                            ),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Box(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .height(2.dp)
                                                .background(CyberPink)
                                        )
                                    }
                                    Spacer(modifier = Modifier.height(10.dp))
                                    Text("CAMERA VIEWFINDER ACTIVE", color = Color.Gray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("Audio Warning (Beep ALERT)", color = TextLight, fontSize = 11.sp, fontWeight = FontWeight.Medium)
                            Box(
                                modifier = Modifier
                                    .background(if (beepEnabled) CyberCyan.copy(alpha = 0.2f) else Color(0xFF1E293B), RoundedCornerShape(6.dp))
                                    .clickable { beepEnabled = !beepEnabled }
                                    .padding(horizontal = 12.dp, vertical = 4.dp)
                            ) {
                                Text(if (beepEnabled) "ENABLED 🔊" else "MUTED 🔇", color = if (beepEnabled) CyberCyan else Color.Gray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        OutlinedTextField(
                            value = manualBarcodeText,
                            onValueChange = { manualBarcodeText = it },
                            label = { Text("Manual Serial Overrides (Optional)", fontSize = 10.sp, color = CyberCyan) },
                            modifier = Modifier.fillMaxWidth(),
                            colors = OutlinedTextFieldDefaults.colors(focusedTextColor = Color.White, unfocusedTextColor = Color.White, focusedBorderColor = CyberCyan, unfocusedBorderColor = GridSpace),
                            singleLine = true
                        )

                        Button(
                            onClick = {
                                isScanning = true
                                coroutineScope.launch {
                                    kotlinx.coroutines.delay(1200)
                                    if (beepEnabled) {
                                        // Emit virtual alert sound
                                    }
                                    if (manualBarcodeText.isNotBlank()) {
                                        barcodeResult = "Detected Manual: $manualBarcodeText\nTarget Location Verified!"
                                    } else {
                                        val randomCodes = listOf(
                                            "Samsung SyncMaster (991-884-A12)" to "Warehouse Corridor A",
                                            "Saheli Brain Core Module (505-112-TX2)" to "Rabiya Advanced Hosting Cloud",
                                            "Logitech Pro Mouse (404-303-MD)" to "Dispatch Dock Section 7"
                                        )
                                        val (product, source) = randomCodes.random()
                                        barcodeResult = "Product: $product\nLocation: $source"
                                    }
                                    isScanning = false
                                    // Save Scan Result
                                    viewModel.addFileToFileManager(context, "Scan_Log_${System.currentTimeMillis()}.txt", "Documents", "Neural Scan Event Log:\nQuery: $manualBarcodeText\nResult: $barcodeResult\nTime: ${System.currentTimeMillis()}")
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                            modifier = Modifier.fillMaxWidth(),
                            shape = RoundedCornerShape(10.dp),
                            enabled = !isScanning
                        ) {
                            Text("SIMULATE REAL FOCUS SCAN 📸", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                        }

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF03070E), RoundedCornerShape(10.dp))
                                .padding(10.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(barcodeResult, color = CyberCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold, textAlign = TextAlign.Center)
                        }
                    }
                }
            }
        }

        "qr_gen" -> {
            var isFullScreen by remember { mutableStateOf(true) }
            androidx.compose.ui.window.Dialog(
                onDismissRequest = { activeSpecializedDialog = null },
                properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = !isFullScreen)
            ) {
                var textQr by remember { mutableStateOf("https://ai.studio") }
                var fgColorHex by remember { mutableStateOf("00ffff") } // Cyan (Default)
                var bgColorHex by remember { mutableStateOf("0c101a") } // Dark Background
                var eccLevel by remember { mutableStateOf("M") } // L, M, Q, H
                var isSaving by remember { mutableStateOf(false) }
                val context = LocalContext.current
                val coroutineScope = rememberCoroutineScope()

                // Recalculate QR Code URL dynamically based on modified UI controls
                val qrUrl = remember(textQr, fgColorHex, bgColorHex, eccLevel) {
                    val encoded = java.net.URLEncoder.encode(textQr, "UTF-8")
                    "https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=$encoded&color=$fgColorHex&bgcolor=$bgColorHex&ecc=$eccLevel"
                }

                Surface(
                    shape = if (isFullScreen) RoundedCornerShape(0.dp) else RoundedCornerShape(24.dp),
                    color = Color(0xFF0B0F19),
                    modifier = if (isFullScreen) {
                        Modifier.fillMaxSize()
                    } else {
                        Modifier
                            .fillMaxWidth()
                            .padding(12.dp)
                            .border(1.5.dp, CyberCyan, RoundedCornerShape(24.dp))
                    }
                ) {
                    Column(modifier = Modifier.padding(18.dp), verticalArrangement = Arrangement.spacedBy(10.dp), horizontalAlignment = Alignment.CenterHorizontally) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("🔳 MOBILE QR GENERATOR PRO", fontWeight = FontWeight.Bold, color = Color.White, fontSize = 12.sp)
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                IconButton(onClick = { isFullScreen = !isFullScreen }) {
                                    Icon(
                                        imageVector = if (isFullScreen) Icons.Default.FullscreenExit else Icons.Default.Fullscreen,
                                        contentDescription = "Toggle Fullscreen",
                                        tint = CyberCyan
                                    )
                                }
                                IconButton(onClick = { activeSpecializedDialog = null }) {
                                    Icon(Icons.Default.Close, contentDescription = "Close", tint = TextMuted)
                                }
                            }
                        }

                        OutlinedTextField(
                            value = textQr,
                            onValueChange = { textQr = it },
                            label = { Text("Enter Data or Link", color = CyberCyan, fontSize = 11.sp) },
                            modifier = Modifier.fillMaxWidth(),
                            colors = OutlinedTextFieldDefaults.colors(focusedTextColor = Color.White, unfocusedTextColor = Color.White, focusedBorderColor = CyberCyan, unfocusedBorderColor = GridSpace),
                            singleLine = true
                        )

                        // Foreground Color Selector Row
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("Foreground Color:", color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(horizontalArrangement = Arrangement.spacedBy(5.dp)) {
                                val colorsList = listOf("00ffff" to CyberCyan, "ff3399" to CyberPink, "10b981" to Color(0xFF10B981), "f59e0b" to Color(0xFFF59E0B), "ffffff" to Color.White)
                                colorsList.forEach { (hex, col) ->
                                    Box(
                                        modifier = Modifier
                                            .size(20.dp)
                                            .background(col, CircleShape)
                                            .border(if (fgColorHex == hex) 1.5.dp else 0.dp, Color.White, CircleShape)
                                            .clickable { fgColorHex = hex }
                                    )
                                }
                            }
                        }

                        // Background Color Selector Row
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("Background Color:", color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(horizontalArrangement = Arrangement.spacedBy(5.dp)) {
                                val bgList = listOf("0c101a" to Color(0xFF0C101A), "ffffff" to Color.White)
                                bgList.forEach { (hex, col) ->
                                    Box(
                                        modifier = Modifier
                                            .size(20.dp)
                                            .background(col, RoundedCornerShape(4.dp))
                                            .border(if (bgColorHex == hex) 1.5.dp else 0.dp, CyberCyan, RoundedCornerShape(4.dp))
                                            .clickable { bgColorHex = hex }
                                    )
                                }
                            }
                        }

                        // Error Correction Selection Card
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("Error Grid Matrix:", color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                listOf("L", "M", "Q", "H").forEach { ecc ->
                                    Box(
                                        modifier = Modifier
                                            .background(if (eccLevel == ecc) CyberPink.copy(alpha = 0.2f) else Color(0xFF0F172A), RoundedCornerShape(4.dp))
                                            .border(1.dp, if (eccLevel == ecc) CyberPink else Color.Transparent, RoundedCornerShape(4.dp))
                                            .clickable { eccLevel = ecc }
                                            .padding(horizontal = 8.dp, vertical = 2.dp)
                                    ) {
                                        Text(ecc, color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                        }

                        // Load Real QR Code Image using Coil AsyncImage
                        Box(
                            modifier = Modifier
                                .size(130.dp)
                                .background(Color.White, RoundedCornerShape(12.dp))
                                .padding(8.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            AsyncImage(
                                model = qrUrl,
                                contentDescription = "Dynamic QR Code",
                                modifier = Modifier.size(114.dp)
                            )
                        }

                        // Save QR Code Button
                        Button(
                            onClick = {
                                isSaving = true
                                coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                                    try {
                                        val client = okhttp3.OkHttpClient()
                                        val req = okhttp3.Request.Builder().url(qrUrl).build()
                                        client.newCall(req).execute().use { response ->
                                            if (response.isSuccessful) {
                                                val bytes = response.body?.bytes()
                                                if (bytes != null) {
                                                    val filename = "QR_${System.currentTimeMillis()}.png"
                                                    viewModel.addFileToFileManager(context, filename, "Images", "", bytes)
                                                    kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                                        android.widget.Toast.makeText(context, "Saved QR Code to File Manager (Images)!", android.widget.Toast.LENGTH_SHORT).show()
                                                    }
                                                }
                                            }
                                        }
                                    } catch (e: Exception) {
                                        kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.Main) {
                                            android.widget.Toast.makeText(context, "Failed to save: ${e.message}", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    } finally {
                                        isSaving = false
                                    }
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                            modifier = Modifier.fillMaxWidth(),
                            shape = RoundedCornerShape(10.dp),
                            enabled = !isSaving
                        ) {
                            if (isSaving) {
                                CircularProgressIndicator(color = Color.Black, modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                            } else {
                                Text("SAVE QR TO FILE MANAGER 💾", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                            }
                        }
                    }
                }
            }
        }

        "code_sandbox" -> {
            CodeSandboxDialog(
                viewModel = viewModel,
                onDismiss = {
                    activeSpecializedDialog = null
                    selectedToolForUiDialog = null
                }
            )
        }
    }
}


@Composable
fun MemoryBoxNotesSubTab(viewModel: MainViewModel) {
    val items by viewModel.allMemoryItems.collectAsStateWithLifecycle()
    var noteTitle by remember { mutableStateOf("") }
    var noteContent by remember { mutableStateOf("") }
    var noteCategory by remember { mutableStateOf("Personal") }

    val context = LocalContext.current

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        item {
            // Save card
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(CardSpace, RoundedCornerShape(20.dp))
                    .padding(16.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Text("ADD SECURE INTEL BRAINWAVE", color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                    
                    OutlinedTextField(
                        value = noteTitle,
                        onValueChange = { noteTitle = it },
                        placeholder = { Text("Brainwave Title...", color = TextMuted, fontSize = 12.sp) },
                        modifier = Modifier.fillMaxWidth(),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = CyberCyan,
                            unfocusedBorderColor = GridSpace
                        ),
                        singleLine = true
                    )

                    OutlinedTextField(
                        value = noteContent,
                        onValueChange = { noteContent = it },
                        placeholder = { Text("What are you capturing inside memory box? (SQL query, scripts, numbers)...", color = TextMuted, fontSize = 12.sp) },
                        modifier = Modifier.fillMaxWidth(),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = CyberCyan,
                            unfocusedBorderColor = GridSpace
                        ),
                        maxLines = 4
                    )

                    // Categories select
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        listOf("Ideas", "Personal", "Code", "Reminders").forEach { cat ->
                            val isSelected = (noteCategory == cat)
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .background(if (isSelected) CyberCyan.copy(alpha = 0.2f) else GridSpace, RoundedCornerShape(8.dp))
                                    .border(1.2.dp, if (isSelected) CyberCyan else Color.Transparent, RoundedCornerShape(8.dp))
                                    .clickable { noteCategory = cat }
                                    .padding(vertical = 8.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Text(cat, color = if (isSelected) Color.White else TextMuted, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }

                    var isAIEnhancing by remember { mutableStateOf(false) }
                    val coroutineScope = rememberCoroutineScope()

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Button(
                            onClick = {
                                if (noteContent.isBlank()) {
                                    android.widget.Toast.makeText(context, "Write some drafts in content to enrich!", android.widget.Toast.LENGTH_SHORT).show()
                                    return@Button
                                }
                                isAIEnhancing = true
                                coroutineScope.launch {
                                    try {
                                        val prompt = "Format, structurally organize and enrich this note content with beautiful markdown titles/bullets and code structure if appropriate: \"$noteContent\""
                                        val response = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, prompt)
                                        if (response.isNotBlank()) {
                                            noteContent = response
                                            if (noteTitle.isBlank()) {
                                                noteTitle = "AI Generated Intel"
                                            }
                                            android.widget.Toast.makeText(context, "🪄 Intel Boosted via Custom Rabiya Brain!", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    } catch (e: Exception) {
                                        android.widget.Toast.makeText(context, "AI enrichment failed. Try again.", android.widget.Toast.LENGTH_SHORT).show()
                                    } finally {
                                        isAIEnhancing = false
                                    }
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = if (isAIEnhancing) Color.Gray else CyberPink),
                            modifier = Modifier.weight(1.1f),
                            shape = RoundedCornerShape(10.dp),
                            enabled = !isAIEnhancing
                        ) {
                            Text(if (isAIEnhancing) "BOOSTING..." else "AI ENRICH 🪄", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 10.5.sp)
                        }

                        Button(
                            onClick = {
                                if (noteContent.isNotBlank()) {
                                    viewModel.addMemoryNote(noteTitle, noteContent, noteCategory)
                                    noteTitle = ""
                                    noteContent = ""
                                    android.widget.Toast.makeText(context, "✅ Capturing Intel inside database!", android.widget.Toast.LENGTH_SHORT).show()
                                } else {
                                    android.widget.Toast.makeText(context, "Note content cannot be empty!", android.widget.Toast.LENGTH_SHORT).show()
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                            modifier = Modifier.weight(1.3f),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Text("SAVE INTEL VAULT 💾", color = DarkBackground, fontWeight = FontWeight.Bold, fontSize = 10.5.sp)
                        }
                    }
                }
            }
        }

        item {
            Text("SECURED BRAINWAVES ACTIVE (${items.size})", fontWeight = FontWeight.Bold, fontSize = 12.sp, color = Color.White)
        }

        if (items.isEmpty()) {
            item {
                Box(modifier = Modifier.fillMaxWidth().padding(32.dp), contentAlignment = Alignment.Center) {
                    Text("No notes captured inside sqlite.", color = TextMuted, fontSize = 12.sp)
                }
            }
        } else {
            items(items, key = { it.id }) { item ->
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(CardSpace, RoundedCornerShape(16.dp))
                        .padding(14.dp)
                ) {
                    Column {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Box(
                                modifier = Modifier
                                    .background(CyberCyan.copy(alpha = 0.15f), RoundedCornerShape(6.dp))
                                    .padding(horizontal = 8.dp, vertical = 3.dp)
                            ) {
                                Text(item.category.uppercase(), color = CyberCyan, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            }
                            IconButton(
                                onClick = { viewModel.deleteMemoryNote(item.id) },
                                modifier = Modifier.size(24.dp)
                            ) {
                                Icon(Icons.Default.Delete, contentDescription = "Delete", tint = CyberPink)
                            }
                        }
                        Spacer(modifier = Modifier.height(8.dp))
                        Text(item.title, fontWeight = FontWeight.Bold, color = Color.White, fontSize = 13.sp)
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(item.content, color = TextLight, fontSize = 12.sp, lineHeight = 16.sp)
                    }
                }
            }
        }
        item { Spacer(modifier = Modifier.height(20.dp)) }
    }
}

@Composable
fun SeoPlannerSubTab(viewModel: MainViewModel) {
    val keywordResults by viewModel.keywordResults.collectAsStateWithLifecycle()
    val planTitle by viewModel.seoPlanTitle.collectAsStateWithLifecycle()
    val planContent by viewModel.seoPlanContent.collectAsStateWithLifecycle()
    val isLoading by viewModel.isSeoLoading.collectAsStateWithLifecycle()

    var seedQuery by remember { mutableStateOf("") }
    var locationSelected by remember { mutableStateOf("United States") }

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        item {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(CardSpace, RoundedCornerShape(20.dp))
                    .padding(16.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Text("DYNAMIC INTEL KEYWORDS DISCOVERY PRO", color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                    
                    OutlinedTextField(
                        value = seedQuery,
                        onValueChange = { seedQuery = it },
                        placeholder = { Text("E.g. Saheli companion, smart assistant...", color = TextMuted, fontSize = 12.sp) },
                        modifier = Modifier.fillMaxWidth(),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = CyberCyan,
                            unfocusedBorderColor = GridSpace
                        ),
                        singleLine = true
                    )

                    // Country selector chips
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(4.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        listOf("United States" to "US 🇺🇸", "India" to "IN 🇮🇳", "United Kingdom" to "UK 🇬🇧", "Pakistan" to "PK 🇵🇰", "Canada" to "CA 🇨🇦").forEach { (loc, label) ->
                            val isSel = (locationSelected == loc)
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .background(if (isSel) CyberPink.copy(alpha = 0.2f) else GridSpace, RoundedCornerShape(6.dp))
                                    .border(1.dp, if (isSel) CyberPink else Color.Transparent, RoundedCornerShape(6.dp))
                                    .clickable { locationSelected = loc }
                                    .padding(vertical = 6.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Text(label, color = if (isSel) Color.White else TextMuted, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }

                    Button(
                        onClick = {
                            if (seedQuery.isNotBlank()) {
                                viewModel.generateKeywordAnalysis(seedQuery, locationSelected)
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                        modifier = Modifier.fillMaxWidth(),
                        shape = RoundedCornerShape(10.dp)
                    ) {
                        Text("DECONSTRUCT ORGANIC KEYWORDS 📈", color = DarkBackground, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                    }
                }
            }
        }

        if (isLoading) {
            item {
                Box(modifier = Modifier.fillMaxWidth(), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator(color = CyberCyan)
                }
            }
        } else {
            if (keywordResults.isNotEmpty()) {
                item {
                    Text("ORGANIC SEARCH LANDSCAPE STATS", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 13.sp)
                }
                items(keywordResults) { item ->
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(CardSpace, RoundedCornerShape(12.dp))
                            .padding(12.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text(item.keyword, fontWeight = FontWeight.Bold, color = Color.White, fontSize = 13.sp)
                                Text("Suggestion fit: ${item.suggestion}", color = TextMuted, fontSize = 11.sp)
                            }
                            Column(horizontalAlignment = Alignment.End) {
                                Text("${item.searchVolume} Monthly", color = CyberCyan, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Box(modifier = Modifier.background(CyberPink.copy(alpha = 0.15f), RoundedCornerShape(4.dp)).padding(3.dp)) {
                                        Text(item.cpc, color = CyberPink, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                    Box(modifier = Modifier.background(SuccessGreen.copy(alpha = 0.15f), RoundedCornerShape(4.dp)).padding(3.dp)) {
                                        Text(item.trend, color = SuccessGreen, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                        }
                    }
                }

                if (planTitle.isNotEmpty()) {
                    item {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(CardSpace, RoundedCornerShape(16.dp))
                                .padding(16.dp)
                                .border(1.dp, SuccessGreen.copy(alpha = 0.4f), RoundedCornerShape(16.dp))
                        ) {
                            Column {
                                Text(planTitle, fontWeight = FontWeight.Bold, color = SuccessGreen, fontSize = 13.sp)
                                Spacer(modifier = Modifier.height(8.dp))
                                Text(planContent, color = TextLight, fontSize = 12.sp, lineHeight = 17.sp)
                            }
                        }
                    }
                }
            }
        }
        item { Spacer(modifier = Modifier.height(20.dp)) }
    }
}

