@Composable
fun ProfileScreen(viewModel: MainViewModel) {
    var activeSubTab by remember { mutableStateOf(0) } // 0 = AI Directory, 1 = Settings
    val context = LocalContext.current

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(14.dp),
        verticalArrangement = Arrangement.spacedBy(14.dp)
    ) {
        // Sub Tab Selector
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(CardSpace, RoundedCornerShape(14.dp))
                .padding(4.dp),
            horizontalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            listOf("AI HUB" to 0, "SETTINGS" to 1, "COMPLIANCE" to 2).forEach { (label, index) ->
                val isSelected = activeSubTab == index
                Box(
                    modifier = Modifier
                        .weight(1f)
                        .clip(RoundedCornerShape(10.dp))
                        .background(if (isSelected) GridSpace else Color.Transparent)
                        .border(1.dp, if (isSelected) CyberCyan.copy(alpha = 0.4f) else Color.Transparent, RoundedCornerShape(10.dp))
                        .clickable { activeSubTab = index }
                        .padding(vertical = 10.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = label,
                        fontWeight = FontWeight.ExtraBold,
                        fontSize = 11.sp,
                        color = if (isSelected) CyberCyan else TextMuted
                    )
                }
            }
        }

        // Dynamic State Screen
        when (activeSubTab) {
            0 -> AiDirectoryPanel()
            1 -> SystemSettingsPanel(viewModel)
            2 -> LegalCompliancePanel(viewModel)
        }
    }
}

@Composable
fun AiDirectoryPanel() {
    var searchQuery by remember { mutableStateOf("") }
    var selectedCategory by remember { mutableStateOf("All") }
    val context = LocalContext.current

    val categories = listOf(
        "All",
        "Text / Language",
        "Image Gen",
        "Video Gen",
        "Code / Dev",
        "Voice / Audio",
        "Research",
        "Productivity",
        "Design",
        "Data / Analytics",
        "Other Cool AI"
    )

    // Filter tools
    val filteredTools = remember(searchQuery, selectedCategory) {
        aiToolsList.filter { tool ->
            val matchCategory = selectedCategory == "All" || tool.category == selectedCategory
            val matchQuery = searchQuery.isBlank() ||
                    tool.name.contains(searchQuery, ignoreCase = true) ||
                    tool.category.contains(searchQuery, ignoreCase = true) ||
                    tool.description.contains(searchQuery, ignoreCase = true)
            matchCategory && matchQuery
        }
    }

    Column(
        modifier = Modifier.fillMaxSize(),
        verticalArrangement = Arrangement.spacedBy(10.dp)
    ) {
        // Search bar
        OutlinedTextField(
            value = searchQuery,
            onValueChange = { searchQuery = it },
            placeholder = { Text("Search 100+ Free AI models & tools...", color = TextMuted, fontSize = 12.sp) },
            leadingIcon = { Icon(Icons.Default.Search, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(18.dp)) },
            trailingIcon = if (searchQuery.isNotEmpty()) {
                {
                    IconButton(onClick = { searchQuery = "" }) {
                        Icon(Icons.Default.Close, contentDescription = "Clear", tint = CyberPink, modifier = Modifier.size(18.dp))
                    }
                }
            } else null,
            modifier = Modifier.fillMaxWidth(),
            shape = RoundedCornerShape(12.dp),
            colors = OutlinedTextFieldDefaults.colors(
                focusedBorderColor = CyberCyan,
                unfocusedBorderColor = GridSpace
            ),
            singleLine = true
        )

        // Categories Row
        LazyRow(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(6.dp),
            contentPadding = PaddingValues(bottom = 2.dp)
        ) {
            items(categories) { category ->
                val isSelected = selectedCategory == category
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(30.dp))
                        .background(if (isSelected) CyberCyan.copy(alpha = 0.15f) else CardSpace)
                        .border(
                            1.dp,
                            if (isSelected) CyberCyan else GridSpace,
                            RoundedCornerShape(30.dp)
                        )
                        .clickable { selectedCategory = category }
                        .padding(horizontal = 12.dp, vertical = 6.dp)
                ) {
                    Text(
                        text = category,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold,
                        color = if (isSelected) CyberCyan else TextLight
                    )
                }
            }
        }

        // Help Box
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(SuccessGreen.copy(alpha = 0.05f), RoundedCornerShape(12.dp))
                .border(1.dp, SuccessGreen.copy(alpha = 0.15f), RoundedCornerShape(12.dp))
                .padding(10.dp)
        ) {
            Row(
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text("💡", fontSize = 15.sp)
                Text(
                    text = "Tap on any tool block to open its main website instantly. No log-ins or payments required.",
                    color = TextLight,
                    fontSize = 10.sp,
                    lineHeight = 14.sp
                )
            }
        }

        // Tools list
        if (filteredTools.isEmpty()) {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .weight(1f),
                contentAlignment = Alignment.Center
            ) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text("🔍", fontSize = 36.sp)
                    Spacer(modifier = Modifier.height(8.dp))
                    Text("No AI Tools match your query", color = TextMuted, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                }
            }
        } else {
            LazyColumn(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth(),
                verticalArrangement = Arrangement.spacedBy(8.dp),
                contentPadding = PaddingValues(bottom = 12.dp)
            ) {
                items(filteredTools) { tool ->
                    AiToolCard(tool = tool)
                }
            }
        }
    }
}

@Composable
fun AiToolCard(tool: AiTool) {
    val context = LocalContext.current
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(16.dp))
            .background(CardSpace)
            .border(1.dp, GridSpace, RoundedCornerShape(16.dp))
            .clickable {
                try {
                    android.widget.Toast.makeText(context, "Redirecting to ${tool.name}...", android.widget.Toast.LENGTH_SHORT).show()
                    val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(tool.url))
                    context.startActivity(intent)
                } catch (e: Exception) {
                    android.widget.Toast.makeText(context, "Url launch failed: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                }
            }
            .padding(12.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Box(
                modifier = Modifier.size(42.dp)
            ) {
                // Main Favicon Box
                Box(
                    modifier = Modifier
                        .size(36.dp)
                        .background(Color(0xFF0F172A), RoundedCornerShape(10.dp))
                        .border(1.dp, CyberCyan.copy(alpha = 0.3f), RoundedCornerShape(10.dp))
                        .align(Alignment.CenterStart),
                    contentAlignment = Alignment.Center
                ) {
                    val domain = remember(tool.url) {
                        try {
                            val uri = android.net.Uri.parse(tool.url)
                            var host = uri.host ?: ""
                            if (host.startsWith("www.")) {
                                host = host.substring(4)
                            }
                            host
                        } catch (e: Exception) {
                            ""
                        }
                    }
                    AsyncImage(
                        model = "https://www.google.com/s2/favicons?sz=64&domain=$domain",
                        contentDescription = tool.name,
                        modifier = Modifier
                            .size(22.dp)
                            .clip(RoundedCornerShape(4.dp)),
                        contentScale = ContentScale.Fit
                    )
                }
                
                // Category emoji badge in the bottom-right corner
                Box(
                    modifier = Modifier
                        .size(16.dp)
                        .background(CardSpace, RoundedCornerShape(4.dp))
                        .border(0.5.dp, GridSpace, RoundedCornerShape(4.dp))
                        .align(Alignment.BottomEnd),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = when (tool.category) {
                            "Text / Language" -> "💬"
                            "Image Gen" -> "🎨"
                            "Video Gen" -> "🎬"
                            "Code / Dev" -> "💻"
                            "Voice / Audio" -> "🔊"
                            "Research" -> "📚"
                            "Productivity" -> "🚀"
                            "Design" -> "✨"
                            "Data / Analytics" -> "📊"
                            else -> "⚙️"
                        },
                        fontSize = 9.sp
                    )
                }
            }

            Column(modifier = Modifier.weight(1f)) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Text(
                        text = tool.name,
                        fontWeight = FontWeight.ExtraBold,
                        color = Color.White,
                        fontSize = 13.sp
                    )
                    Box(
                        modifier = Modifier
                            .background(CyberCyan.copy(alpha = 0.15f), RoundedCornerShape(4.dp))
                            .padding(horizontal = 4.dp, vertical = 2.dp)
                    ) {
                        Text(
                            text = "100% FREE",
                            color = CyberCyan,
                            fontSize = 7.sp,
                            fontWeight = FontWeight.ExtraBold
                        )
                    }
                }
                Spacer(modifier = Modifier.height(2.dp))
                Text(
                    text = tool.description,
                    color = TextMuted,
                    fontSize = 11.sp,
                    lineHeight = 15.sp,
                    maxLines = 2,
                    overflow = TextOverflow.Ellipsis
                )
                Spacer(modifier = Modifier.height(2.dp))
                Text(
                    text = tool.url,
                    color = CyberCyan.copy(alpha = 0.5f),
                    fontSize = 9.sp,
                    fontWeight = FontWeight.SemiBold
                )
            }

            Icon(
                imageVector = Icons.Default.OpenInNew,
                contentDescription = "Open Portal",
                tint = CyberCyan.copy(alpha = 0.7f),
                modifier = Modifier.size(16.dp)
            )
        }
    }
}

@Composable
fun SystemSettingsPanel(viewModel: MainViewModel) {
    val lockSettings by viewModel.lockSettings.collectAsStateWithLifecycle()
    var editPasscode by remember { mutableStateOf("") }
    val context = LocalContext.current

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        verticalArrangement = Arrangement.spacedBy(14.dp)
    ) {
        // Upgrade to Pro inside Settings (Bound to ViewModel)
        item {
            val isProUnlocked by viewModel.isProStatusUnlocked.collectAsStateWithLifecycle()
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(
                        Brush.linearGradient(listOf(Color(0xFF0F172A), Color(0xFF131C32))),
                        RoundedCornerShape(20.dp)
                    )
                    .border(
                        BorderStroke(1.2.dp, Brush.linearGradient(listOf(Color(0xFFFFD700), CyberPink))),
                        RoundedCornerShape(20.dp)
                    )
                    .padding(16.dp)
            ) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(14.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(
                        modifier = Modifier
                            .size(60.dp)
                            .background(
                                Brush.radialGradient(colors = listOf(CyberPink.copy(alpha = 0.3f), Color.Transparent)),
                                CircleShape
                            ),
                        contentAlignment = Alignment.Center
                    ) {
                        Text("🎁", fontSize = 32.sp)
                    }

                    Column(modifier = Modifier.weight(1.2f)) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(6.dp)
                        ) {
                            Text("👑", fontSize = 14.sp)
                            Text(
                                text = if (isProUnlocked) "Active Pro Mode" else "Upgrade to Pro",
                                fontWeight = FontWeight.ExtraBold,
                                color = Color(0xFFFFD700),
                                fontSize = 13.sp
                            )
                        }
                        Spacer(modifier = Modifier.height(4.dp))
                        Column(verticalArrangement = Arrangement.spacedBy(2.dp)) {
                            ProBenefitRow("Unlock All Premium Tools")
                            ProBenefitRow("Faster Generations")
                            ProBenefitRow("No Ads")
                        }
                    }

                    Button(
                        onClick = { viewModel.toggleProStatus() },
                        colors = ButtonDefaults.buttonColors(
                            containerColor = if (isProUnlocked) SuccessGreen else Color(0xFF3B82F6)
                        ),
                        shape = RoundedCornerShape(12.dp),
                        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 6.dp)
                    ) {
                        Text(
                            text = if (isProUnlocked) "Active!" else "Upgrade Now",
                            fontWeight = FontWeight.ExtraBold,
                            fontSize = 11.sp,
                            color = Color.White
                        )
                    }
                }
            }
        }

        // 🚀 RABIYA NEURAL TURBO PERFORMANCE ENGINE (RAM & SPEED BOOSTER)
        item {
            val isTurboEnabled by viewModel.isTurboMode.collectAsStateWithLifecycle()
            val speedLatency by viewModel.performanceLatency.collectAsStateWithLifecycle()
            val threadsAllocated by viewModel.threadAllocations.collectAsStateWithLifecycle()
            val lastFreedRam by viewModel.freedRamCount.collectAsStateWithLifecycle()
            val totalCacheHits by viewModel.cachedRequestCount.collectAsStateWithLifecycle()

            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(CardSpace, RoundedCornerShape(20.dp))
                    .border(
                        BorderStroke(
                            1.2.dp,
                            if (isTurboEnabled) Brush.linearGradient(listOf(CyberCyan, SuccessGreen))
                            else Brush.linearGradient(listOf(TextMuted, GridSpace))
                        ),
                        RoundedCornerShape(20.dp)
                    )
                    .padding(16.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    // Header
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Text("🚀", fontSize = 20.sp)
                            Column {
                                Text(
                                    text = "RABIYA NEURAL SPEED ENGINE",
                                    color = if (isTurboEnabled) CyberCyan else TextLight,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.ExtraBold,
                                    letterSpacing = 0.5.sp
                                )
                                Text(
                                    text = "Optimize processor threads, RAM, and caching",
                                    color = TextMuted,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Medium
                                )
                            }
                        }

                        Switch(
                            checked = isTurboEnabled,
                            onCheckedChange = { viewModel.setTurboModeEnabled(it) },
                            colors = SwitchDefaults.colors(
                                checkedThumbColor = CyberCyan,
                                checkedTrackColor = CyberCyan.copy(alpha = 0.3f),
                                uncheckedThumbColor = TextMuted,
                                uncheckedTrackColor = GridSpace
                            ),
                            modifier = Modifier.testTag("turbo_mode_switch")
                        )
                    }

                    // Divider
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(1.dp)
                            .background(GridSpace)
                    )

                    // Live Statistics
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        // Latency Card
                        Column(
                            modifier = Modifier
                                .weight(1.5f)
                                .background(GridSpace, RoundedCornerShape(10.dp))
                                .padding(8.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Text("⏱️ LATENCY", color = TextMuted, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            Spacer(modifier = Modifier.height(4.dp))
                            Text(
                                text = speedLatency,
                                color = if (isTurboEnabled) SuccessGreen else CyberPink,
                                fontSize = 14.sp,
                                fontWeight = FontWeight.Black
                            )
                        }

                        // Thread Allocation Card
                        Column(
                            modifier = Modifier
                                .weight(1.5f)
                                .background(GridSpace, RoundedCornerShape(10.dp))
                                .padding(8.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Text("🧵 THREADS", color = TextMuted, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            Spacer(modifier = Modifier.height(4.dp))
                            Text(
                                text = "$threadsAllocated",
                                color = if (isTurboEnabled) CyberCyan else TextLight,
                                fontSize = 14.sp,
                                fontWeight = FontWeight.Black
                            )
                        }

                        // Cache Hits Card
                        Column(
                            modifier = Modifier
                                .weight(1.5f)
                                .background(GridSpace, RoundedCornerShape(10.dp))
                                .padding(8.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Text("⚡ CACHE HITS", color = TextMuted, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            Spacer(modifier = Modifier.height(4.dp))
                            Text(
                                text = "$totalCacheHits",
                                color = if (totalCacheHits > 0) SuccessGreen else TextMuted,
                                fontSize = 14.sp,
                                fontWeight = FontWeight.Black
                            )
                        }
                    }

                    // Boost Status message if present
                    if (lastFreedRam > 0f) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(SuccessGreen.copy(alpha = 0.1f), RoundedCornerShape(8.dp))
                                .border(BorderStroke(0.8.dp, SuccessGreen.copy(alpha = 0.3f)), RoundedCornerShape(8.dp))
                                .padding(8.dp)
                        ) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.Center,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = "✨ Ram Boost Success: Freed ${String.format("%.2f", lastFreedRam)} MB memory heap!",
                                    color = SuccessGreen,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }

                    // Optimization Button
                    Button(
                        onClick = {
                            viewModel.optimizeRamMemory()
                            android.widget.Toast.makeText(context, "🚀 RAM Booster Activated! Heap cleaned and cache synchronized.", android.widget.Toast.LENGTH_SHORT).show()
                        },
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(38.dp)
                            .testTag("boost_ram_button"),
                        colors = ButtonDefaults.buttonColors(
                            containerColor = if (isTurboEnabled) CyberCyan else Color(0xFF475569)
                        ),
                        shape = RoundedCornerShape(10.dp),
                        contentPadding = PaddingValues(0.dp)
                    ) {
                        Row(
                            horizontalArrangement = Arrangement.spacedBy(6.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("🔋", fontSize = 14.sp)
                            Text(
                                text = "TRIGGER MEMORY BOOST (FREE UP HEAP RAM)",
                                color = if (isTurboEnabled) DarkBackground else Color.White,
                                fontSize = 9.sp,
                                fontWeight = FontWeight.ExtraBold,
                                letterSpacing = 0.5.sp
                            )
                        }
                    }
                }
            }
        }

        // App Lock Config Panel
        item {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(CardSpace, RoundedCornerShape(20.dp))
                    .padding(16.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Text("SECURE ACCESS LOCK SETTINGS", color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                    
                    val isLockedSet = lockSettings.passcode.isNotEmpty()
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = if (isLockedSet) "🔒 SECURITY LOCK PATTERN ACTIVE" else "🔓 SECURITY LOCK INSTANCE INACTIVE",
                            color = if (isLockedSet) SuccessGreen else CyberPink,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    OutlinedTextField(
                        value = editPasscode,
                        onValueChange = { editPasscode = it },
                        placeholder = { Text("Set 4-digit Passcode (e.g. 1290)...", color = TextMuted, fontSize = 12.sp) },
                        modifier = Modifier.fillMaxWidth(),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = CyberCyan,
                            unfocusedBorderColor = GridSpace
                        ),
                        singleLine = true,
                        visualTransformation = PasswordVisualTransformation()
                    )

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Button(
                            onClick = {
                                if (editPasscode.length == 4) {
                                    viewModel.configurePasscode(editPasscode, false)
                                    editPasscode = ""
                                    android.widget.Toast.makeText(context, "✅ Security passcode updated!", android.widget.Toast.LENGTH_SHORT).show()
                                } else {
                                    android.widget.Toast.makeText(context, "Passcode must be exactly 4 digits!", android.widget.Toast.LENGTH_SHORT).show()
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                            modifier = Modifier.weight(1f),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Text("Set Lock", color = DarkBackground, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }

                        OutlinedButton(
                            onClick = {
                                viewModel.configurePasscode("", false)
                                editPasscode = ""
                                android.widget.Toast.makeText(context, "🔓 Security lock cleared completely!", android.widget.Toast.LENGTH_SHORT).show()
                            },
                            border = BorderStroke(1.dp, CyberPink),
                            modifier = Modifier.weight(1f),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Text("Clear Lock", color = CyberPink, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }
            }
        }

        // API credentials Decoder panel
        item {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(CardSpace, RoundedCornerShape(16.dp))
                    .padding(16.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Text("API CREDENTIALS SYSTEM DECODER", color = CyberCyan, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                    
                    ApiCredentialRow("Google Gemini Key", viewModel.geminiKey.isNotBlank() && viewModel.geminiKey != "ai_key_placeholder")
                    ApiCredentialRow("ChatGPT Instance Key", viewModel.chatGptKey.isNotBlank() && viewModel.chatGptKey != "chatgpt_placeholder")
                    ApiCredentialRow("Anthropic Claude Key", viewModel.claudeKey.isNotBlank() && viewModel.claudeKey != "claude_placeholder")
                }
            }
        }
        
        // 🛡️ SECURITY PROTOCOL & PRIVACY POLICY COMPLIANCE
        item {
            var isPrivacyPolicyExpanded by remember { mutableStateOf(false) }
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(CardSpace, RoundedCornerShape(20.dp))
                    .border(
                        BorderStroke(
                            1.2.dp,
                            if (isPrivacyPolicyExpanded) Brush.linearGradient(listOf(CyberCyan, SuccessGreen))
                            else Brush.linearGradient(listOf(CyberCyan.copy(alpha = 0.3f), Color.Transparent))
                        ),
                        RoundedCornerShape(20.dp)
                    )
                    .clickable { isPrivacyPolicyExpanded = !isPrivacyPolicyExpanded }
                    .padding(16.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Text("🛡️", fontSize = 20.sp)
                            Column {
                                Text(
                                    text = "PRIVACY POLICY & SAFE LAUNCH STATUS",
                                    color = CyberCyan,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.ExtraBold,
                                    letterSpacing = 0.5.sp
                                )
                                Text(
                                    text = "Google Play Store guidelines & key safety protocols",
                                    color = TextMuted,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Medium
                                )
                            }
                        }
                        Icon(
                            imageVector = if (isPrivacyPolicyExpanded) Icons.Default.KeyboardArrowUp else Icons.Default.KeyboardArrowDown,
                            contentDescription = "Expand Policy Details",
                            tint = CyberCyan,
                            modifier = Modifier.size(22.dp)
                        )
                    }

                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(SuccessGreen.copy(alpha = 0.1f), RoundedCornerShape(10.dp))
                            .border(BorderStroke(1.dp, SuccessGreen.copy(alpha = 0.3f)), RoundedCornerShape(10.dp))
                            .padding(12.dp)
                    ) {
                        Row(
                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("🛡️", fontSize = 16.sp)
                            Column(modifier = Modifier.weight(1f)) {
                                Text(
                                    text = "100% KEY EXTRACTION SECURE",
                                    color = SuccessGreen,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Black
                                )
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(
                                    text = "Hardcoded fallback API Keys are completely REMOVED from the source code. Custom secrets are dynamic and safe from decompilation extraction.",
                                    color = TextLight,
                                    fontSize = 9.5.sp,
                                    lineHeight = 14.sp
                                )
                            }
                        }
                    }

                    if (isPrivacyPolicyExpanded) {
                        Divider(color = GridSpace, thickness = 1.dp)

                        Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                            PrivacyDisclosureItem(
                                title = "1. VOICE & AUDIO PERMISSIONS",
                                text = "App uses audio recording exclusively for real-time speech-to-text translation and verbal saheli communication. Audio files are processed locally on-device and never stored or uploaded."
                            )
                            PrivacyDisclosureItem(
                                title = "2. NETWORK ACCESS & DATA USE",
                                text = "Internet permission is used strictly to interface with official secure API gateways (Google Gemini, OpenRouter, and Pollinations AI) to respond to user requests."
                            )
                            PrivacyDisclosureItem(
                                title = "3. NO THIRD-PARTY LOGS / TRACKING",
                                text = "There are zero background telemetry trackers or unapproved analytic SDKs. Your interaction histories are 100% private to you."
                            )
                            PrivacyDisclosureItem(
                                title = "4. SECURE ROOM DATABASE SANDBOX",
                                text = "All conversation histories, vocalizer archives, and application logs are saved locally on your device's isolated storage sandbox. Uninstalling the app completely wipes all data."
                            )
                            PrivacyDisclosureItem(
                                title = "5. HARDWARE INTERACTION (FLASH/CAMERA)",
                                text = "Hardware features (like the camera shutter and flashlight) are toggled safely using standard Android local system APIs, ensuring complete safety and user consent."
                            )

                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(CardSpace, RoundedCornerShape(10.dp))
                                    .border(BorderStroke(1.dp, CyberCyan.copy(alpha = 0.4f)), RoundedCornerShape(10.dp))
                                    .padding(10.dp)
                            ) {
                                Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Text(
                                        text = "📋 LAUNCH PREPARATION CHECKLIST",
                                        color = CyberCyan,
                                        fontSize = 9.5.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                    BulletPoint("Generate a Privacy Policy URL using these disclosures and add it to your Google Play Console.")
                                    BulletPoint("Configure your custom API Keys securely using the AI Studio Secrets panel.")
                                    BulletPoint("Ensure the application label matches the store asset name.")
                                }
                            }
                        }
                    } else {
                        Text(
                            text = "Tap to read full Google Play compliant disclosures & launch guidelines...",
                            color = CyberCyan,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }
        }

        // 🔄 SOFTWARE UPDATE CHECKER (LATEST VERSION CHECK)
        item {
            var isCheckingForUpdates by remember { mutableStateOf(false) }
            var updateStatus by remember { mutableStateOf("No active check. Current Version: v4.2.1 Stable") }
            var updateProgress by remember { mutableStateOf(0f) }
            val coroutineScope = rememberCoroutineScope()

            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(CardSpace, RoundedCornerShape(20.dp))
                    .border(
                        BorderStroke(1.dp, Brush.linearGradient(listOf(CyberCyan.copy(alpha = 0.3f), Color.Transparent))),
                        RoundedCornerShape(20.dp)
                    )
                    .padding(16.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Text("🔄", fontSize = 20.sp)
                            Column {
                                Text(
                                    text = "SOFTWARE UPDATE HUB",
                                    color = CyberCyan,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.ExtraBold,
                                    letterSpacing = 1.sp
                                )
                                Text(
                                    text = "Check and update to the latest system software versions",
                                    color = TextMuted,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Medium
                                )
                            }
                        }
                        Box(
                            modifier = Modifier
                                .background(CyberCyan.copy(alpha = 0.12f), RoundedCornerShape(8.dp))
                                .padding(horizontal = 8.dp, vertical = 4.dp)
                        ) {
                            Text(
                                text = "v4.2.1 Stable",
                                color = CyberCyan,
                                fontSize = 8.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }

                    if (isCheckingForUpdates) {
                        Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                            Text(updateStatus, color = TextLight, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            LinearProgressIndicator(
                                progress = { updateProgress },
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(6.dp)
                                    .clip(RoundedCornerShape(3.dp)),
                                color = CyberCyan,
                                trackColor = GridSpace
                            )
                        }
                    } else {
                        Text(updateStatus, color = TextMuted, fontSize = 10.sp, fontWeight = FontWeight.Medium)
                    }

                    Button(
                        onClick = {
                            if (!isCheckingForUpdates) {
                                isCheckingForUpdates = true
