                    val freeGb = bytesAvailable / (1024 * 1024 * 1024)
                    val totalGb = bytesTotal / (1024 * 1024 * 1024)
                    val usedGb = totalGb - freeGb
                    val progress = if (totalGb > 0) usedGb.toFloat() / totalGb else 0f
