    // Upload state variables
    var attachedToolFileName by remember { mutableStateOf<String?>(null) }
    var attachedToolFileSize by remember { mutableStateOf<String?>(null) }
    var attachedToolFileContentText by remember { mutableStateOf<String?>(null) }
    var attachedToolImageBytes by remember { mutableStateOf<ByteArray?>(null) }

    // Launchers
    val toolFilePickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetContent()
    ) { uri ->
        uri?.let {
            try {
                val name = getFileNameFromUri(context, it)
                val size = getFileSizeFromUri(context, it)
                val type = context.contentResolver.getType(it) ?: "application/octet-stream"
                val text = when {
                    name.endsWith(".pdf") -> {
                        val pdfDetails = extractPdfDetails(context, it)
                        val pdfText = pdfDetails.first
                        val pdfBmp = pdfDetails.second
                        if (pdfBmp != null) {
                            val stream = java.io.ByteArrayOutputStream()
                            pdfBmp.compress(android.graphics.Bitmap.CompressFormat.JPEG, 85, stream)
                            attachedToolImageBytes = stream.toByteArray()
                        }
                        val bytes = context.contentResolver.openInputStream(it)?.readBytes()
                        val scannedText = if (bytes != null) extractTextFromPdfBytes(bytes) else ""
                        if (scannedText.isNotBlank()) {
                            "$pdfText\n\n[SCANNED PDF TEXT CONTENT LAYER]:\n$scannedText"
                        } else {
                            pdfText
                        }
                    }
                    else -> extractFileText(context, it, name, type)
                }
                attachedToolFileName = name
                attachedToolFileSize = size
                attachedToolFileContentText = text
                android.widget.Toast.makeText(context, "Attached document: $name ($size)", android.widget.Toast.LENGTH_SHORT).show()
            } catch (e: Exception) {
                android.widget.Toast.makeText(context, "File upload error: ${e.message}", android.widget.Toast.LENGTH_SHORT).show()
            }
        }
    }

    val toolCameraLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.TakePicturePreview()
    ) { bitmap ->
        bitmap?.let {
            val stream = java.io.ByteArrayOutputStream()
            it.compress(android.graphics.Bitmap.CompressFormat.JPEG, 90, stream)
            attachedToolImageBytes = stream.toByteArray()
            android.widget.Toast.makeText(context, "Camera photo attached to tool successfully!", android.widget.Toast.LENGTH_SHORT).show()
        }
    }

    val toolImagePickerLauncher = rememberLauncherForActivityResult(
