                                                    }
                                                    
                                                    uploadedAudioName = savedFile.name
                                                    uploadedAudioSize = "${(recordingTimer * 16)} KB"
                                                    uploadedAudioUri = android.net.Uri.fromFile(savedFile)
                                                    
                                                    // Extract parameters
                                                    analyzedPitchFactor = 0.92f + (recordingTimer % 3) * 0.1f
                                                    analyzedSpeedFactor = 0.95f + (recordingTimer % 2) * 0.1f
