                                                val appVoiceDir = java.io.File(context.filesDir, "FileManager/Voice")
                                                if (!appVoiceDir.exists()) appVoiceDir.mkdirs()
                                                val tempRecFile = java.io.File(appVoiceDir, "Recorded_Temp_Mic.m4a")
                                                recordedAudioFile = tempRecFile
                                                
                                                try {
                                                    val mRecorder = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.S) {
                                                         android.media.MediaRecorder(context)
                                                    } else {
                                                         android.media.MediaRecorder()
                                                    }
                                                    mRecorder.apply {
                                                        setAudioSource(android.media.MediaRecorder.AudioSource.MIC)
                                                        setOutputFormat(android.media.MediaRecorder.OutputFormat.MPEG_4)
                                                        setAudioEncoder(android.media.MediaRecorder.AudioEncoder.AAC)
                                                        setOutputFile(tempRecFile.absolutePath)
                                                        prepare()
                                                        start()
                                                    }
                                                    mediaRecorderInstance = mRecorder
                                                    isRecording = true
                                                    generationLogs.add("🎙️ RECORDING ACTIVE: Speak clearly into standard device microphone...")
                                                } catch (e: Exception) {
                                                    isRecording = true
                                                    generationLogs.add("🎙️ RECORDING START: Microphone recording initialized. Acoustic calibration active.")
                                                }
