                                                        activeAudioPlayerItem = null // special flag representing uploaded audio track
                                                        isPlaying = true
                                                        playDuration = mp.duration
                                                        mp.setOnCompletionListener {
                                                            isPlaying = false
                                                            playPosition = 0
                                                        }
                                                    } catch (e: Exception) {
