                                                                tts.setSpeechRate(targetRate)
                                                                tts.setLanguage(java.util.Locale(profile.langCode, profile.countryCode))
                                                                tts.speak(profile.auditionText, android.speech.tts.TextToSpeech.QUEUE_FLUSH, null, "AuditionUTT")
                                                                
                                                                generationLogs.add("🎧 AUDITION: Speaking '${profile.name}' preview live at ${String.format("%.2f", targetPitch)}x pitch!")
                                                            }
