                                generationLogs.clear()
                                generationLogs.add("⚡ PHASE 1: Parsing entered prompt strings & structural semantics...")
                                
                                val pitchShiftToUse = if (voiceToVoiceMode && uploadedAudioUri != null) {
                                    analyzedPitchFactor * fineTunedPitch
                                } else if (!voiceToVoiceMode) {
                                    selectedVoiceProfileObj.pitch * fineTunedPitch
                                } else {
                                    when (websiteSelected) {
