                                }
                                val speedToUse = if (voiceToVoiceMode && uploadedAudioUri != null) {
                                    analyzedSpeedFactor * fineTunedRate
                                } else if (!voiceToVoiceMode) {
                                    selectedVoiceProfileObj.rate * fineTunedRate
                                } else {
                                    when (websiteSelected) {
                                        0 -> fishSpeed * fineTunedRate
                                        2 -> soundToolsSpeakerRate * fineTunedRate
                                        else -> 1.0f * fineTunedRate
                                    }
                                }
                                
                                coroutineScope.launch(Dispatchers.IO) {
                                    kotlinx.coroutines.delay(800)
                                    generationProgress = 0.25f
                                    if (voiceToVoiceMode && uploadedAudioUri != null) {
                                        generationLogs.add("🎙️ PHASE 2: Fetching instant speaker features from: $uploadedAudioName")
                                        generationLogs.add("🧬 TIMBRE MATCHER: Extracting match waves ($analyzedGenderSignature)...")
                                    } else {
                                        generationLogs.add("🎙️ PHASE 2: Fetching instant speaker features from input anchors...")
                                    }
                                    
                                    kotlinx.coroutines.delay(1000)
                                    generationProgress = 0.55f
                                    val activeWebsiteName = if (voiceToVoiceMode && uploadedAudioUri != null) {
                                        "Voice-to-Voice Pipeline Sync (Pitch: ${analyzedPitchFactor}x, Rate: ${analyzedSpeedFactor}x)"
