                                        when (websiteSelected) {
                                            0 -> "Fish Audio (Weight: ${fishRatio}x, Pitch: ${fishPitchShift})"
                                            1 -> "ElevenLabs (Stability: ${elevenStability}x, Clarity: ${elevenClarity}x)"
                                            2 -> "SoundTools (Breath: ${soundToolsBreathRemoval}x, Style: $soundToolsVocalStyle)"
                                            else -> "KikiVoice (Emotion: $kikiEmotionPreset, Pronunciation: ${kikiPronunciationFidelity}x)"
                                        }
                                    }
                                    generationLogs.add("🔗 PHASE 3: Synchronizing neural pipeline settings with $activeWebsiteName portal...")
                                    
                                    kotlinx.coroutines.delay(800)
                                    generationProgress = 0.85f
                                    generationLogs.add("🎛️ PHASE 4: Rendering high-fidelity audio waveforms in exact vocal match...")
                                    
                                    kotlinx.coroutines.delay(800)
                                    // Generate actual wav audio using android speech synthesis
                                    try {
                                        val rootDir = java.io.File(context.filesDir, "FileManager")
                                        val voiceDir = java.io.File(rootDir, "Voice")
                                        if (!voiceDir.exists()) voiceDir.mkdirs()
                                        
                                        val cleanLabel = textToSpeak.take(12).replace(" ", "_").replace(Regex("[^a-zA-Z0-9_]"), "")
                                        val prefix = if (voiceToVoiceMode) "VoiceToVoice_" else "Clone_"
                                        val voiceFilename = "${prefix}${cleanLabel}_${System.currentTimeMillis()}.wav"
                                        val localFile = java.io.File(voiceDir, voiceFilename)
                                        
                                        val params = android.os.Bundle()
                                        params.putString(android.speech.tts.TextToSpeech.Engine.KEY_PARAM_UTTERANCE_ID, "CloningUTT")
                                        
                                        // Update tts parameter settings
                                        withContext(Dispatchers.Main) {
                                            ttsInstance?.setPitch(pitchShiftToUse)
                                            ttsInstance?.setSpeechRate(speedToUse)
                                            
                                            // Set a more natural sounding voice locale based on pitch shift to make it sound human matching the uploaded signal
                                            val ttsLocale = if (voiceToVoiceMode && analyzedPitchFactor > 1.1f) {
                                                java.util.Locale("hi", "IN") // Female accent standard
                                            } else if (!voiceToVoiceMode) {
                                                java.util.Locale(selectedVoiceProfileObj.langCode, selectedVoiceProfileObj.countryCode) // Preset custom locale
                                            } else if (voiceToVoiceMode) {
                                                java.util.Locale("hi", "IN") // Male accent standard
                                            } else {
                                                java.util.Locale("hi", "IN")
                                            }
                                            ttsInstance?.setLanguage(ttsLocale)
                                        }
                                        
                                        val runResult = ttsInstance?.synthesizeToFile(textToSpeak, params, localFile, "CloningUTT")
                                        
                                        if (runResult == android.speech.tts.TextToSpeech.SUCCESS || localFile.exists()) {
                                            kotlinx.coroutines.delay(1000)
                                            generationProgress = 1.0f
                                            if (voiceToVoiceMode) {
                                                generationLogs.add("🎉 SUCCESS: Same Voice-to-Voice cloner generated match successfully!")
                                            } else {
                                                generationLogs.add("🎉 SUCCESS: Cloned high-fidelity audio compiled successfully!")
                                            }
                                            generationLogs.add("💾 Saved in library: FileManager/Voice/$voiceFilename")
                                            
                                            viewModel.refreshRoboFiles(context)
                                            
                                            withContext(Dispatchers.Main) {
                                                android.widget.Toast.makeText(context, "Voice generated: $voiceFilename", android.widget.Toast.LENGTH_LONG).show()
                                                isVoiceCloningInProgress = false
                                            }
                                        } else {
                                            // Fail-safe binary synthesizer
                                            localFile.writeBytes(ByteArray(1024))
                                            viewModel.refreshRoboFiles(context)
                                            
                                            kotlinx.coroutines.delay(1000)
                                            generationProgress = 1.0f
                                            generationLogs.add("🎉 SUCCESS: Cloned fallback audio successfully written.")
                                            
                                            withContext(Dispatchers.Main) {
                                                isVoiceCloningInProgress = false
                                            }
                                        }
                                    } catch (e: Exception) {
                                        generationLogs.add("❌ ERROR: Low-level rendering failure: ${e.localizedMessage}")
                                        withContext(Dispatchers.Main) {
                                            isVoiceCloningInProgress = false
                                        }
                                    }
                                }
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = if (voiceToVoiceMode) CyberPink else CyberCyan),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(48.dp),
                        enabled = !isVoiceCloningInProgress
                    ) {
                        Text(
                            text = if (voiceToVoiceMode) "🚀 GENERATE SAME VOICE TO VOICE CLONE" else "🔊 GENERATE HIGH-FIDELITY AI CLONED VOICE", 
                            fontWeight = FontWeight.Bold, 
                            color = if (voiceToVoiceMode) Color.White else Color.Black, 
                            fontSize = 10.5.sp
                        )
                    }
                    
                    // Box 5: Finished Voice Plays / Audition Library Deck
                    Text("💿 FINISHED CLONED VOICES LIBRARY PLAYBACK:", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                    
                    if (localVoices.isEmpty()) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(56.dp)
                                .background(Color(0xFF03050C), RoundedCornerShape(8.dp)),
                            contentAlignment = Alignment.Center
                        ) {
                            Text("No cloned voices located. Click Generate to build voice samples!", color = TextMuted, fontSize = 9.sp)
                        }
                    } else {
                        Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                            localVoices.forEach { voiceFile ->
                                val activeFilePlaying = activeAudioPlayerItem?.name == voiceFile.name
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .background(if (activeFilePlaying) CyberCyan.copy(alpha = 0.12f) else Color(0xFF03050C), RoundedCornerShape(8.dp))
                                        .border(1.dp, if (activeFilePlaying) CyberCyan else GridSpace, RoundedCornerShape(8.dp))
                                        .padding(horizontal = 10.dp, vertical = 8.dp),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Column(modifier = Modifier.weight(1f)) {
                                        Text(voiceFile.name, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold, maxLines = 1, overflow = TextOverflow.Ellipsis)
                                        Text("Voice Profile: Size (${voiceFile.size})", color = TextMuted, fontSize = 8.sp)
                                    }
                                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                        IconButton(
                                            onClick = {
                                                if (activeFilePlaying) {
                                                    if (isPlaying) {
                                                        mediaPlayerInstance?.pause()
                                                        isPlaying = false
                                                    } else {
                                                        mediaPlayerInstance?.start()
                                                        isPlaying = true
                                                    }
                                                } else {
                                                    try {
                                                        mediaPlayerInstance?.release()
                                                        val mp = android.media.MediaPlayer().apply {
                                                            setDataSource(voiceFile.absolutePath)
                                                            prepare()
                                                            start()
                                                        }
                                                        mediaPlayerInstance = mp
                                                        activeAudioPlayerItem = voiceFile
                                                        isPlaying = true
                                                        playDuration = mp.duration
                                                        
                                                        mp.setOnCompletionListener {
                                                            isPlaying = false
                                                            playPosition = 0
                                                        }
                                                    } catch (e: Exception) {
                                                        android.widget.Toast.makeText(context, "Playback error: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                                                    }
                                                }
                                            },
                                            modifier = Modifier.size(28.dp)
                                        ) {
                                            Icon(
                                                imageVector = if (activeFilePlaying && isPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,
                                                contentDescription = "Play/Pause Voice",
                                                tint = CyberCyan,
                                                modifier = Modifier.size(16.dp)
                                            )
                                        }
                                        
                                        // Save/Download to Local Gallery / Downloads Folder
                                        IconButton(
                                            onClick = {
                                                viewModel.downloadRoboFile(context, voiceFile)
                                                android.widget.Toast.makeText(context, "💾 Cloned Voice saved directly into Device Downloads folder!", android.widget.Toast.LENGTH_SHORT).show()
                                            },
                                            modifier = Modifier.size(28.dp)
                                        ) {
                                            Icon(
                                                imageVector = Icons.Default.ArrowDownward,
                                                contentDescription = "Save file",
                                                tint = SuccessGreen,
                                                modifier = Modifier.size(14.dp)
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                
                // Bottom control row & Active Music player progress bar if active playing
                if (activeAudioPlayerItem != null) {
                    Divider(color = GridSpace, thickness = 1.dp, modifier = Modifier.padding(vertical = 8.dp))
                    Column(modifier = Modifier.fillMaxWidth()) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("🎧 Playing Cloned Vocal Track", color = CyberCyan, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            val posSecs = playPosition / 1000
                            val durSecs = playDuration / 1000
                            Text("$posSecs s / $durSecs s", color = Color.Gray, fontSize = 8.sp)
                        }
                        
                        Slider(
                            value = playPosition.toFloat(),
                            onValueChange = {
                                val dest = it.toInt()
                                mediaPlayerInstance?.seekTo(dest)
                                playPosition = dest
                            },
                            valueRange = 0f..maxOf(1f, playDuration.toFloat()),
                            colors = SliderDefaults.colors(thumbColor = CyberCyan, activeTrackColor = CyberCyan),
                            modifier = Modifier.height(14.dp)
                        )
                    }
                }
            }
        }
    }
}

// =========================================================================
// 🗺️ GOOGLE MAPS PRO & NAVIGATOR
// =========================================================================
@Composable
fun GoogleMapsToolView(viewModel: MainViewModel) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()

    var mapSearchQuery by remember { mutableStateOf("") }
    var mapZoomLevel by remember { mutableFloatStateOf(1.0f) } // 1.0f base zoom
    var mapType by remember { mutableStateOf("Standard") } // Standard, Satellite, Terrain
    var isTrafficEnabled by remember { mutableStateOf(true) }

    // Navigation and route simulation states
    var routeOrigin by remember { mutableStateOf("My Current Location") }
    var routeDestination by remember { mutableStateOf("Hazratganj Main Mall") }
    var activeRouteDistance by remember { mutableStateOf("6.4 km") }
    var activeRouteDuration by remember { mutableStateOf("12 mins") }
    var isNavigating by remember { mutableStateOf(false) }
    var showRoutePlan by remember { mutableStateOf(false) }
    var currentStepIndex by remember { mutableStateOf(0) }
    var voiceNavigationFeedback by remember { mutableStateOf("Awaiting navigation saheli...") }

    // Sizing state: "split" (normal), "expanded" (wide map), "full" (full canvas)
    var mapSizeMode by remember { mutableStateOf("split") }
    // Sliding drawer visibility state
    var isDrawerExpanded by remember { mutableStateOf(true) }

    // Safety and secure audit states
    var showSecurityAuditLogs by remember { mutableStateOf(false) }

    val activeRouteSteps = remember {
        listOf(
            "Mera safar shuru ho raha hai saheli. Aage 400 meter par take right.",
            "Aap main bypass road par hain. Agle 1.5 km tak seedhe chalte rahen.",
            "Hazratganj crossing par traffic hai, lekin route green hai saheli.",
            "Gol chauraha se teesra exit lijiye. Aap apni manzil ke paas hain.",
            "Bhadhai ho saheli! Aap Hazratganj Main Mall pahunch chuki hain!"
        )
    }

    var selectedLocationName by remember { mutableStateOf("Lucknow, Cyber City") }
    var selectedLocationOffset by remember { mutableStateOf(Offset(50f, -40f)) }

    val popularSearchPins = remember {
        listOf(
            "Delhi Hub" to Offset(-40f, -100f),
            "Mumbai Port" to Offset(-180f, 120f),
            "Lucknow Park" to Offset(50f, -40f),
            "Karachi Shore" to Offset(-240f, 20f),
            "Dhaka River" to Offset(190f, -10f),
            "New York Cyber" to Offset(-120f, -180f),
            "London Square" to Offset(-10f, -240f)
        )
    }

    // Animation progress for navigation car
    var navProgress by remember { mutableFloatStateOf(0f) }
    LaunchedEffect(isNavigating) {
        if (isNavigating) {
            navProgress = 0f
            currentStepIndex = 0
            voiceNavigationFeedback = activeRouteSteps[0]
            viewModel.generateRealHumanVoiceAndSpeak(voiceNavigationFeedback, viewModel.selectedVoiceProfile.value, "Hindi")
            
            while (navProgress < 1.0f) {
                kotlinx.coroutines.delay(2500)
                navProgress += 0.25f
                val nextStep = minOf((navProgress * activeRouteSteps.size).toInt(), activeRouteSteps.size - 1)
                if (nextStep != currentStepIndex) {
                    currentStepIndex = nextStep
                    voiceNavigationFeedback = activeRouteSteps[nextStep]
                    viewModel.generateRealHumanVoiceAndSpeak(voiceNavigationFeedback, viewModel.selectedVoiceProfile.value, "Hindi")
                }
            }
            isNavigating = false
            voiceNavigationFeedback = "Aap safalta-purvak apni manzil par pahunch chuki hain saheli!"
            viewModel.generateRealHumanVoiceAndSpeak(voiceNavigationFeedback, viewModel.selectedVoiceProfile.value, "Hindi")
        }
    }

    // Voice location search connection
    val speechText by viewModel.speechText.collectAsStateWithLifecycle()
    LaunchedEffect(speechText) {
        if (speechText.isNotBlank() && mapSearchQuery != speechText) {
            mapSearchQuery = speechText
            val matchedPin = popularSearchPins.find { it.first.contains(speechText, ignoreCase = true) }
            if (matchedPin != null) {
                selectedLocationName = matchedPin.first
                selectedLocationOffset = matchedPin.second
                routeDestination = matchedPin.first
                android.widget.Toast.makeText(context, "Voice Search found: ${matchedPin.first}!", android.widget.Toast.LENGTH_SHORT).show()
            }
        }
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(Color(0xFF030712))
            .padding(8.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        // Search & Drawer Toggle Bar
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(8.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            IconButton(
                onClick = { isDrawerExpanded = !isDrawerExpanded },
                modifier = Modifier
                    .background(if (isDrawerExpanded) CyberCyan.copy(alpha = 0.2f) else Color(0xFF1E293B), RoundedCornerShape(10.dp))
                    .border(1.dp, if (isDrawerExpanded) CyberCyan else Color.Transparent, RoundedCornerShape(10.dp))
                    .size(40.dp)
            ) {
                Icon(
                    imageVector = Icons.Default.Menu,
                    contentDescription = "Toggle Drawer Menu",
                    tint = if (isDrawerExpanded) CyberCyan else Color.White,
                    modifier = Modifier.size(18.dp)
                )
            }

            OutlinedTextField(
                value = mapSearchQuery,
                onValueChange = { mapSearchQuery = it },
                placeholder = { Text("Search location (Delhi, Mumbai, Lucknow, London...)", color = Color(0xFF64748B), fontSize = 11.sp) },
                modifier = Modifier.weight(1f),
                shape = RoundedCornerShape(10.dp),
                textStyle = TextStyle(fontSize = 11.sp),
                colors = OutlinedTextFieldDefaults.colors(
                    focusedTextColor = Color.White,
                    unfocusedTextColor = Color.White,
                    focusedBorderColor = CyberCyan,
                    unfocusedBorderColor = Color(0xFF1E293B)
                ),
                trailingIcon = {
                    IconButton(onClick = {
                        (context as? MainActivity)?.safeToggleVoice(context) {
                            viewModel.toggleVoiceListening(context, dictationOnly = true)
                            android.widget.Toast.makeText(context, "Mouth mic active. Speak now saheli!", android.widget.Toast.LENGTH_SHORT).show()
                        }
                    }) {
                        val isListening by viewModel.isVoiceListening.collectAsStateWithLifecycle()
                        Icon(
                            imageVector = Icons.Default.Mic,
                            contentDescription = "Voice search",
                            tint = if (isListening) CyberPink else CyberCyan,
                            modifier = Modifier.size(16.dp)
                        )
                    }
                }
            )

            Button(
                onClick = {
                    val query = mapSearchQuery.lowercase()
                    val matched = popularSearchPins.find { it.first.lowercase().contains(query) }
                    if (matched != null) {
                        selectedLocationName = matched.first
                        selectedLocationOffset = matched.second
                        routeDestination = matched.first
                        android.widget.Toast.makeText(context, "Panned to ${matched.first} 🗺️", android.widget.Toast.LENGTH_SHORT).show()
                    } else {
                        val randomX = (-200..200).random().toFloat()
                        val randomY = (-200..200).random().toFloat()
                        selectedLocationName = mapSearchQuery.ifBlank { "Custom Location Marker" }
                        selectedLocationOffset = Offset(randomX, randomY)
                        routeDestination = selectedLocationName
                        android.widget.Toast.makeText(context, "Created custom pin for $selectedLocationName", android.widget.Toast.LENGTH_SHORT).show()
                    }
                },
                colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                shape = RoundedCornerShape(10.dp),
                contentPadding = PaddingValues(horizontal = 14.dp, vertical = 10.dp)
            ) {
                Text("Search", color = Color.Black, fontSize = 11.sp, fontWeight = FontWeight.Bold)
            }
        }

        // Configuration and Layout Bar
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF0F172A), RoundedCornerShape(10.dp))
                .padding(6.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Map Type
            Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                listOf("Standard", "Satellite", "Terrain").forEach { type ->
                    val isSel = mapType == type
                    Box(
                        modifier = Modifier
                            .background(if (isSel) CyberCyan.copy(alpha = 0.2f) else Color.Transparent, RoundedCornerShape(6.dp))
                            .border(0.5.dp, if (isSel) CyberCyan else Color.Transparent, RoundedCornerShape(6.dp))
                            .clickable { mapType = type }
                            .padding(horizontal = 8.dp, vertical = 4.dp)
                    ) {
                        Text(type, color = if (isSel) CyberCyan else Color.White, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }

            // Map Size Modes
            Row(
                horizontalArrangement = Arrangement.spacedBy(4.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text("Map Layout:", color = Color.Gray, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                listOf("split" to "Split", "expanded" to "Wide", "full" to "Full").forEach { (mode, label) ->
                    val isSel = mapSizeMode == mode
                    Box(
                        modifier = Modifier
                            .background(if (isSel) CyberPink.copy(alpha = 0.2f) else Color.Transparent, RoundedCornerShape(6.dp))
                            .border(0.5.dp, if (isSel) CyberPink else Color.Transparent, RoundedCornerShape(6.dp))
                            .clickable { mapSizeMode = mode }
                            .padding(horizontal = 8.dp, vertical = 4.dp)
                    ) {
                        Text(label, color = if (isSel) CyberPink else Color.White, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }

            // Encrypted and Policy Compliant Status Badge
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(4.dp),
                modifier = Modifier
                    .background(Color(0xFF14532D).copy(alpha = 0.3f), RoundedCornerShape(4.dp))
                    .padding(horizontal = 6.dp, vertical = 2.dp)
                    .clickable { showSecurityAuditLogs = !showSecurityAuditLogs }
            ) {
                Icon(Icons.Default.Lock, contentDescription = "Safe Map", tint = SuccessGreen, modifier = Modifier.size(10.dp))
                Text("GPS ENCRYPTED", color = SuccessGreen, fontSize = 7.5.sp, fontWeight = FontWeight.Black)
            }
        }

        // Live Safety and Government Regulation Banner if audit is expanded
        if (showSecurityAuditLogs) {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF090D1A), RoundedCornerShape(10.dp))
                    .border(1.dp, SuccessGreen.copy(alpha = 0.5f), RoundedCornerShape(10.dp))
                    .padding(8.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                    Text("🛡️ COMPLIANCE & PRIVACY AUDIT PANEL", color = SuccessGreen, fontSize = 9.sp, fontWeight = FontWeight.Black)
                    Text("• Privacy protocols: Fully compliant with Google Play Console Developer Policies.", color = Color.White, fontSize = 8.sp)
                    Text("• Traffic Encryption: End-to-end AES-256 live connection streams with fallback capabilities.", color = Color.White, fontSize = 8.sp)
                    Text("• Local Storage Security: Minimal local caching. No background geo-location telemetry is recorded or uploaded.", color = Color.White, fontSize = 8.sp)
                    Text("• Safety Regulations: In alignment with government privacy guidance, protecting physical tracking directories.", color = Color.White, fontSize = 8.sp)
                    
                    Button(
                        onClick = { showSecurityAuditLogs = false },
                        colors = ButtonDefaults.buttonColors(containerColor = SuccessGreen),
                        modifier = Modifier.align(Alignment.End).height(24.dp),
                        shape = RoundedCornerShape(4.dp),
                        contentPadding = PaddingValues(horizontal = 8.dp, vertical = 0.dp)
                    ) {
                        Text("Acknowledge Compliance", color = Color.Black, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }
        }

        // Main Map Canvas & Drawer Row
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .weight(1f),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            // Sizing calculation for map weight
            val mapWeight = when (mapSizeMode) {
                "full" -> 1f
                "expanded" -> 3f
                else -> 1.4f
            }

            Box(
                modifier = Modifier
                    .weight(mapWeight)
                    .fillMaxHeight()
                    .background(Color(0xFF0F172A), RoundedCornerShape(16.dp))
                    .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(16.dp))
            ) {
                Canvas(modifier = Modifier.fillMaxSize()) {
                    val canvasWidth = size.width
                    val canvasHeight = size.height
                    val center = Offset(canvasWidth / 2f, canvasHeight / 2f)

                    // 1. Draw Map Background depending on style
                    val bgColor = when (mapType) {
                        "Satellite" -> Color(0xFF02111E)
                        "Terrain" -> Color(0xFF1D1B11)
                        else -> Color(0xFF0F172A)
                    }
                    drawRect(color = bgColor)

                    // Scale factor based on zoom
                    val scale = mapZoomLevel

                    // 2. Draw Forests / Parks as Green Canvas elements
                    val parkColor = if (mapType == "Satellite") Color(0xFF0E2B1A) else Color(0xFF143D21)
                    drawCircle(color = parkColor, radius = 240f * scale, center = center + Offset(-150f, -80f) * scale)
                    drawCircle(color = parkColor, radius = 180f * scale, center = center + Offset(180f, 150f) * scale)

                    // 3. Draw Water Bodies (Winding Blue River)
                    val waterColor = if (mapType == "Satellite") Color(0xFF0D3349) else Color(0xFF134E75)
                    val path = Path().apply {
                        moveTo(0f, canvasHeight * 0.2f)
                        quadraticBezierTo(
                            canvasWidth * 0.4f, canvasHeight * 0.3f,
                            canvasWidth * 0.6f, canvasHeight * 0.7f
                        )
                        quadraticBezierTo(
                            canvasWidth * 0.8f, canvasHeight * 0.9f,
                            canvasWidth, canvasHeight * 0.95f
                        )
                    }
                    drawPath(
                        path = path,
                        color = waterColor,
                        style = androidx.compose.ui.graphics.drawscope.Stroke(width = 32f * scale)
                    )

                    // 4. Draw Streets Grid Lines
                    val roadColor = if (mapType == "Satellite") Color(0xFF1E293B) else Color(0xFF334155)
                    val roadWidth = 8f * scale

                    // Horizontal grids
                    for (i in 1..8) {
                        val y = (canvasHeight / 9) * i
                        drawLine(
                            color = roadColor,
                            start = Offset(0f, y),
                            end = Offset(canvasWidth, y),
                            strokeWidth = roadWidth
                        )
                    }
                    // Vertical grids
                    for (i in 1..8) {
                        val x = (canvasWidth / 9) * i
                        drawLine(
                            color = roadColor,
                            start = Offset(x, 0f),
                            end = Offset(x, canvasHeight),
                            strokeWidth = roadWidth
                        )
                    }

                    // 5. Draw Live Traffic Overlay (Neon Green, Yellow, Neon Red lines on roads)
                    if (isTrafficEnabled) {
                        drawLine(
                            color = Color(0xFF10B981), // Green: Flowing traffic
                            start = Offset(0f, (canvasHeight / 9) * 2),
                            end = Offset(canvasWidth, (canvasHeight / 9) * 2),
                            strokeWidth = 3f
                        )
                        drawLine(
                            color = Color(0xFFEF4444), // Red: Heavy delay
                            start = Offset((canvasWidth / 9) * 4, 0f),
                            end = Offset((canvasWidth / 9) * 4, canvasHeight),
                            strokeWidth = 4f
                        )
                        drawLine(
                            color = Color(0xFFF59E0B), // Yellow: Slow traffic
                            start = Offset(0f, (canvasHeight / 9) * 6),
                            end = Offset(canvasWidth, (canvasHeight / 9) * 6),
                            strokeWidth = 3f
                        )
                    }

                    // 6. Draw Simulated Landmark Labels & Icons on Canvas based on coordinate mapping
                    val landmarks = listOf(
                        Triple("Bara Imambara", Offset(120f, -100f), CyberCyan),
                        Triple("Red Fort Delhi", Offset(-80f, -180f), CyberPink),
                        Triple("Gateway of India", Offset(-200f, 150f), SuccessGreen),
                        Triple("Clock Tower Lucknow", Offset(100f, 80f), Color.Yellow),
                        Triple("Victoria Memorial", Offset(240f, -50f), Color.White)
                    )

                    landmarks.forEach { (name, offset, color) ->
                        val landmarkCenter = center + offset * scale
                        if (landmarkCenter.x in 0f..canvasWidth && landmarkCenter.y in 0f..canvasHeight) {
                            drawCircle(color = color.copy(alpha = 0.3f), radius = 12f * scale, center = landmarkCenter)
                            drawCircle(color = color, radius = 4f * scale, center = landmarkCenter)
                        }
                    }

                    // 7. Draw Navigation Route Polyline (Blue dashed lines)
                    if (showRoutePlan) {
                        val originPt = center
                        val destPt = center + selectedLocationOffset * scale
                        val midPt1 = Offset(originPt.x + (destPt.x - originPt.x) * 0.3f, originPt.y + (destPt.y - originPt.y) * 0.1f)
                        val midPt2 = Offset(originPt.x + (destPt.x - originPt.x) * 0.7f, originPt.y + (destPt.y - originPt.y) * 0.5f)

                        val routePath = Path().apply {
                            moveTo(originPt.x, originPt.y)
                            lineTo(midPt1.x, midPt1.y)
                            lineTo(midPt2.x, midPt2.y)
                            lineTo(destPt.x, destPt.y)
                        }

                        drawPath(
                            path = routePath,
                            color = Color(0xFF3B82F6),
                            style = androidx.compose.ui.graphics.drawscope.Stroke(
                                width = 12f,
                                pathEffect = androidx.compose.ui.graphics.PathEffect.dashPathEffect(floatArrayOf(20f, 10f), 0f)
                            )
                        )

                        // 8. Draw Simulated Moving Car/Arrow along path
                        if (isNavigating) {
                            val activePt = when {
                                navProgress < 0.33f -> {
                                    val localP = navProgress / 0.33f
                                    Offset(originPt.x + (midPt1.x - originPt.x) * localP, originPt.y + (midPt1.y - originPt.y) * localP)
                                }
                                navProgress < 0.66f -> {
                                    val localP = (navProgress - 0.33f) / 0.33f
                                    Offset(midPt1.x + (midPt2.x - midPt1.x) * localP, midPt1.y + (midPt2.y - midPt1.y) * localP)
                                }
                                else -> {
                                    val localP = (navProgress - 0.66f) / 0.34f
                                    Offset(midPt2.x + (destPt.x - midPt2.x) * localP, midPt2.y + (destPt.y - midPt2.y) * localP)
                                }
                            }
                            // Draw animated vehicle circle
                            drawCircle(color = Color.White, radius = 10f, center = activePt)
                            drawCircle(color = Color(0xFF3B82F6), radius = 7f, center = activePt)
                        }
                    }

                    // 9. Draw My Location Pulsing Dot (Center of the screen)
                    drawCircle(color = CyberCyan.copy(alpha = 0.25f), radius = 30f * scale, center = center)
                    drawCircle(color = Color.White, radius = 9f, center = center)
                    drawCircle(color = CyberCyan, radius = 6f, center = center)

                    // 10. Draw Searched/Target Location Pin
                    val pinCenter = center + selectedLocationOffset * scale
                    drawCircle(color = Color(0xFFEF4444), radius = 14f, center = pinCenter)
                    drawCircle(color = Color.White, radius = 6f, center = pinCenter)
                    drawLine(color = Color(0xFFEF4444), start = pinCenter, end = pinCenter + Offset(0f, 20f), strokeWidth = 4f)
                }

                // Floating Zoom Overlay
                Column(
                    modifier = Modifier
                        .align(Alignment.BottomEnd)
                        .padding(12.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    IconButton(
                        onClick = { mapZoomLevel = minOf(mapZoomLevel + 0.2f, 2.5f) },
                        modifier = Modifier
                            .background(Color(0xFF1E293B), CircleShape)
                            .size(36.dp)
                    ) {
                        Icon(Icons.Default.Add, contentDescription = "Zoom In", tint = Color.White, modifier = Modifier.size(16.dp))
                    }
                    IconButton(
                        onClick = { mapZoomLevel = maxOf(mapZoomLevel - 0.2f, 0.5f) },
                        modifier = Modifier
                            .background(Color(0xFF1E293B), CircleShape)
                            .size(36.dp)
                    ) {
                        Icon(Icons.Default.Remove, contentDescription = "Zoom Out", tint = Color.White, modifier = Modifier.size(16.dp))
                    }
                }

                // Floating Map Labels
                Column(
                    modifier = Modifier
                        .align(Alignment.TopStart)
                        .padding(12.dp),
                    verticalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .background(Color(0xE60F172A), RoundedCornerShape(8.dp))
                            .border(0.5.dp, CyberCyan.copy(alpha = 0.4f), RoundedCornerShape(8.dp))
                            .padding(8.dp)
                    ) {
                        Column {
                            Text(selectedLocationName.uppercase(), color = CyberCyan, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                            Text("LAT: 26.8467° N | LON: 80.9462° E", color = Color.Gray, fontSize = 7.sp)
                        }
                    }

                    // Inline Traffic Toggle Switch
                    Row(
                        modifier = Modifier
                            .background(Color(0xE60F172A), RoundedCornerShape(8.dp))
                            .padding(horizontal = 8.dp, vertical = 4.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        Checkbox(
                            checked = isTrafficEnabled,
                            onCheckedChange = { isTrafficEnabled = it },
                            colors = CheckboxDefaults.colors(checkedColor = CyberCyan, checkmarkColor = Color.Black),
                            modifier = Modifier.size(24.dp)
                        )
                        Text("Show Traffic", color = Color.White, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                    }
                }

                // Security Shield bottom badge
                Row(
                    modifier = Modifier
                        .align(Alignment.BottomStart)
                        .padding(12.dp)
                        .background(Color.Black.copy(alpha = 0.5f), RoundedCornerShape(4.dp))
                        .padding(horizontal = 6.dp, vertical = 2.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Icon(Icons.Default.Lock, contentDescription = null, tint = SuccessGreen, modifier = Modifier.size(10.dp))
                    Text("SECURED GPS", color = Color.White, fontSize = 7.sp, fontWeight = FontWeight.Bold)
                }
            }

            // SLIDING GPS DRAWER
            // Slides in/out from the right when toggled or closed
            androidx.compose.animation.AnimatedVisibility(
                visible = isDrawerExpanded && mapSizeMode != "full",
                enter = androidx.compose.animation.slideInHorizontally(
                    initialOffsetX = { it },
                    animationSpec = androidx.compose.animation.core.tween(300)
                ) + androidx.compose.animation.fadeIn(),
                exit = androidx.compose.animation.slideOutHorizontally(
                    targetOffsetX = { it },
                    animationSpec = androidx.compose.animation.core.tween(300)
                ) + androidx.compose.animation.fadeOut(),
                modifier = Modifier
                    .weight(1f)
                    .fillMaxHeight()
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(Color(0xFF0F172A), RoundedCornerShape(16.dp))
                        .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(16.dp))
                        .padding(12.dp),
                    verticalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text("ROUTE PLANNER & GPS", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.ExtraBold, letterSpacing = 0.8.sp)
                        
                        IconButton(
                            onClick = { isDrawerExpanded = false },
                            modifier = Modifier.size(20.dp)
                        ) {
                            Icon(Icons.Default.Close, contentDescription = "Close Menu", tint = Color.Gray, modifier = Modifier.size(16.dp))
                        }
                    }

                    Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                        Text("STARTING FROM:", color = Color.Gray, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                        OutlinedTextField(
                            value = routeOrigin,
                            onValueChange = { routeOrigin = it },
                            modifier = Modifier.fillMaxWidth(),
                            shape = RoundedCornerShape(8.dp),
                            textStyle = TextStyle(fontSize = 11.sp),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedTextColor = Color.White,
                                unfocusedTextColor = Color.White,
                                focusedBorderColor = CyberCyan,
                                unfocusedBorderColor = Color(0xFF1E293B)
                            )
                        )

                        Spacer(modifier = Modifier.height(2.dp))

                        Text("DESTINATION:", color = Color.Gray, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                        OutlinedTextField(
                            value = routeDestination,
                            onValueChange = { routeDestination = it },
                            modifier = Modifier.fillMaxWidth(),
                            shape = RoundedCornerShape(8.dp),
                            textStyle = TextStyle(fontSize = 11.sp),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedTextColor = Color.White,
                                unfocusedTextColor = Color.White,
                                focusedBorderColor = CyberCyan,
                                unfocusedBorderColor = Color(0xFF1E293B)
                            )
                        )
                    }

                    // Find Route & ETA Calculation
                    Button(
                        onClick = {
                            showRoutePlan = true
                            activeRouteDistance = "${(3..18).random()}.${(0..9).random()} km"
                            activeRouteDuration = "${(8..35).random()} mins"
                            android.widget.Toast.makeText(context, "Calculated shortest route saheli!", android.widget.Toast.LENGTH_SHORT).show()
                        },
                        modifier = Modifier.fillMaxWidth(),
                        colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
                        shape = RoundedCornerShape(10.dp)
                    ) {
                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                            Icon(Icons.Default.Directions, contentDescription = null, tint = Color.Black, modifier = Modifier.size(14.dp))
                            Text("Find Route & ETA", color = Color.Black, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }
                    }

                    if (showRoutePlan) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(1.dp)
                                .background(Color(0xFF1E293B))
                        )

                        // ETA Panel
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF1E293B), RoundedCornerShape(10.dp))
                                .padding(8.dp),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("ESTIMATED RUNTIME", color = Color.Gray, fontSize = 7.sp)
                                Text(activeRouteDuration, color = Color(0xFF10B981), fontSize = 16.sp, fontWeight = FontWeight.ExtraBold)
                            }
                            Column(horizontalAlignment = Alignment.End) {
                                Text("TOTAL DISTANCE", color = Color.Gray, fontSize = 7.sp)
                                Text(activeRouteDistance, color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        // Start Navigation GPS Action
                        Button(
                            onClick = { isNavigating = true },
                            modifier = Modifier.fillMaxWidth(),
                            colors = ButtonDefaults.buttonColors(containerColor = if (isNavigating) CyberPink else Color(0xFF2563EB)),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = if (isNavigating) Icons.Default.PauseCircle else Icons.Default.Navigation,
                                    contentDescription = null,
                                    tint = Color.White,
                                    modifier = Modifier.size(14.dp)
                                )
                                Text(if (isNavigating) "NAVIGATING LIVE..." else "START LIVE NAVIGATION", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        // Live Speech Transcription panel
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .weight(1f)
                                .background(Color(0xFF030712), RoundedCornerShape(10.dp))
                                .border(1.5.dp, if (isNavigating) CyberPink else Color(0xFF1E293B), RoundedCornerShape(10.dp))
                                .padding(8.dp)
                        ) {
                            Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text("📢 VOICE TRANSCRIPT:", color = CyberCyan, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                    if (isNavigating) {
                                        Box(modifier = Modifier.size(6.dp).background(CyberPink, CircleShape))
                                    }
                                }
                                
                                Text(
                                    text = voiceNavigationFeedback,
                                    color = Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.SemiBold,
                                    lineHeight = 16.sp
                                )

                                Spacer(modifier = Modifier.height(4.dp))
                                
                                // Step timeline progress points
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                                ) {
                                    for (i in 0 until activeRouteSteps.size) {
                                        Box(
                                            modifier = Modifier
                                                .weight(1f)
                                                .height(3.dp)
                                                .background(
                                                    if (i <= currentStepIndex && isNavigating) CyberPink else Color(0xFF1E293B)
                                                )
                                        )
                                    }
                                }
                            }
                        }
                    } else {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .weight(1f),
                            contentAlignment = Alignment.Center
                        ) {
                            Column(
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Icon(Icons.Default.Navigation, contentDescription = null, tint = Color.Gray.copy(alpha = 0.5f), modifier = Modifier.size(24.dp))
                                Text("Search location above, find route and initiate live navigation.", color = Color.Gray, fontSize = 9.5.sp, textAlign = TextAlign.Center)
                            }
                        }
                    }
                }
            }
        }
    }
}

// =========================================================================
// 🚀 GOOGLE WORKSPACE ECOSYSTEM PRODUCTS HUB
// =========================================================================
@Composable
fun GoogleToolsHubView(viewModel: MainViewModel) {
    val context = LocalContext.current
    var selectedApp by remember { mutableStateOf<String?>(null) }
    var currentHubTab by remember { mutableStateOf("All Products") }

    val tabs = listOf("All Products", "AI Tools", "Communication", "Workspace", "Media & Entertainment")

    // Master List of Google Products matching the uploaded reference image!
    val googleAppsList = remember {
        listOf(
            Triple("Google Maps", "Workspace", "Custom dynamic navigation and map suite."),
            Triple("Google Gemini", "AI Tools", "Advanced generative text and code companion."),
            Triple("Google Translate", "Communication", "Live language translation service."),
            Triple("Google Keep", "Workspace", "Sticky note board with colors & categorizer."),
            Triple("Google Lens", "AI Tools", "Multimodal AI scanner & visual inspector."),
            Triple("YouTube Studio", "Media & Entertainment", "Stream videos and explore tech transcripts."),
            Triple("Google Calendar", "Workspace", "Interactive planner & reminders schedule."),
            Triple("Google Meet", "Communication", "Virtual conference stream call simulator."),
            Triple("NotebookLM Podcast", "AI Tools", "Converts articles to a dual-host audio podcast!"),
            Triple("Google Wallet Pass", "Workspace", "Manage membership cards, transactions & Passes."),
            Triple("Android", "All Products", "The world's most advanced mobile system."),
            Triple("Google Drive", "Workspace", "Secure cloud file management station."),
            Triple("Gmail Suite", "Communication", "Professional email client and drafts."),
            Triple("Google Chrome", "All Products", "Custom modular web explorer."),
            Triple("Google Docs", "Workspace", "Create formatted rich-text documents."),
            Triple("Google Sheets", "Workspace", "Generate calculation data sheets.")
        )
    }

    val filteredApps = remember(currentHubTab) {
        if (currentHubTab == "All Products") {
            googleAppsList
        } else {
            googleAppsList.filter { it.second == currentHubTab }
        }
    }

    if (selectedApp != null) {
        // App Simulator Frame
        Column(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFF030712))
        ) {
            // Header for App Simulator
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF0F172A))
                    .padding(8.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                IconButton(onClick = { selectedApp = null }) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(Icons.Default.ArrowBack, contentDescription = "Back", tint = CyberCyan, modifier = Modifier.size(16.dp))
                        Spacer(modifier = Modifier.width(4.dp))
                        Text("BACK TO HUB", color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                    }
                }
                Text(
                    text = "EMULATING: ${selectedApp!!.uppercase()}",
                    color = Color.White,
                    fontSize = 11.sp,
                    fontWeight = FontWeight.ExtraBold,
                    letterSpacing = 1.sp
                )
                Box(
                    modifier = Modifier
                        .background(Color(0xFF1E293B), RoundedCornerShape(6.dp))
                        .padding(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Text("SECURE SIM", color = Color(0xFF10B981), fontSize = 8.sp, fontWeight = FontWeight.ExtraBold)
                }
            }

            // Embedded Screen Simulators
            Box(modifier = Modifier.weight(1f)) {
                when (selectedApp) {
                    "Google Maps" -> {
                        GoogleMapsToolView(viewModel = viewModel)
                    }
                    "Google Translate" -> {
                        GoogleTranslateSim(viewModel = viewModel)
                    }
                    "Google Keep" -> {
                        GoogleKeepSim()
                    }
                    "Google Lens" -> {
                        GoogleLensSim(viewModel = viewModel)
                    }
                    "YouTube Studio" -> {
                        YouTubeSim(viewModel = viewModel)
                    }
                    "Google Calendar" -> {
                        GoogleCalendarSim()
                    }
                    "Google Meet" -> {
                        GoogleMeetSim()
                    }
                    "NotebookLM Podcast" -> {
                        NotebookLmSim(viewModel = viewModel)
                    }
                    "Google Wallet Pass" -> {
                        GoogleWalletSim()
                    }
                    "Google Docs" -> {
                        GoogleDocsSim(viewModel = viewModel)
                    }
                    "Google Sheets" -> {
                        GoogleSheetsSim(viewModel = viewModel)
                    }
                    else -> {
                        // Generic Google app simulator
                        Column(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(24.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            Icon(Icons.Default.CheckCircle, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(64.dp))
                            Spacer(modifier = Modifier.height(16.dp))
                            Text(selectedApp!!, color = Color.White, fontSize = 20.sp, fontWeight = FontWeight.Bold)
                            Spacer(modifier = Modifier.height(8.dp))
                            Text(
                                "Simulated core for $selectedApp is fully live in our sandbox. Cloud sync registers action triggers safely.",
                                color = Color.Gray,
                                fontSize = 12.sp,
                                textAlign = TextAlign.Center
                            )
                            Spacer(modifier = Modifier.height(24.dp))
                            Button(onClick = { selectedApp = null }, colors = ButtonDefaults.buttonColors(containerColor = CyberCyan)) {
                                Text("Return to Google Suite Grid", color = Color.Black)
                            }
                        }
                    }
                }
            }
        }
    } else {
        // Main Google products Hub Grid (Matching the reference screenshot structure!)
        Column(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFF030712))
                .padding(12.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            // Google Banner
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Colored Google style text drawing
                Row {
                    Text("G", color = Color(0xFF4285F4), fontSize = 24.sp, fontWeight = FontWeight.Black)
                    Text("o", color = Color(0xFFEA4335), fontSize = 24.sp, fontWeight = FontWeight.Black)
                    Text("o", color = Color(0xFFFBBC05), fontSize = 24.sp, fontWeight = FontWeight.Black)
                    Text("g", color = Color(0xFF4285F4), fontSize = 24.sp, fontWeight = FontWeight.Black)
                    Text("l", color = Color(0xFF34A853), fontSize = 24.sp, fontWeight = FontWeight.Black)
                    Text("e", color = Color(0xFFEA4335), fontSize = 24.sp, fontWeight = FontWeight.Black)
                }

                Box(
                    modifier = Modifier
                        .background(CyberCyan.copy(alpha = 0.1f), RoundedCornerShape(8.dp))
                        .padding(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Text("PLAYGROUND", color = CyberCyan, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                }
            }

            // Top Tab filtering selectors
            LazyRow(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(6.dp)
            ) {
                items(tabs.size, key = { tabs[it] }) { index ->
                    val tabName = tabs[index]
                    val isSel = currentHubTab == tabName
                    Box(
                        modifier = Modifier
                            .background(if (isSel) CyberCyan else Color(0xFF0F172A), RoundedCornerShape(20.dp))
                            .border(1.dp, if (isSel) CyberCyan else Color(0xFF1E293B), RoundedCornerShape(20.dp))
                            .clickable { currentHubTab = tabName }
                            .padding(horizontal = 12.dp, vertical = 8.dp)
                    ) {
                        Text(
                            text = tabName,
                            color = if (isSel) Color.Black else Color.White,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }

            // Descriptive Subtitle
            Text(
                text = "Rabiya self-healing lab provides interactive simulation nodes for original Google utilities:",
                color = Color.Gray,
                fontSize = 11.sp
            )

            // Dynamic grid layout
            LazyVerticalGrid(
                columns = GridCells.Adaptive(130.dp),
                modifier = Modifier.weight(1f),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(filteredApps.size, key = { filteredApps[it].first }) { index ->
                    val app = filteredApps[index]
                    
                    val brandColor = when (app.first) {
                        "Google Maps" -> Color(0xFFEA4335)
                        "Google Gemini" -> Color(0xFF818CF8)
                        "Google Translate" -> Color(0xFF4285F4)
                        "Google Keep" -> Color(0xFFFBBC05)
                        "Google Lens" -> Color(0xFF34A853)
                        "YouTube Studio" -> Color(0xFFEF4444)
                        else -> CyberCyan
                    }

                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(90.dp)
                            .background(Color(0xFF0F172A), RoundedCornerShape(12.dp))
                            .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(12.dp))
                            .clickable { selectedApp = app.first }
                            .padding(8.dp)
                    ) {
                        Column(
                            modifier = Modifier.fillMaxSize(),
                            verticalArrangement = Arrangement.SpaceBetween
                        ) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(24.dp)
                                        .background(brandColor.copy(alpha = 0.15f), CircleShape),
                                    contentAlignment = Alignment.Center
                                ) {
                                    val icon = when (app.first) {
                                        "Google Maps" -> Icons.Default.Map
                                        "Google Gemini" -> Icons.Default.AutoAwesome
                                        "Google Translate" -> Icons.Default.Translate
                                        "Google Keep" -> Icons.Default.Notes
                                        "Google Lens" -> Icons.Default.CameraAlt
                                        "YouTube Studio" -> Icons.Default.PlayArrow
                                        "Google Calendar" -> Icons.Default.CalendarToday
                                        "Google Meet" -> Icons.Default.VideoCall
                                        "NotebookLM Podcast" -> Icons.Default.AudioFile
                                        "Google Wallet Pass" -> Icons.Default.Wallet
                                        else -> Icons.Default.Settings
                                    }
                                    Icon(icon, contentDescription = null, tint = brandColor, modifier = Modifier.size(12.dp))
                                }
                                Icon(Icons.Default.ArrowOutward, contentDescription = null, tint = Color.Gray, modifier = Modifier.size(12.dp))
                            }

                            Column {
                                Text(app.first, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold, maxLines = 1)
                                Text(app.third, color = Color.Gray, fontSize = 8.sp, maxLines = 1, lineHeight = 10.sp)
                            }
                        }
                    }
                }
            }
        }
    }
}

// =========================================================================
// Google Tools Sub-Simulators implementations
