@Composable
fun NotebookLmSim(viewModel: MainViewModel) {
    var pastedDocText by remember { mutableStateOf("") }
    var podcastGenerating by remember { mutableStateOf(false) }
    var podcastScriptResult by remember { mutableStateOf("") }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(12.dp),
        verticalArrangement = Arrangement.spacedBy(10.dp)
    ) {
        Text("NOTEBOOK LM - PODCAST BRIEFING GENERATOR 🎙️", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)

        OutlinedTextField(
            value = pastedDocText,
            onValueChange = { pastedDocText = it },
            placeholder = { Text("Paste document text or article content here...", color = Color.Gray, fontSize = 11.sp) },
            modifier = Modifier
                .fillMaxWidth()
                .height(110.dp)
        )

        Button(
            onClick = {
                if (pastedDocText.isNotBlank()) {
                    podcastGenerating = true
                    val coroutineScope = kotlinx.coroutines.MainScope()
                    coroutineScope.launch {
                        val prompt = "Generate a short podcast script conversation between Host A (Sam) and Host B (Zara) reviewing this content: '$pastedDocText'. Make it extremely engaging, funny and clear."
                        val reply = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, prompt)
                        podcastScriptResult = reply
                        podcastGenerating = false
                    }
                }
            },
            colors = ButtonDefaults.buttonColors(containerColor = CyberCyan),
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Generate Podcast Script", color = Color.Black, fontSize = 11.sp, fontWeight = FontWeight.Bold)
        }

        Box(
            modifier = Modifier
                .fillMaxWidth()
                .weight(1f)
                .background(Color(0xFF0F172A), RoundedCornerShape(12.dp))
                .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(12.dp))
                .padding(10.dp)
                .verticalScroll(rememberScrollState())
        ) {
            if (podcastGenerating) {
                Text("Synthesizing dual-host debate parameters...", color = CyberPink, fontSize = 11.sp)
            } else {
                Text(
                    text = podcastScriptResult.ifBlank { "Podcast script output will print here..." },
                    color = Color.White,
                    fontSize = 11.sp
                )
            }
        }
    }
}

@Composable
fun GoogleWalletSim() {
    var selectedPassType by remember { mutableStateOf("Cyber Card") } // Cyber Card, Transit Pass, Digital ID
    var isNfcPulsing by remember { mutableStateOf(false) }
    var rollingTokenHash by remember { mutableStateOf("TXN-88402-2026-X") }
    var nfcStatusText by remember { mutableStateOf("Ready to Wave (Contactless NFC)") }

    // Dynamic rotating secure hash simulation
    LaunchedEffect(Unit) {
        while (true) {
            kotlinx.coroutines.delay(4000)
            rollingTokenHash = "TXN-${(10000..99999).random()}-2026-${('A'..'Z').random()}"
        }
    }

    LaunchedEffect(isNfcPulsing) {
        if (isNfcPulsing) {
            nfcStatusText = "Pulsing NFC radio-waves..."
            kotlinx.coroutines.delay(1800)
            nfcStatusText = "SECURED HANDSHAKE COMPLETED ✅"
            isNfcPulsing = false
            kotlinx.coroutines.delay(1500)
            nfcStatusText = "Ready to Wave (Contactless NFC)"
        }
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(12.dp),
        verticalArrangement = Arrangement.spacedBy(10.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text("GOOGLE WALLET SECURE PASS", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold, letterSpacing = 0.5.sp)
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(4.dp),
                modifier = Modifier
                    .background(Color(0xFF1E3A8A).copy(alpha = 0.3f), RoundedCornerShape(4.dp))
