                Icon(Icons.Default.Lock, contentDescription = null, tint = Color(0xFF60A5FA), modifier = Modifier.size(10.dp))
                Text("BIOMETRIC SAFE", color = Color(0xFF60A5FA), fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
