@Composable
fun GoogleSheetsSim(viewModel: MainViewModel) {
    val context = LocalContext.current
    var sheetTitle by remember { mutableStateOf("Monthly Budget 2026") }
    var sheetTopicPrompt by remember { mutableStateOf("Marketing Budget 2026") }
    var isGenerating by remember { mutableStateOf(false) }

    // Use mutableStateListOf of mutableStateListOf or a single list of lists
    val parsedRows = remember {
        mutableStateListOf<List<String>>().apply {
            // Pre-populate with high quality default spreadsheet so it is never empty!
            add(listOf("Category", "Jan Budget", "Feb Budget", "Actual Spent", "Difference"))
            add(listOf("Google Cloud Server", "1200", "1150", "1100", "50"))
            add(listOf("Workspace Licenses", "450", "450", "460", "-10"))
            add(listOf("Gemini API Tokens", "800", "1200", "950", "250"))
            add(listOf("Office Cyber Cafeteria", "300", "320", "290", "10"))
            add(listOf("Transit Reimbursements", "150", "180", "170", "10"))
        }
    }

    var selectedCell by remember { mutableStateOf<Pair<Int, Int>?>(null) } // Row, Col
    var cellEditValue by remember { mutableStateOf("") }

    // Formula Calculations: Sum of all numerical fields
    val sheetSum = remember(parsedRows.size, parsedRows.map { it.joinToString() }) {
        var sum = 0.0
        parsedRows.forEachIndexed { rIdx, row ->
            if (rIdx > 0) { // Skip header
                row.forEach { cell ->
                    cell.toDoubleOrNull()?.let { sum += it }
                }
            }
        }
        sum
    }

    val sheetAvg = remember(parsedRows.size, parsedRows.map { it.joinToString() }) {
        var count = 0
        var sum = 0.0
        parsedRows.forEachIndexed { rIdx, row ->
            if (rIdx > 0) {
                row.forEach { cell ->
                    cell.toDoubleOrNull()?.let {
                        sum += it
                        count++
                    }
                }
            }
        }
        if (count > 0) sum / count else 0.0
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(12.dp),
        verticalArrangement = Arrangement.spacedBy(10.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text("📊 GOOGLE SHEETS CORE", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold, letterSpacing = 0.5.sp)
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(4.dp),
                modifier = Modifier
                    .background(Color(0xFF065F46), RoundedCornerShape(4.dp))
                    .padding(horizontal = 6.dp, vertical = 2.dp)
            ) {
                Icon(Icons.Default.Lock, contentDescription = null, tint = Color(0xFF34D399), modifier = Modifier.size(10.dp))
                Text("SSL SHA-256 SAFE", color = Color(0xFF34D399), fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
            }
        }

        // Inputs
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            OutlinedTextField(
                value = sheetTitle,
                onValueChange = { sheetTitle = it },
                label = { Text("Sheet Title", color = Color.Gray, fontSize = 8.sp) },
                modifier = Modifier.weight(1f),
                colors = OutlinedTextFieldDefaults.colors(
                    focusedTextColor = Color.White,
                    unfocusedTextColor = Color.White,
                    focusedBorderColor = CyberCyan,
                    unfocusedBorderColor = Color(0xFF1E293B)
                ),
                textStyle = TextStyle(fontSize = 10.sp),
                singleLine = true
            )

            OutlinedTextField(
                value = sheetTopicPrompt,
                onValueChange = { sheetTopicPrompt = it },
                label = { Text("AI Generator Topic", color = Color.Gray, fontSize = 8.sp) },
                modifier = Modifier.weight(1.2f),
                colors = OutlinedTextFieldDefaults.colors(
                    focusedTextColor = Color.White,
                    unfocusedTextColor = Color.White,
                    focusedBorderColor = CyberCyan,
                    unfocusedBorderColor = Color(0xFF1E293B)
                ),
                textStyle = TextStyle(fontSize = 10.sp),
                singleLine = true
            )
        }

        // Action buttons
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            Button(
                onClick = {
                    isGenerating = true
                    selectedCell = null
                    val coroutineScope = kotlinx.coroutines.MainScope()
                    coroutineScope.launch {
                        val prompt = "Generate a realistic CSV spreadsheet dataset (raw text format, separated ONLY by commas and newlines) for the topic '$sheetTopicPrompt'. Provide a header row and 5-8 highly accurate data rows. Output absolutely only valid CSV, no conversational filler or markup."
                        val reply = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, prompt).trim()
                        val rows = reply.split("\n")
                            .map { it.split(",").map { cell -> cell.trim().replace("\"", "") } }
                            .filter { it.isNotEmpty() && it[0].isNotBlank() }
                        parsedRows.clear()
                        parsedRows.addAll(rows)
                        isGenerating = false
                    }
                },
                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF107C41)),
                modifier = Modifier.weight(1f),
                enabled = !isGenerating,
                shape = RoundedCornerShape(8.dp)
            ) {
                if (isGenerating) {
                    CircularProgressIndicator(color = Color.White, modifier = Modifier.size(14.dp), strokeWidth = 2.dp)
                } else {
                    Row(horizontalArrangement = Arrangement.spacedBy(4.dp), verticalAlignment = Alignment.CenterVertically) {
                        Icon(Icons.Default.AutoAwesome, contentDescription = null, tint = Color.White, modifier = Modifier.size(12.dp))
                        Text("AI BUILD SHEET", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }

            Button(
                onClick = {
                    if (parsedRows.isNotEmpty()) {
                        val csvContent = parsedRows.joinToString("\n") { it.joinToString(",") }
                        viewModel.addFileToFileManager(context, "${sheetTitle.replace(" ", "_")}_${System.currentTimeMillis()}.csv", "Documents", csvContent)
                        android.widget.Toast.makeText(context, "Saved Sheet to Rabiya File Manager Documents!", android.widget.Toast.LENGTH_SHORT).show()
                    } else {
                        android.widget.Toast.makeText(context, "Sheet is empty!", android.widget.Toast.LENGTH_SHORT).show()
                    }
                },
                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF1E293B)),
                modifier = Modifier.weight(1f),
                shape = RoundedCornerShape(8.dp)
            ) {
                Row(horizontalArrangement = Arrangement.spacedBy(4.dp), verticalAlignment = Alignment.CenterVertically) {
                    Icon(Icons.Default.Save, contentDescription = null, tint = CyberCyan, modifier = Modifier.size(12.dp))
                    Text("SAVE FILE", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                }
            }
        }

        Divider(color = Color(0xFF1E293B))

        // Dynamic formula metrics summary bar
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF0F172A), RoundedCornerShape(8.dp))
                .padding(8.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Row(horizontalArrangement = Arrangement.spacedBy(12.dp)) {
                Column {
                    Text("SUM", color = Color.Gray, fontSize = 7.sp, fontWeight = FontWeight.Bold)
                    Text(String.format("%.2f", sheetSum), color = CyberCyan, fontSize = 10.sp, fontWeight = FontWeight.ExtraBold)
                }
                Column {
                    Text("AVERAGE", color = Color.Gray, fontSize = 7.sp, fontWeight = FontWeight.Bold)
                    Text(String.format("%.2f", sheetAvg), color = CyberPink, fontSize = 10.sp, fontWeight = FontWeight.ExtraBold)
                }
            }
            Text("LIVE MATH FORMULAS ACTIVE", color = Color.DarkGray, fontSize = 7.sp, fontWeight = FontWeight.Bold)
        }

        // Spreadsheet Grid Rendering
        if (parsedRows.isNotEmpty()) {
            Box(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
                    .background(Color(0xFF0F172A), RoundedCornerShape(12.dp))
                    .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(12.dp))
                    .padding(8.dp)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .verticalScroll(rememberScrollState())
                        .horizontalScroll(rememberScrollState()),
                    verticalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    parsedRows.forEachIndexed { rIdx, row ->
                        Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                            row.forEachIndexed { cIdx, cell ->
                                val isSelected = selectedCell == Pair(rIdx, cIdx)
                                Box(
                                    modifier = Modifier
                                        .width(90.dp)
                                        .background(
                                            if (rIdx == 0) Color(0xFF1E293B)
                                            else if (isSelected) Color(0xFF107C41).copy(alpha = 0.25f)
                                            else Color(0xFF030712),
                                            RoundedCornerShape(4.dp)
                                        )
                                        .border(
                                            width = if (isSelected) 1.5.dp else 0.5.dp,
                                            color = if (isSelected) Color(0xFF107C41) else Color(0xFF1E293B),
                                            shape = RoundedCornerShape(4.dp)
                                        )
                                        .clickable {
                                            selectedCell = Pair(rIdx, cIdx)
                                            cellEditValue = cell
                                        }
                                        .padding(6.dp),
                                    contentAlignment = Alignment.CenterStart
                                ) {
                                    Text(
                                        text = cell,
                                        color = if (rIdx == 0) CyberCyan else Color.White,
                                        fontSize = 9.sp,
                                        fontWeight = if (rIdx == 0) FontWeight.Bold else FontWeight.Normal,
                                        maxLines = 1
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // Editable Formula Bar for the Selected Cell!
        if (selectedCell != null) {
            val (r, c) = selectedCell!!
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF030712), RoundedCornerShape(10.dp))
                    .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(10.dp))
                    .padding(10.dp)
            ) {
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "EDIT CELL [Row $r, Col ${('A' + c)}]",
                            color = Color.Gray,
                            fontSize = 8.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            text = "Enter raw text or numerical metrics",
                            color = Color.DarkGray,
                            fontSize = 7.5.sp
                        )
                    }

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text("fx", color = Color(0xFF107C41), fontSize = 12.sp, fontWeight = FontWeight.Bold)
                        
                        OutlinedTextField(
                            value = cellEditValue,
                            onValueChange = { cellEditValue = it },
                            modifier = Modifier.weight(1f),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedTextColor = Color.White,
                                unfocusedTextColor = Color.White,
                                focusedBorderColor = Color(0xFF107C41),
                                unfocusedBorderColor = Color(0xFF1E293B)
                            ),
                            textStyle = TextStyle(fontSize = 11.sp),
                            singleLine = true
                        )

                        Button(
                            onClick = {
                                // Apply cell edit
                                val updatedRow = parsedRows[r].toMutableList()
                                updatedRow[c] = cellEditValue
                                parsedRows[r] = updatedRow
                                selectedCell = null
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF107C41)),
                            shape = RoundedCornerShape(6.dp),
                            contentPadding = PaddingValues(horizontal = 10.dp, vertical = 4.dp),
                            modifier = Modifier.height(32.dp)
                        ) {
                            Text("Apply", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun CodeSandboxDialog(
    viewModel: MainViewModel,
    onDismiss: () -> Unit
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    
    val prefilledCode by viewModel.sandboxPrefilledCode.collectAsStateWithLifecycle()
    val prefilledLanguage by viewModel.sandboxPrefilledLanguage.collectAsStateWithLifecycle()
    
    var selectedLanguage by remember { mutableStateOf("HTML/CSS/JS") }
    var codeText by remember { mutableStateOf("") }
    
    // Dynamic styling settings for the Design Arena preview
    var deviceMode by remember { mutableStateOf("mobile") } // "mobile", "tablet", "desktop"
    var themeAccentColor by remember { mutableStateOf(CyberCyan) }
    var cornerRadiusVal by remember { mutableFloatStateOf(16f) }
    var spacingPaddingVal by remember { mutableFloatStateOf(12f) }
    
    // Internal helper function for cleaning and detecting code format (useful for pasting from AI)
    fun cleanAndDetectCode(pastedText: String): Pair<String, String> {
        val trimmed = pastedText.trim()
        if (trimmed.isEmpty()) return Pair("", "HTML/CSS/JS")

        // 1. Check for markdown code blocks (```lang ... ```) using regex to find ALL blocks
        val codeBlockRegex = """```(\w*)\n([\s\S]*?)```""".toRegex()
        val matches = codeBlockRegex.findAll(trimmed).toList()

        if (matches.isNotEmpty()) {
            var htmlPart = ""
            var cssPart = ""
            var jsPart = ""
            val otherBlocks = mutableListOf<Pair<String, String>>() // lang to code

            for (match in matches) {
                val lang = match.groupValues[1].lowercase().trim()
                val code = match.groupValues[2]
                when (lang) {
                    "html" -> htmlPart += code + "\n"
                    "css" -> cssPart += code + "\n"
                    "javascript", "js" -> jsPart += code + "\n"
                    else -> otherBlocks.add(Pair(lang, code))
                }
            }

            // If we have some combination of HTML, CSS, JS, merge them!
            if (htmlPart.isNotEmpty() || cssPart.isNotEmpty() || jsPart.isNotEmpty()) {
                var mergedHtml = ""
                if (htmlPart.contains("<html", ignoreCase = true)) {
                    mergedHtml = htmlPart
                    if (cssPart.isNotEmpty()) {
                        mergedHtml = if (mergedHtml.contains("</head>", ignoreCase = true)) {
                            mergedHtml.replace("</head>", "<style>\n$cssPart\n</style>\n</head>", ignoreCase = true)
                        } else {
                            "<style>\n$cssPart\n</style>\n" + mergedHtml
                        }
                    }
                    if (jsPart.isNotEmpty()) {
                        mergedHtml = if (mergedHtml.contains("</body>", ignoreCase = true)) {
                            mergedHtml.replace("</body>", "<script>\n$jsPart\n</script>\n</body>", ignoreCase = true)
                        } else {
                            mergedHtml + "\n<script>\n$jsPart\n</script>"
                        }
                    }
                } else {
                    mergedHtml = """
                    <!DOCTYPE html>
                    <html lang="en">
                    <head>
                        <meta charset="UTF-8">
                        <meta name="viewport" content="width=device-width, initial-scale=1.0">
                        <title>Rabiya Smart Integrated Render</title>
                        <style>
                            body {
                                margin: 0;
                                padding: 16px;
                                font-family: system-ui, -apple-system, sans-serif;
                                background-color: #0F172A;
                                color: #E2E8F0;
                            }
                            $cssPart
                        </style>
                    </head>
                    <body>
                        $htmlPart
                        <script>
                            $jsPart
                        </script>
                    </body>
                    </html>
                    """.trimIndent()
                }
                return Pair(mergedHtml.trim(), "HTML/CSS/JS")
            }

            // If we didn't merge but have other blocks, pick the most relevant one (like kotlin or python)
            if (otherBlocks.isNotEmpty()) {
                val bestBlock = otherBlocks.firstOrNull { it.first in listOf("kotlin", "kt", "python", "py", "java", "cpp", "c++") } 
                    ?: otherBlocks.first()
                val detectedLanguage = when (bestBlock.first) {
                    "html", "css", "js", "javascript", "typescript", "ts" -> "HTML/CSS/JS"
                    "java" -> "Java"
                    "python", "py", "python3" -> "Python"
                    "kotlin", "kt" -> "Kotlin"
                    "cpp", "c++", "c", "h", "hpp" -> "C++"
                    else -> "HTML/CSS/JS"
                }
                return Pair(bestBlock.second.trim(), detectedLanguage)
            }
        }

        // If no explicit backticks but manual backticks present, fallback to manual parse
        if (trimmed.contains("```")) {
            val lines = trimmed.lines()
            val firstBacktickIdx = lines.indexOfFirst { it.trim().startsWith("```") }
            if (firstBacktickIdx != -1) {
                val langLine = lines[firstBacktickIdx].trim().substring(3).trim().lowercase()
                val detectedLanguage = when (langLine) {
                    "html", "css", "js", "html/css/js", "javascript", "typescript", "ts" -> "HTML/CSS/JS"
                    "java" -> "Java"
                    "python", "py", "python3" -> "Python"
                    "kotlin", "kt" -> "Kotlin"
                    "cpp", "c++", "c", "h", "hpp" -> "C++"
                    else -> "HTML/CSS/JS"
                }
                val codeLines = mutableListOf<String>()
                var insideBlock = false
                for (i in lines.indices) {
                    if (i == firstBacktickIdx) {
                        insideBlock = true
                        continue
                    }
                    if (insideBlock) {
                        if (lines[i].trim().startsWith("```")) {
                            break
                        }
                        codeLines.add(lines[i])
                    }
                }
                if (codeLines.isNotEmpty()) {
                    return Pair(codeLines.joinToString("\n").trim(), detectedLanguage)
                }
            }
        }

        // 3. Fallback heuristic
        val lower = trimmed.lowercase()
        val detectedLanguage = when {
            lower.contains("<!doctype html") || lower.contains("<html") || lower.contains("<div") || lower.contains("document.getelementbyid") -> "HTML/CSS/JS"
            lower.contains("def ") && (lower.contains("import ") || lower.contains("print(")) -> "Python"
            lower.contains("public class ") || lower.contains("system.out.print") -> "Java"
            lower.contains("fun ") || lower.contains("val ") || lower.contains("var ") || lower.contains("import androidx.compose") -> "Kotlin"
            lower.contains("#include") || lower.contains("std::cout") || lower.contains("int main(") -> "C++"
            else -> "HTML/CSS/JS"
        }
        return Pair(trimmed, detectedLanguage)
    }

    LaunchedEffect(prefilledCode, prefilledLanguage) {
