                                            CRITICAL: Return ONLY the raw, pure, updated code inside your response. Do NOT wrap it in any markdown code blocks (such as ```html, ```kotlin, or ```), and do NOT provide any introductory or concluding text. Your entire response must be valid runnable code.
                                        """.trimIndent()
                                        
                                        val response = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, tweakInstruct).trim()
                                        var cleanedResp = response
                                        if (cleanedResp.startsWith("```")) {
                                            val lines = cleanedResp.lines()
                                            if (lines.isNotEmpty() && lines.first().startsWith("```")) {
                                                cleanedResp = lines.drop(1).joinToString("\n")
