                                    } finally {
                                        isTweakingCode = false
                                    }
                                }
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = themeAccentColor),
                        enabled = !isTweakingCode && sandboxTweakPromptText.isNotBlank() && codeText.isNotBlank(),
                        shape = RoundedCornerShape(8.dp),
