                        coroutineScope.launch {
                            try {
                                val userPrompt = """
                                You are acting as the high-accuracy execution backend of the Rabiya Code Sandbox.
                                The user selected language: ${selectedLanguage}.
                                The user pasted code:
                                ${codeText}

                                Please perform the following actions and return the result in this structured format:

                                [VISUAL_PREVIEW]
                                (For HTML/CSS/JS, write 'LOADS_IN_WEBVIEW'. For other languages like Kotlin/Compose, Java/Swing, Python/Tkinter or terminal output, please provide a beautiful text-based mockup of what the UI screen looks like! Highlight interactive buttons, labels, and text boxes. Use clean modern emojis and a beautiful visual smartphone mockup layout in text!)

                                [SIMULATION_OUTPUT]
                                (Simulate running the code and output the terminal/console result exactly, including program logs, performance latency, exit code, memory footprints, and CPU execution time simulation. If there are syntax or logic errors, point them out like a compiler error log!)

                                [LINE_EXPLANATION]
                                (Explain what the code does step-by-step in clear, easy Roman Urdu/Hindi or English, explaining design patterns, key lines, variables, time complexity, and how it executes.)

                                [EXTRACTED_RESOURCES]
                                (Identify components, APIs called, buttons, inputs, packages imported, or design details. Suggest how this code can connect with local tools like File Manager, PDF Analyzer, or Gemini API!)
                                """
                                val reply = viewModel.getLLMResponseForModel(viewModel.selectedModel.value, userPrompt)
                                
                                val cleanReply = reply
                                fun extractBlock(tag: String, nextTag: String?): String {
                                    val startIdx = cleanReply.indexOf(tag)
                                    if (startIdx == -1) return ""
                                    val contentStart = startIdx + tag.length
                                    if (nextTag != null) {
                                        val endIdx = cleanReply.indexOf(nextTag, contentStart)
                                        if (endIdx != -1) {
                                            return cleanReply.substring(contentStart, endIdx).trim()
                                        }
                                    }
                                    return cleanReply.substring(contentStart).trim()
                                }
                                
                                var prev = extractBlock("[VISUAL_PREVIEW]", "[SIMULATION_OUTPUT]")
                                var sim = extractBlock("[SIMULATION_OUTPUT]", "[LINE_EXPLANATION]")
                                var exp = extractBlock("[LINE_EXPLANATION]", "[EXTRACTED_RESOURCES]")
                                var res = extractBlock("[EXTRACTED_RESOURCES]", null)
                                
                                if (prev.isEmpty() && sim.isEmpty() && exp.isEmpty() && res.isEmpty()) {
                                    sim = "Compilation completed successfully with code exit: 0."
                                    exp = reply
                                    res = "Extracted structural nodes: Code Block Detected."
                                    prev = "No explicit visual preview returned, but simulation succeeded!"
                                }
                                
                                visualPreviewResult = prev
                                simulationResult = sim
                                lineExplanation = exp
                                extractedRes = res
                                
                            } catch (e: Exception) {
                                simulationResult = "Error simulating compilation:\n${e.message}"
                                lineExplanation = "Could not generate analysis due to network limits."
                                extractedRes = "Error analyzing components."
                                visualPreviewResult = "Mock render failed due to compile simulation error."
                            } finally {
                                isCompiling = false
                            }
