@Composable
fun MarkdownText(
    markdown: String,
    color: Color = Color.White,
    fontSize: androidx.compose.ui.unit.TextUnit = 13.sp,
    lineHeight: androidx.compose.ui.unit.TextUnit = 18.sp,
    onImageClick: ((String) -> Unit)? = null,
    onArtifactClick: ((String, String) -> Unit)? = null,
    modifier: Modifier = Modifier
) {
    val annotatedString = remember(markdown) {
        androidx.compose.ui.text.buildAnnotatedString {
            val parts = markdown.split("**")
            var isBold = false
            parts.forEach { part ->
                if (isBold) {
                    withStyle(style = androidx.compose.ui.text.SpanStyle(fontWeight = FontWeight.Bold, color = color)) {
                        append(part)
                    }
                } else {
                    val subParts = part.split("`")
                    var isCode = false
                    subParts.forEach { subPart ->
                        if (isCode) {
                            withStyle(style = androidx.compose.ui.text.SpanStyle(fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace, color = CyberCyan, background = Color(0xFF1E293B))) {
                                append(subPart)
                            }
                        } else {
                            append(subPart)
                        }
                        isCode = !isCode
                    }
                }
                isBold = !isBold
            }
        }
    }
    Text(
        text = annotatedString,
        color = color,
        fontSize = fontSize,
        lineHeight = lineHeight,
        modifier = modifier
    )
}

